INSERT INTO node VALUES (360, '2020年11月15日，2020全国电子竞技高校邀请赛总决赛圆满结束。江西软件职业技术大学电竞战队与包括985和211高校在内的众多电竞战队，进行了激烈争夺，一路过关斩将。在最终的决赛中，我校电竞战队以2：0的成绩，击败了武汉大学电竞战队，勇夺本届大赛《英雄联盟》项目的全国冠军。', 2692, '2020-11-02 16:11:38', '', 'false', 'true', '', 'https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2020-11-04%2019%3A26%3A39338.jpg?Expires=1919849201&OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&Signature=dOZM6UA70fuz%2B69PR%2Fbj9RhJmxA%3D', 1, 243);
