INSERT INTO content VALUES (263, '<p><video style="display: block; margin-left: auto; margin-right: auto;" controls="controls" width="952" height="476">
<source src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2020.8.26%E6%98%93%E7%9C%81%E9%95%BF%E8%A7%86%E5%AF%9F%E5%85%88%E9%94%8B%E5%AD%A6%E6%A0%A1%E8%A7%86%E9%A2%91.mp4?Expires=1914282845&OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&Signature=CpwlbRJBfMlUU%2BLgon1mJy9iXj8%3D
" type="video/mp4" /></video></p>');
INSERT INTO content VALUES (264, '<p style="text-indent: 0em; text-align: center;"><strong><img src="/branch_static_img/99a732b6-2af0-4e31-92db-b93fca7ef285.png" width="800" height="533" title="" alt=""/></strong></p><p style="text-indent: 2em;">2019年1月3日，浙江广厦建设职业技术学院专家组组长奚建华、院长沈兵虎、专家组专家楼程富、党委副书记蒋忠樟、戚姚云等一行莅临先锋小镇参观考察。</p><p><br/></p>');
INSERT INTO content VALUES (265, '<p style="text-align: center;"><img src="/branch_static_img/b4f86819-bbff-4f92-86d4-08ea264f2e05.png" width="800" height="533" title="" alt=""/></p><p style="text-indent: 2em;">2019年1月9日，江西省社科院科研处处长樊宾、江西省社科院学术委员会副主任高平、吴晓荣一行莅临先锋小镇开展调研座谈。</p>');
INSERT INTO content VALUES (266, '<p style="text-align: center;">
    <img src="/branch_static_img/4703dc88-82e4-476f-8c0c-74731421a67f.png" width="800" height="400" title="" alt=""/>
</p>
<p style="text-indent: 2em;">
    2019年1月15日，硅谷风险投资人、美国风投学院校董、500IPO基金及VCC（创投链）创始人钟德辉莅临先锋小镇作题为“中美区块链的差异与机会”的讲座。让区块链人才结合全球信息资讯，打造引领全球的区块链公司持续导入硅谷乃至全球的区块链专家、技术、风投等，把江西打造为全球顶级区块链生态系统中心。
</p>
<p>
    <br/>
</p>');
INSERT INTO content VALUES (267, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: undefinedquot;Microsoft YaHeiundefinedquot;; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: rgb(51, 51, 51); text-indent: 0em; white-space: normal; text-align: center;">
    <span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><img src="/branch_static_img/bcd3994b-b91a-478a-9881-6e77f989efc2.png" width="800" height="533" title="" alt=""/></span>
</p>
<p style="text-align: justify; text-indent: 2em;">
    2019年2月16日，上海长江时代物联网科技公司董事长王平、深圳宏壬易午区块链科技公司董事长刘勇等莅临先锋小镇洽谈合作事宜，共同推动区块链应用在江西落地，为区域经济与社会发展做出应有的贡献。
</p>
<p>
    <br/>
</p>');
INSERT INTO content VALUES (268, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: undefinedquot;Microsoft YaHeiundefinedquot;; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: rgb(51, 51, 51); text-indent: 0em; white-space: normal; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><img src="/branch_static_img/b35661fd-e56e-4bb1-8629-357fa45fa042.png" width="800" height="533" title="" alt=""/></span></p><p style="text-align: justify; text-indent: 2em;">2019年2月26日，五洲传播中心、节中荣日（上海）文化传播有限公司领导一行到先锋小镇考察交流，进一步深化职业教育教学改革，全面推进产教深度融合，更好地为区域产业发展服务。</p><p><br/></p><p><br/></p>');
INSERT INTO content VALUES (269, '<p style="text-indent: 0em; text-align: center;"><strong><img src="/branch_static_img/83b3d4ba-a43f-47d5-9e79-45c7c33df26d.png" width="800" height="533" title="" alt=""/></strong></p><p style="text-indent: 2em;">2019年2月28日，先锋小镇创业团队为做好南昌市第二届郁金香花展各项工作，邀请湾里区各职能部门召开了工作协调会，汇报了相关工作进展，并向湾里区领导提出了需要支持解决的一些问题。</p><p><br/></p><p><br/></p>');
INSERT INTO content VALUES (270, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/21afae7b-ca66-4d52-afd3-f2258a721c1c.png" width="800" height="503" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年3月31日，江西省副省长吴晓军来先锋小镇视察指导。校党委书记、省教育厅督导专员卢晓健，先锋软件集团董事长陈苏，先锋软件集团总经理卢松，罗亭镇党委书记刘福明等陪同。
</p>
<p>
    <br/>
</p>');
INSERT INTO content VALUES (271, '<p style="text-indent: 0em; text-align: center;"><strong><img src="/branch_static_img/117c8e99-3717-4a00-bd55-7375dbc4202c.png" width="800" height="390" title="" alt=""/></strong></p><p style="text-indent: 2em;">2019年4月12日，陈苏董事长代表先锋小镇受邀参加临空管委会2019年第二期临空讲堂并围绕“区块链改变未来”作专题讲座。临空区党工委管委会领导、各部门负责人及工作人员、城投集团公司代表共80余人参加讲座。</p><p style="text-indent: 2em;"><br/></p>');
INSERT INTO content VALUES (272, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/cbba02d0-8cf9-4cd7-84ed-9363d0b44ff5.png" width="800" height="390" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
2019年12月27日，江西财经大学信息管理学院院长毛小兵、院党委书记张志军一行莅临先锋小镇，先后参观了区块链专家小村、区块链学院等。
</p>
<p style="text-indent: 2em;">
    <br/>
</p>');
INSERT INTO content VALUES (273, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/354b5f0b-e097-48c2-8796-2b9f3c1758b6.png" width="800" height="448" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
   2019年12月23日，先锋小镇与中节能太阳能公司在北京就区块链 能源互联网项目签署战略合作框架协议，基于区块链的微电网关键技术研究与示范应用项目将落户先锋小镇。
</p>
<p style="text-indent: 0em;">
    <br/>
</p>');
INSERT INTO content VALUES (274, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/a37e45bf-e4dc-443f-9244-ebacafc62301.png" width="800" height="448" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
   2019年12月16日，先锋小镇代表团一行参观江西日报社及其“赣鄱云”融媒体中央厨房，受到江西日报社长王晖、总经理王少君等报社领导的热情接待。双方就在江西软件大学筹划建立二级学院项目进行了洽谈商讨。
</p>
<p style="text-indent: 0em;">
    <br/>
</p>');
INSERT INTO content VALUES (275, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/97cc44ac-bcd5-452e-bd08-5fbd2626d407.png" width="800" height="448" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
  2019年12月13日，董事长陈苏代表先锋小镇受邀参加江西省市场监管局举办的市场监管大讲堂并发表《区块链在江西大有可为》的主题演讲。
</p>
<p style="text-indent: 0em;">
    <br/>
</p>');
INSERT INTO content VALUES (276, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/292997a3-c23e-43bc-a04c-1f33b08e6e88.png" width="800" height="462" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年12月11日，先锋小镇与光大银行南昌分行签约，共同打造中国第一所基于区块链技术的智慧校园。
</p>');
INSERT INTO content VALUES (277, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/5dcb3688-4adc-4857-a349-b2837bb847f5.png" width="800" height="221" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年12月7日，江西省区块链技术专家委员会、江西省经济领域信息化专委会在先锋小镇举办第三期《赣鄱区块链专家论坛》。
</p>');
INSERT INTO content VALUES (278, '<p style="text-indent: 0em; text-align: center;"><strong><img src="/branch_static_img/76c8970e-490e-4eea-b7b3-df4ebb2c51d7.png" width="800" height="534" title="" alt=""/></strong></p><p style="text-indent: 2em;">2019年12月7日，来自江西十一个地市和北京、上海、广东、浙江、山东、海南、福建等省市以及美国、香港等国家地区的112名企业家齐聚英雄城南昌，在先锋小镇召开江西省区块链行业协会成立大会，江西省政协副主席雷元江为协会揭牌。</p>');
INSERT INTO content VALUES (279, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/5746de6d-1393-46fd-8324-b89af6702c13.png" width="800" height="534" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年12月6日，先锋小镇荣获由省委网信办指导，省委教育工委、省教育厅、国家计算机网络应急技术处理协调中心江西分中心主办的第二届江西省高校网络安全技能大赛决赛的冠军。
</p>');
INSERT INTO content VALUES (280, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/d81c6236-fdee-46f1-95a2-eac154f670dd.png" width="800" height="534" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年12月6日，赣江新区管委会副主任肖玉文一行先锋小镇，商讨区块链项目合作事宜。
</p>');
INSERT INTO content VALUES (281, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/46301b57-eb93-41f0-b50a-411d353e92c6.png" width="800" height="534" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年12月3日，中节能太阳能公司总经理曹华斌一行莅临先锋小镇，洽谈区块链 能源互联网项目相关事宜。
</p>');
INSERT INTO content VALUES (282, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/7d60a2e1-ec44-4325-b3f1-f99e944f17bb.png" width="800" height="533" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    世界大学生电子竞技联赛WUCG 2019全球总决赛暨ICC(International College Cup)邀请赛在历经数月的上百场对局，12月4日在中国三亚完美落幕。先锋小镇的HMG战队继荣膺2019英特尔大师挑战赛英雄联盟项目总决赛冠军以及WUCG2019中国赛区冠军之后，再次技压群雄，以全胜的战绩荣获世界冠军。
</p>');
INSERT INTO content VALUES (283, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/5d452917-7950-4d67-8a61-a29ca20ba9bc.png" width="800" height="493" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年11月30日，先锋软件公司总经理卢松代表先锋小镇参加由江西省工信委组织的江西省区块链产业及技术应用培训班并授课。
</p>');
INSERT INTO content VALUES (284, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/c86e0ae8-2c84-4717-aaef-a44de70e783b.png" width="800" height="493" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年11月23日，先锋小镇参加江西省军区组织的全省群众性练兵比武竞赛活动网络攻防组竞赛荣获第一名。
</p>');
INSERT INTO content VALUES (285, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/0662fd83-754a-4683-9f57-4df716de9a34.png" width="800" height="464" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年11月23日，中国科学院院士陈国良一行到访先锋小镇考察，在参观了区块链专家小村、区块链学院以及听完介绍后，陈国良院士表示很高兴受聘为智能计算战略发展专家顾问，也很乐意为学校的发展贡献力量。陪同考察的有中国科学院计算技术研究所研究员、江西软件大学客座教授张云泉，北京启升科技副总、海云基金创始人王海英，北京理工大学数据科学实验中心主任陈学斌教授。
</p>');
INSERT INTO content VALUES (286, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/ecf94f3a-c3d7-4a08-b79b-7985d0184878.png" width="800" height="493" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;"></p>
<p style="text-indent: 2em;">
    2019年11月8日，江西省发改委高技术处处长余世华、副处长刘波和省信息中心副主任吴俐等一行莅临先锋小镇考察调研，就区块链的产业发展、应用场景、商业模式及通过新技术应用解决实际问题等进行了深入交流。
</p>');
INSERT INTO content VALUES (287, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/69053442-5274-4676-92c3-9cc71b0155e0.png" width="800" height="464" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年11月2日，先锋软件集团董事长、学校董事长陈苏通过网络现场直播的方法在先锋小镇作《区块链改变世界——我们在区块链时代大有所为》专题讲座，江西软件大学万名师生同步学习直播讲座。先锋小镇在五年前就开始了区块链研发与应用、区块链人才培养研究，举办了数百场区块链专题讲座。<br/>
</p>
<p style="text-indent: 2em;">
    <br/>
</p>');
INSERT INTO content VALUES (288, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/c306094b-e190-4100-aa5c-34f8708872e7.png" width="800" height="464" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年10月31日，区块链专家江海教授在先锋小镇为全体员工及创业者作题为《正解区块链》的专题讲座，对哈希、区块链的“链”、挖矿、智能合约、DAPP（分布式应用）等用现场演示的方法生动的正解区块链。
</p>
<p style="text-indent: 2em;">
    <br/>
</p>');
INSERT INTO content VALUES (289, '<p style="text-indent: 0em; text-align: center;">
    <strong><img src="/branch_static_img/1864617b-f6e6-4981-a936-f8ae10cb22ad.png" width="800" height="464" title="" alt=""/></strong>
</p>
<p style="text-indent: 2em;">
    2019年10月31日，南昌市第四届先锋创客节。
</p>
<p style="text-indent: 2em;">
    <br/>
</p>');
INSERT INTO content VALUES (290, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: undefinedquot;Microsoft YaHeiundefinedquot;; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: rgb(51, 51, 51); text-indent: 0em; white-space: normal; text-align: center;">
