<p style="text-indent: 2em;">
    2019年10月13日，先锋小镇在2019年全国大学生电子信息类创新能力大赛——通信工程应用竞赛中喜获佳绩。
</p>');
INSERT INTO content VALUES (291, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: undefinedquot;Microsoft YaHeiundefinedquot;; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: rgb(51, 51, 51); text-indent: 0em; white-space: normal; text-align: center;">
