<p style="text-indent: 2em;">
    2019年9月19日，慧科集团合伙人、首席战略官、慧科研究院院长陈滢博士来先锋小镇作《产学融合2.0赋能新人才培养》的专题报告。
</p>');
INSERT INTO content VALUES (292, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: undefinedquot;Microsoft YaHeiundefinedquot;; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: rgb(51, 51, 51); text-indent: 0em; white-space: normal; text-align: center;">
