<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 32px;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Apple Color Emoji', 'Emoji Symbols Font', 'Segoe UI Symbol', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-05-17%2013%3A10%3A52ee.jpg?Expires=1936588252&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=L0nePgvZ5H7Fd9NR3KATSQVKXIc%3D" alt="" width="680" height="461" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 32px;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 32px;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-05-17%2013%3A12%3A28ff.jpg?Expires=1936588348&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=wSljd%2F%2FpUE0SggD1tK0sTlicmuc%3D" alt="" width="680" height="412" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 32px;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 32px;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-05-17%2013%3A13%3A11gg.jpg?Expires=1936588391&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=LBhAtz7t32E67eNnYyhIwCfrGos%3D" alt="" width="680" height="462" /></p>');
INSERT INTO content VALUES (385, '<p class="MsoNormal" style="text-indent: 28.0000pt; mso-char-indent-count: 2.0000;"><span style="font-family: arial, helvetica, sans-serif;"><span style="color: #191919; font-size: 14pt; background: #ffffff;">为进一步深化我校&ldquo;互联网+&rdquo; 创新创业大赛工作，5月21日下午，由创新创业学院主办&ldquo;数字化转型的机遇与挑战 &mdash;&ldquo;互联网+&rdquo;大赛视角下的数字科技创新&rdquo;专题讲座在学术报告厅召开</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">。本次讲座特邀请到了</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">慧科集团合伙人、首席战略官、慧科研究院院长陈滢博士</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">来为同学们演讲。</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">全校</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">五百余师生聆听报告。本次讲座由</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">创新创业学院</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">院长</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">倪锋</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">教授主持。</span></span></p>
<p class="MsoNormal" style="text-indent: 28.0000pt; mso-char-indent-count: 2.0000;"><span style="mso-spacerun: 'yes'; font-family: Arial; mso-fareast-font-family: 宋体; color: #191919; font-size: 14.0000pt; mso-font-kerning: 1.0000pt; background: #ffffff; mso-shading: #ffffff;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-24%2010%3A28%3A16%E5%9B%BE%E7%89%871.png?Expires=1937183296&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QinY%2FVkB40mE6FEnuD4GiIQpUQ0%3D" alt="" width="609" height="412" />&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 28.0000pt; mso-char-indent-count: 2.0000;"><span style="font-family: arial, helvetica, sans-serif;"><span style="color: #191919; font-size: 14pt; background: #ffffff;">此次讲座座无虚席，充分体现了我校学子</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">在</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">追求创新创业路上的学习热情。</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">当今的社会大环境下，创新创业教育已成为</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">高等教育</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">大势所趋</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">，</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">开设创新创业课程，进行创新创业教育改革最重要的意义，并不是鼓励所有大学生都去创业，而是</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">通过学习</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">创新创业的</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">实践</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">尝试，能够帮助大学生更好的认识自己，从而发掘自身的更多</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">潜</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">能。</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">&nbsp;</span></span></p>
<p class="MsoNormal" style="text-indent: 28.0000pt; mso-char-indent-count: 2.0000;"><span style="mso-spacerun: 'yes'; font-family: 宋体; mso-ascii-font-family: Arial; mso-hansi-font-family: Arial; mso-bidi-font-family: Arial; color: #191919; font-size: 14.0000pt; mso-font-kerning: 1.0000pt; background: #ffffff; mso-shading: #ffffff;"><span style="font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp;&nbsp;</span><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-24%2010%3A28%3A46%E5%9B%BE%E7%89%872.png?Expires=1937183326&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=VznL3FMDsipZaffJlH%2Bt8I%2B93WM%3D" alt="" width="700" height="473" /></span></p>
<p class="MsoNormal" style="text-indent: 28.0000pt; mso-char-indent-count: 2.0000;"><span style="font-family: arial, helvetica, sans-serif;"><span style="color: #191919; font-size: 14pt; background: #ffffff;">此次讲座</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">陈博士紧密联系</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">&ldquo;</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">互联网+</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">&rdquo;</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">&nbsp;</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">创新创业</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">大赛</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">解读</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">数字技术创新创业项目如何挖掘和培育</span><span style="color: #191919; font-size: 14pt; background: #ffffff;">、如何构建一份完整的项目计划书、大赛评分规则等内容，通过案例分析与同学们积极互动,共同探讨此次大赛的相关问题，通过此次的讲座，参赛的指导老师和同学们都受益良多。</span></span></p>
<p class="MsoNormal" style="text-indent: 32.0000pt; mso-char-indent-count: 2.0000;"><span style="mso-spacerun: 'yes'; font-family: Arial; mso-fareast-font-family: 宋体; color: #191919; font-size: 16.0000pt; mso-font-kerning: 1.0000pt; background: #ffffff; mso-shading: #ffffff;"><span style="font-family: 'andale mono', monospace;">&nbsp;</span><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-24%2010%3A29%3A08%E5%9B%BE%E7%89%873.png?Expires=1937183348&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=fKEKydkTXArowZ%2BkbSKwYAmh79c%3D" alt="" width="583" height="394" /></span></p>
<p class="MsoNormal" style="text-indent: 32.0000pt; mso-char-indent-count: 2.0000;"><span style="font-family: arial, helvetica, sans-serif; color: #191919; font-size: 16pt; background: #ffffff;">最后，为更好地指导我校大赛参赛项目和创新创业工作，聘请陈滢博士担任我校创新创业导师。</span></p>');
INSERT INTO content VALUES (386, '<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;">为进一步推进我院&ldquo;互联网+&rdquo;大学生创新创业大赛工作，激励我院师生创新创业的热情，2021年5月11日下午14：00，软件工程学院在A9-213召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会。座谈会邀请了创新创业学院院长倪锋，软件工程学院党总支书记鲍庆军，副院长柴亚辉博士及全体教职工出席会议。座谈会由副院长柴亚辉博士主持。</span></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff;"><img class="am-img-responsive am-img-thumbnail am-u-sm-10 am-u-sm-centered" style="box-sizing: border-box; vertical-align: middle; border: 1px solid #dddddd; width: 542.125px; padding: 2px; float: none; position: relative; display: block; max-width: 100%; height: auto; line-height: 1.6; border-radius: 0px; transition: all 0.2s ease-in-out 0s; margin-left: auto; margin-right: auto;" title="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" src="http://rjxy.jxuspt.com/uploads/ueditor/image/20210513/1620864559969539.jpg" alt="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" /></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;">首先，鲍书记代表软件工程学院对创新创业倪锋院长的到来表示欢迎。鲍庆军强调，&ldquo;互联网+&rdquo;大学生创新创业大赛是促进我校以赛促教、以赛促学、以赛促技的人才培养模式，我们要提高工作站位，思想上再重视；加强组织领导，行动上再落实。软件工程学院&ldquo;互联网+&rdquo;大学生创新创业大赛负责人席慧琴对学院&ldquo;互联网+&rdquo;大学生创新创业大赛的准备情况作了简单的汇报。</span></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;">创新创业倪锋院长介绍了&ldquo;互联网+&rdquo;大学生创新创业大赛的具体情况，包括大赛的报名时间、报名方式、相关要求和省赛安排。各位项目申报负责人对申报项目内容作了详细的汇报，在座教师针对各自思考的问题分别发言，进行深入讨论。倪锋院长认真听取了汇报提出了几点建议。作为软件大学最大的学院他希望软件学院在&ldquo;互联网+&rdquo;大学生创新创业大赛能申报更多优秀的项目参赛，为我校增添光彩。</span></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-align: center;"><img class="am-img-responsive am-img-thumbnail am-u-sm-10 am-u-sm-centered" style="box-sizing: border-box; vertical-align: middle; border: 1px solid #dddddd; width: 542.125px; padding: 2px; float: none; position: relative; display: block; max-width: 100%; height: auto; line-height: 1.6; border-radius: 0px; transition: all 0.2s ease-in-out 0s; margin-left: auto; margin-right: auto;" title="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" src="http://rjxy.jxuspt.com/uploads/ueditor/image/20210513/1620864588179339.jpg" alt="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" /></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;">&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;"><img class="am-img-responsive am-img-thumbnail am-u-sm-10 am-u-sm-centered" style="box-sizing: border-box; vertical-align: middle; border: 1px solid #dddddd; width: 542.125px; padding: 2px; float: none; position: relative; display: block; max-width: 100%; height: auto; line-height: 1.6; border-radius: 0px; transition: all 0.2s ease-in-out 0s; margin-left: auto; margin-right: auto;" title="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" src="http://rjxy.jxuspt.com/uploads/ueditor/image/20210513/1620864627133486.jpg" alt="我院召开&ldquo;互联网+&rdquo;大学生创新创业大赛交流座谈会" /></span></p>
<p style="box-sizing: border-box; margin: 1.6rem 0px; color: #333333; font-family: 'Segoe UI', 'Lucida Grande', Helvetica, Arial, 'Microsoft YaHei', FreeSans, Arimo, 'Droid Sans', 'wenquanyi micro hei', 'Hiragino Sans GB', 'Hiragino Sans GB W3', FontAwesome, sans-serif; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; font-family: 宋体, SimSun; font-size: 18px;">最后，副院长柴亚辉博士号召全院专职教师充分发挥软件专业特色与优势，积极参与支持互联网+创新创业大赛，展开头脑风暴，充分创新创意，支持学校与学院的创新创业大赛项目。</span></p>');
INSERT INTO content VALUES (387, '<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px 20px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; font-size: 14px; color: #000000; line-height: 1.8; letter-spacing: 1.8px;">
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; text-indent: 2em; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Microsoft YaHei', Arial, sans-serif;">为更好地做好学院创新创业教育及第七届&ldquo;互联网+&rdquo;创新创业大赛相关工作，5月11日上午，创新创业学院院长<span style="margin: 0px; padding: 0px; max-width: 100%; letter-spacing: 1.8px; box-sizing: border-box !important; overflow-wrap: break-word !important;">倪峰、</span>黄敏老师莅临网络工程学院指导工作、交流经验。此次会议于A10-417会议室召开，会议由网络工程学院院长吴志勇主持，学院夏顺顺老师、田莎莎老师、陈毓茹老师参加会议。</span></p>
<hr style="margin: 0px; padding: 0px; max-width: 100%; border-color: rgba(0, 0, 0, 0.098); transform-origin: 0px 0px 0px; transform: scale(1, 0.5); box-sizing: border-box !important; overflow-wrap: break-word !important;" />
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; text-indent: 0em; overflow-wrap: break-word !important;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-27%2009%3A02%3A1801.jpg?Expires=1937437338&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=ufFwhGpzUDOwA1CSRcDwXTRmBC0%3D" width="726" height="409" /></section>
<hr style="margin: 0px; padding: 0px; max-width: 100%; border-color: rgba(0, 0, 0, 0.098); transform-origin: 0px 0px 0px; transform: scale(1, 0.5); box-sizing: border-box !important; overflow-wrap: break-word !important;" />
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; text-indent: 2em; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Microsoft YaHei', Arial, sans-serif;"><br />会议开始，<span style="margin: 0px; padding: 0px; max-width: 100%; letter-spacing: 1.8px; box-sizing: border-box !important; overflow-wrap: break-word !important;">倪峰</span>院长对我院在第七届全国国际&ldquo;互联网+&rdquo;大学生创新创业大赛中参赛项目提交积极表示肯定，并介绍了<span style="margin: 0px; padding: 0px; max-width: 100%; letter-spacing: 1.8px; box-sizing: border-box !important; overflow-wrap: break-word !important;">大学生创新创业大赛</span>的背景、基本情况和近年进展变化，从竞赛赛制、赛道解读、参赛时间节点等方面分享了指导经验与注意事项，更就我院专业学科特色进行了针对性的指导，帮助挖掘推荐潜在项目。</span></p>
</section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; overflow-wrap: break-word !important;">
<section style="margin: 10px 0px 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: flex; flex-flow: row nowrap; text-align: center; justify-content: center;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: inline-block; vertical-align: top; width: auto; flex: 0 0 0%; align-self: flex-start; height: auto; line-height: 0.5;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important;"></section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: inline-block; vertical-align: top; width: auto; flex: 0 0 0%; align-self: flex-start; height: auto; line-height: 0.5;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-27%2009%3A06%3A5302.jpg?Expires=1937437613&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=vgTYVKWtJNK9rtJ%2BMMCzMhV4ygg%3D" width="714" height="536" /></section>
</section>
</section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; overflow-wrap: break-word !important;">
<section style="margin: 0px 0px 10px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: flex; flex-flow: row nowrap; text-align: center; justify-content: center;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: inline-block; vertical-align: bottom; width: auto; flex: 0 0 0%; align-self: flex-end; height: auto; line-height: 0.5;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important;"><br /><br /></section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; display: inline-block; vertical-align: bottom; width: auto; flex: 0 0 0%; align-self: flex-end; height: auto; line-height: 0.5;">
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important;"></section>
</section>
</section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px 20px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; font-size: 14px; color: #000000; line-height: 1.8; letter-spacing: 1.8px;">
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; text-indent: 2em; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Microsoft YaHei', Arial, sans-serif; text-indent: 2em; letter-spacing: 1.8px;">期间，夏顺顺老师表态：一、落实创新创业的工作体现了学校对比赛以及对培养创造型人才的高度重视；二、创新需要体现在教育教学上，创新教育要落实到课程建设，专业建设和学科建设中去；三、学校以及老师同学们都要重视创新创业工作，同时老师需要提升自身能力，以更好地指导和培育创新型人才，让学生支撑学科建设。</span></p>
<hr style="margin: 0px; padding: 0px; max-width: 100%; border-color: rgba(0, 0, 0, 0.098); transform-origin: 0px 0px 0px; transform: scale(1, 0.5); box-sizing: border-box !important; overflow-wrap: break-word !important;" />
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; clear: both; min-height: 1em; text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-05-27%2009%3A04%3A2603.jpg?Expires=1937437466&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=7GSfZCSO8FrpFXUTsbyz7NKmpFA%3D" width="731" height="398" /></p>
</section>
</section>
<section style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px 20px; max-width: 100%; box-sizing: border-box; word-wrap: break-word !important; font-size: 14px; color: #000000; line-height: 1.8; letter-spacing: 1.8px;"><hr style="margin: 0px; padding: 0px; max-width: 100%; border-color: rgba(0, 0, 0, 0.098); transform-origin: 0px 0px 0px; transform: scale(1, 0.5); box-sizing: border-box !important; overflow-wrap: break-word !important;" />
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; text-indent: 2em; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Microsoft YaHei', Arial, sans-serif;">最后，吴志勇院长指出参加<span style="margin: 0px; padding: 0px; max-width: 100%; letter-spacing: 1.8px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&ldquo;互联网+&rdquo;创新创业大赛</span>最重要的是通过比赛培养综合素质能力的人才，营造探究和创新的学习氛围，推动网络工程学院的发展。</span></p>
<p style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; text-indent: 2em; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; word-wrap: break-word !important; font-family: 'Helvetica Neue', Helvetica, 'Hiragino Sans GB', 'Microsoft YaHei', Arial, sans-serif;">本次交流活动，体现了学院对大学生创新创业工作的重视，同时为我院教师指导大学生参与大学生创新创业类竞赛提供了宝贵经验，也为我院学科建设相关规划提出更好的发展指导。</span></p>
</section>
</section>');
INSERT INTO content VALUES (388, '<p><span style="color: #333333; font-family: arial, helvetica, sans-serif; font-size: 14pt; text-align: justify;">&nbsp; &nbsp; &nbsp; 6月6日，来自全国各地的知名企业家、区块链技术专家、职业教育专家和教授等齐聚南昌先锋软件职业中专学校，在&ldquo;新时代、新征程&mdash;数字时代中职教育前景展望&rdquo;论坛上，共同探讨职业教育改革创新的路径，促进区块链技术与中职教育的融合发展，促进江西数字经济高质量跨越式发展。<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-06-09%2014%3A24%3A16%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20210609142257.jpg?Expires=1938579856&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=70nxO8eOV4Vy03ZMItEppULRGH0%3D" alt="" width="690" height="379" /></span></p>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp; &nbsp; &nbsp;开幕式上，南昌先锋软件职业中专学校董事长陈方平代表承办方致辞，他表示，在数字经济风起云涌的新时代，在国家大力发展中职教育、全力打造大国工匠的新征程上，中职教育大有可为、前景广阔。希望参与论坛的嘉宾积极建言献策，为中国、为江西、为南昌职业教育的发展，找准方向、提升信心。</span></p>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp; &nbsp; &nbsp;江西省政协原副主席殷国光在讲话中指出，IT人才培养既包括数字经济人才，也包括大量的数字&ldquo;工匠&rdquo;、数字操作应用型人才，这是中职、高职、职本三个层次人才培养融合贯通的重要基础，职业中专培养的人才正符合这一方面的要求。本次论坛正值江西省职业教育周和南昌市职业教育月，办得及时而且意义重大，紧紧把握住了服务江西省战略性新兴产业发展这个大方向。</span></p>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; 中国青少年科技辅导员协会监事长李晓亮也发表了致辞，他指出，当下社会对于职业教育的需求越来越迫切，对高素质人才的渴求也越来越强烈。南昌先锋软件职业中专学校积极主动适应社会发展，努力满足时代要求，在服务中广集办学资源，在服务中求得发展动力和发展空间，正是抓住当下百年未有之大变局的历史机遇。</span></p>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F03e1337fj00qud5mh003kc000m800e7m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F03e1337fj00qud5mh003kc000m800e7m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
<figure data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F03e1337fj00qud5mh003kc000m800e7m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-family: arial, helvetica, sans-serif; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp; 开幕式后，吉安市职业技术大学党委书记欧阳亮和北京理工大学机器人中心主任罗庆生分别作了《数字经济背景下中职教育品质建设》《关于职业教育转型升级与区域发展相互联系的思考》的主旨演讲。论坛嘉宾还参加了南昌先锋软件职业中专学校开工剪彩仪式。</span></figure>
</div>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2Fecf80245j00qud5mh002rc000m800cum.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2Fecf80245j00qud5mh002rc000m800cum.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
</div>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F4141c048j00qud5mh003mc000m800d6m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F4141c048j00qud5mh003mc000m800d6m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
</div>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F94b4ec03j00qud5mh002rc000m800b4m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F94b4ec03j00qud5mh002rc000m800b4m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
</div>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2Fe184a081j00qud5mh002rc000m800bvm.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2Fe184a081j00qud5mh002rc000m800bvm.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
</div>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp; &nbsp; &nbsp; 下午，在《数字时代的中职教育与区域经济发展》《区块链技术与数字时代的中职教育》《人工智能与数字时代的中职教育》《VR/AR技术与数字时代的中职教育》《区块链技术与数字经济》五个分论坛上，蚂蚁金服、华为、小米科技、平安科技、安博教育、千锋教育、百硕、高通、HTC、紫光、中国联通等大一批科技公司和教育公司的专家共同探讨数字时代中职教育的发展方向和前景。</span></p>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp; &nbsp; &nbsp; 参加本次论坛的还有，南昌市教育局、江西省信息中心、江西省区块链学会、江西省区块链行业协会、江西省区块链专家委员会、先锋软件集团、中科先锋教育发展有限公司、江西软件职业技术大学、都昌县人民政府、宜春宜阳新区教体局等单位的领导。</span></p>
<div class="m-photo " style="margin: 0.58rem 0px 0.5rem; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; position: relative; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;">
<figure class="js-img js-lazy img-loaded u-img-placeholder" style="margin: 0px; padding: 0px; border: 0px; -webkit-user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); position: relative; height: auto;" data-min="120" data-retry="1" data-alt="" data-echo="//nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F2cca6755j00qud5mh002xc000m80093m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;"><img style="margin: 0px auto; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); vertical-align: top; max-width: 100%; width: 670px; display: block;" src="https://nimg.ws.126.net/?url=http%3A%2F%2Fdingyue.ws.126.net%2F2021%2F0608%2F2cca6755j00qud5mh002xc000m80093m.jpg&amp;thumbnail=690x2147483647&amp;quality=75&amp;type=jpg" /></span></figure>
</div>
<p style="margin: 0.4rem 0px 0px; padding: 0px; border: 0px; user-select: text; box-sizing: border-box; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); max-height: 9999.99rem; color: #333333; font-family: -apple-system, 'Hiragino Sans GB', BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 36px;"><span style="font-size: 14pt; font-family: arial, helvetica, sans-serif;">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;南昌先锋软件职业中专学校与江西软件职业技术大学同属先锋教育集团下属、是集本科、大专、中专为一体的教育产业联盟。办学十几年来，已为社会培养近万名&ldquo;软件蓝领&rdquo;，为南昌市地方经济的发展，做出了突出的贡献。无论是当年的服务外包、VR/AR，还是现在的区块链，都是走在学术和科技创新的前沿。同时也为南昌地区区域经济的发展，培养了大量的软件基础性人才，为带动周边的经济发展起到了引领作用。</span></p>');
INSERT INTO content VALUES (389, '<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">为全面落实习近平总书记给中国</span><span style="font-family: 宋体;">&ldquo;互联网</span><span style="font-family: Calibri;">+</span><span style="font-family: 宋体;">&rdquo;大学生创新创业大赛&ldquo;青年红色筑梦之旅&rdquo;大学生回信重要精神，推进我校创新创业教育改革，提开教育质量、培养创新创业人才。</span><span style="font-family: Calibri;">6</span><span style="font-family: 宋体;">月</span><span style="font-family: Calibri;">11</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">日</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">在江西软件职业技术大学路演大厅举办了第七届</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;">&ldquo;<span style="font-family: 宋体;">互联网</span><span style="font-family: Calibri;">+&rdquo;</span><span style="font-family: 宋体;">大学生创新创业大赛，</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">创新创业大赛</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">已成为覆盖全国所有高校，面向全体高校学生，影响最大的赛事活动之一，成为深化高校创新创业教育改革的载体，促进高校学生全面</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">发</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">展的重要平台和推动产学研用结合的关键纽带。<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-06-13%2020%3A26%3A29%E5%9B%BE%E7%89%871.png?Expires=1938947190&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=xnzo5ux6Z0lM69gFypXV%2FH90lsg%3D" alt="" width="987" height="427" /></span></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-06-13%2020%3A28%3A18%E5%9B%BE%E7%89%872.png?Expires=1938947298&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=k%2BTDjbA7qWEShgtVUFG4WOfwej4%3D" alt="" width="839" height="363" />本次参加的评委有王庆教授、王强老师、聂永昭老师以及创新创业学院院长倪锋教授，</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">本次校赛分为高教主赛道、青年红色筑梦之旅赛道、职教赛道</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">三个赛道</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">，总共有</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: Calibri;">1867</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">项目报名，</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">经院级比赛共推荐</span><span style="font-family: Calibri;">30</span><span style="font-family: 宋体;">项参加校赛，经过专家网评</span><span style="font-family: Calibri;">23</span><span style="font-family: 宋体;">个项目进入现场路演决赛环节即争夺金、银、铜奖、优秀奖，现场路演</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;">241<span style="font-family: 宋体;">名学生参加</span><span style="font-family: Calibri;">&ldquo;</span><span style="font-family: 宋体;">互联网</span><span style="font-family: Calibri;">+&rdquo;</span><span style="font-family: 宋体;">校赛，</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">这</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">三个赛道共</span>2</span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: Calibri;">3</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">支队伍对决现场答辩，带来了一场别开生面的视听盛宴。</span></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">参赛团队主讲人用沉稳、响亮的声音从容不迫地对项目背景、市场需求、技术优势等内容进行介绍。</span>2</span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: Calibri;">3</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">个项目分属不同领域，却无一不体现出了选手们</span>&ldquo;<span style="font-family: 宋体;">在创新创业中增长智慧才干，在艰苦奋斗中锤炼意志品质</span><span style="font-family: Calibri;">&rdquo;</span><span style="font-family: 宋体;">的</span><span style="font-family: Calibri;">&ldquo;</span><span style="font-family: 宋体;">我敢闯、我会创</span><span style="font-family: Calibri;">&rdquo;</span><span style="font-family: 宋体;">的大赛精神。每个项目路演结束后，三位评委按照《第七届中国国际</span><span style="font-family: Calibri;">&ldquo;</span><span style="font-family: 宋体;">互联网</span><span style="font-family: Calibri;">+&rdquo;</span><span style="font-family: 宋体;">大学生创新创业大赛评审规则》从项目团队、创新性、实效性、商业维度、创业维度等不同方面给项目打分</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">，</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">每个项目分数的公布都让观众们屏息以待。<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-06-13%2020%3A30%3A29%E5%9B%BE%E7%89%873.png?Expires=1938947429&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Pso2ZbMAHJX31uw5kBBnYTd4TUA%3D" alt="" width="914" height="457" /></span></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">经过一天的激烈角逐，</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">新媒体学院项目红色筑梦（</span><span style="font-family: 宋体;">&ldquo;红旅&rdquo;公益组）项目以及新媒体学院项目创意先锋（高职赛道创意组）项目博得了评委与观众的一致好评。 两个项目</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">从</span>2</span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: Calibri;">3</span></span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">个项目中脱颖而出</span></span><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">获得大赛金奖，大赛还产生了职教赛道《基于区块链的税务信息管理》等</span><span style="font-family: Calibri;">5</span><span style="font-family: 宋体;">位银奖，职教赛道《基于智能化虚拟现实的英语学习系统》等</span><span style="font-family: Calibri;">10</span><span style="font-family: 宋体;">位铜奖。</span></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">金奖获得者陶新茹以及她的团队表示能够参加我们这个红色筑梦的项目，帮助江西农产品文化发扬光大，是我觉得十分有意义的一件事。这次的创业创新比赛也让我明白身为一名媒体人的责任。在互联网时代充分利用好专业的优势让更多的宝藏能够被发现，被看见。未来也会和我的团队把我们这个红色筑梦项目做的更好，希望能够帮助更多的人。</span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">参赛选手表示在参加比赛时，感受到身边都是人才济济。感觉到自己还需要更加努力学习。对于自己所学专业呀有了进一步了解。知道了新媒体在时代发展中的重要性。对于以后的学习也不会迷茫，有了具体学习目标。同样在这次比赛中，我学会了怎么去全面思考一件事，怎么去落实做好一件事。<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2021-06-13%2020%3A31%3A39%E5%9B%BE%E7%89%874.png?Expires=1938947499&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QOzdyOVkuquhKKZ57BjBNNTm65A%3D" alt="" width="987" height="457" /></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;">本次大赛充分展现我校学子&ldquo;敢闯会创&rdquo;的良好精神风貌，</span><span style="font-family: Calibri; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">进一步激发了大学生的创造活力与创新精神，加快促进了</span>&ldquo;<span style="font-family: 宋体;">互联网</span>+&rdquo;<span style="font-family: 宋体;">新业态形成，为建设创新型国家和</span>&ldquo;<span style="font-family: 宋体;">强富美高</span>&rdquo;<span style="font-family: 宋体;">提供源源不断的人才智力支撑。</span></span></p>
<p class="MsoNormal" style="margin-left: 0pt; text-indent: 28pt; line-height: 200%;"><span style="font-family: 宋体; line-height: 200%; font-size: 14pt;"><span style="font-family: 宋体;">我院将持续推动学生的创新创业能力发展、激发学生的创造力，培养为社会发展造就</span><span style="font-family: 宋体;">&ldquo;大众创业、万众创新&rdquo;格局的生力军。</span></span></p>');
INSERT INTO content VALUES (390, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; text-align: justify; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近日，第十七届&ldquo;挑战杯&rdquo;科技竞赛主办单位下发的表彰通知，我校共有2项作品在此次竞赛中获奖。钟啸等9位同学创作的《向阳而生》荣获本次竞赛红色专项二等奖；郑乐馨、周明华两位同学创作的《区块链音乐版权（MCT）交易平台》荣获本次竞赛三等奖。<br style="box-sizing: border-box;" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; text-align: justify; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-09-22%2015%3A16%3A501.png?Expires=1947655010&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=k2HVwJK2648DWbQkSGqeJAN90ss%3D" alt="" width="800" height="530" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-09-22%2015%3A16%3A502.png?Expires=1947655010&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=hjhm6MLKnB5XvbcLE5orKbSc%2BSw%3D" alt="" width="800" height="600" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; text-align: justify; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; text-align: justify; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">自本届&ldquo;挑战杯&rdquo;启动以来，学校领导高度重视，统筹安排部署，各部门各学院支持配合，校团委进行精心组织规划。各参赛学院还发挥出了专业优势，选派优秀指导教师全力打磨，共推荐了自然科学类学术论文作品3件、哲学社会科学类社会调查报告和学术论文作品3件、科技发明制作B类作品1件、红色专项赛道作品3项。这些参赛作品涉及领域广泛，思路新颖、内容充实、形式多样，彰显了江软学子课外学术科技创新能力，对激励广大学生积极参与科技创新和学术研究起到了良好的示范引领作用。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; text-align: justify; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">此次斩获荣誉，也充分体现了江软学子在竞赛中始终坚持&ldquo;崇尚科学、追求真知、勤奋学习、锐意创新、迎接挑战&rdquo;的宗旨。同时，对推动我校学生参与学术科技实践、发现和培养创新型人才、深化高校素质教育等方面发挥了积极作用。</span></p>');
INSERT INTO content VALUES (391, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校瞄准全球技术发展的前沿阵地，成立了全国首个区块链学院，率先设置区块链技术专业，目前学院在校生1186名。为进一步推进区块链技术与应用，培养高素质技术技能人才，2021年4月，我校区块链学院选择了1+X《区块链智能合约开发证书》作为试点证书，开启了与北京鸾翔创杰科技有限公司（以下简称：鸾翔创杰）的校企合作。双方共同负责区块链专业的培养方案编制、课程教学、职业培训、证书考试等育人环节，并面向江西省和全国推进师资培训、1+X书证融通，将成功模式推广至湖南、广东等地。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">一、书证融通</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校成为《区块链智能合约开发职业技能等级标准》的编写单位，与培训评价组织北京中链智培科技有限公司（以下简称：中链智培）共同编写了《区块链智能合约开发证书》的技能等级标准。同时，还与北京智谷星图教育科技有限公司（以下简称：智谷星图）逐步推进1+X中级证书教材的合作编写工作，该教材将由清华大学出版社出版。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><br style="box-sizing: border-box;" /><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A48%3A44blob?Expires=1953262124&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=p2q6o9lQmkrh%2FI0v0%2BohcN5PFMc%3D" alt="" width="650" height="445" /><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-indent: 2em;">图1 我校参与《区块链智能合约开发职业技能等级证书职业技能标准》编制工作</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">此外，学校在基于区块链1+X证书的区块链人才培养上起到了标杆与示范作用，成为江西省区块链1+X证书牵头院校。学校与鸾翔创杰联合编写了基于1+X证书课程体系的&ldquo;区块链技术应用专业&rdquo;人才培养方案修订稿；提供教材、教学支持工作；安排线上与线下结合的专业课培训，进行模拟考试筛选；组织1+X区块链证书的考试。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2021年6月11日，我校举办了全国首批&ldquo;1＋X&rdquo;区块链智能合约开发职业技能等级证书（中级）考试。区块链学院27位同学参加了此次考试，通过率高达80%。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A49%3A31blob?Expires=1953262171&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=LuOs%2BatQmhtWWXRrgdJD%2BRWtHtU%3D" alt="" width="650" height="501" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图2&nbsp;学校举办全国首批&ldquo;1＋X&rdquo;区块链智能合约开发职业技能等级证书（中级）考试</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">二、师资研修</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校联合智谷星图打造了&ldquo;双师型&rdquo;师资队伍。此外，学校还依托中国区块链智库的院士、教授、企业高管等优质师资，邀请腾讯、微众银行、蚂蚁、万向等区块链行业领军企业的一线工程师、实战专家，开展丰富且体系化的教学。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">今年上半年，我校举行了&ldquo;全国区块链师资能力提升培训班&rdquo;，来自全国各地9所高校的区块链技术、软件工程技术、信息安全与管理等相关专业带头人和分管教学工作的校(院)长、主任等人员共计51人参加。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图3&nbsp;学校举行&ldquo;全国区块链师资能力提升培训班&rdquo;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><a style="box-sizing: border-box; color: #337ab7; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;" name="_Hlk84857970"></a>三、平台共搭</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校已经联合智谷星图共同研发了区块链教学实训、实战、模考三大平台，覆盖区块链产业人才培养的全流程。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（一）教学实训平台。我校联合智谷星图研发五大实训产品：区块链技术应用（64课时）、智能合约技术与开发（64课时）、DApp应用开发（64课时）、联盟链开发（64课时）、区块链系统开发（64课时），上述实训课程对应区块链运维工程师、智能合约开发工程师、联盟链开发工程师等岗位核心技能要求。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（二）区块链实战平台。我校联合智谷星图研发的区块链实战平台是基于区块链真实环境所打造的区块链技术与应用开发实训平台，提供一站式开发工具。该平台接入的真实区块链系统包括：以太坊、智谷CTIS教育区块链、腾讯TBaaS、微众银行FISCO BCOS、Hyperledger、蚂蚁链、百度超级链、JD Chain、趣链飞洛平台等，不断拓展新环境，融入新技术。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（三）模拟考试系统。我校联合智谷星图研发的考试系统支持选择、判断、填空、编程、实操等各类题型，逐步实现教考分离。该系统已被工信部采用，作为区块链岗位能力提升培训及考试系统。同时，此考试系统录入相关题库后，也可用于其他社会培训及证书的考试，复用价值高。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">四、社会服务</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2020年9月，学校与先锋软件股份有限公司、数字江西科技有限公司展开校企合作，成立蚂蚁链（江西）研究院，依托蚂蚁链技术在吉安市打造了区块链农产品溯源项目。从产品品类到企业资质，从种植环境条件到人员管控，从清洗筛选到分拣包装，从销售到运输建立和完善溯源管理体系的各个环节，我校师生将所有数据载入到区块链中，打通农业生产、交易和流通等各个关键环节要素。通过区块链、大数据技术对载入先锋可信区块链中的基础数据进行整合运算处理，形成有价值、可用、不可篡改、透明公开的数据，给上层应用提供数据服务。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">井冈蜜柚通过科技力量不断提升产品附加值，在解决丰产又丰收的问题上探索出了新的路径，通过优质优价的定位，实现了生产优化升级，不但卖出了规模，也卖出了好价钱，使井冈蜜柚品牌变&ldquo;名牌&rdquo;，蜜柚农产品的商品变&ldquo;珍品&rdquo;，井冈蜜柚的质量变&ldquo;品质&rdquo;，打造数字化农业示范样板。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图4&nbsp;吉安井冈蜜柚溯源项目</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在1月29日的江西省两会会场上，&ldquo;一个上区块链的柚子&rdquo;脱颖而出成为了两会代表的热议话题，科技创新助力乡村振兴，第一个上蚂蚁链的井冈蜜柚成为了吉安农业产业</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">新的示范标准。&ldquo;区块链+井冈蜜柚&rdquo;在农业领域的先行先试也为下一步构建赋能实体经济、技术创新、管理创新、模式创新协同推进的区块链发展格局打下了良好的基础。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">五、基地共建</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校与鸾翔创杰母公司之一的链人国际咨询（北京）有限责任公司（以下简称：链人国际）联合成立了区块链人才培养基地，让学生学以致用。链人国际是区块链招聘就业服务第一品牌，拥有全国90%以上的市场份额，75%的服务用户是区块链各细分领域龙头企业。智谷星图与链人国际同为区块链国家职业技能标准编制单位，熟知岗位技能要求。我校通过结合上述企业优质资源联合政府、产业园、企业，举办人才双选会、交流会及校招等人才输送活动，为多家龙头企业输送高校实习生。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了留住更多优秀人才留赣发展，服务本地经济，我校联合合作企业组建&ldquo;区块链技术应用实训基地&rdquo;，利用先锋软件及合作企业的市场拓展能力，承接政府及企业项目，形成区块链技术研究、应用开发、项目运维与测试等多重能力的外包服务基地，为更多学生提供高质量就业机会。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校联合智谷星图打造了&ldquo;双师型&rdquo;师资队伍。此外，学校还依托中国区块链智库的院士、教授、企业高管等优质师资，邀请腾讯、微众银行、蚂蚁、万向等区块链行业领军企业的一线工程师、实战专家，开展丰富且体系化的教学。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">今年上半年，我校举行了&ldquo;全国区块链师资能力提升培训班&rdquo;，来自全国各地9所高校的区块链技术、软件工程技术、信息安全与管理等相关专业带头人和分管教学工作的校(院)长、主任等人员共计51人参加。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A51%3A18blob?Expires=1953262278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QGKMxpH93%2BV5cG7O4zryHMSN3OA%3D" alt="" width="650" height="356" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图3&nbsp;学校举行&ldquo;全国区块链师资能力提升培训班&rdquo;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><a style="box-sizing: border-box; color: #337ab7; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;" name="_Hlk84857970"></a>三、平台共搭</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校已经联合智谷星图共同研发了区块链教学实训、实战、模考三大平台，覆盖区块链产业人才培养的全流程。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（一）教学实训平台。我校联合智谷星图研发五大实训产品：区块链技术应用（64课时）、智能合约技术与开发（64课时）、DApp应用开发（64课时）、联盟链开发（64课时）、区块链系统开发（64课时），上述实训课程对应区块链运维工程师、智能合约开发工程师、联盟链开发工程师等岗位核心技能要求。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（二）区块链实战平台。我校联合智谷星图研发的区块链实战平台是基于区块链真实环境所打造的区块链技术与应用开发实训平台，提供一站式开发工具。该平台接入的真实区块链系统包括：以太坊、智谷CTIS教育区块链、腾讯TBaaS、微众银行FISCO BCOS、Hyperledger、蚂蚁链、百度超级链、JD Chain、趣链飞洛平台等，不断拓展新环境，融入新技术。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（三）模拟考试系统。我校联合智谷星图研发的考试系统支持选择、判断、填空、编程、实操等各类题型，逐步实现教考分离。该系统已被工信部采用，作为区块链岗位能力提升培训及考试系统。同时，此考试系统录入相关题库后，也可用于其他社会培训及证书的考试，复用价值高。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">四、社会服务</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2020年9月，学校与先锋软件股份有限公司、数字江西科技有限公司展开校企合作，成立蚂蚁链（江西）研究院，依托蚂蚁链技术在吉安市打造了区块链农产品溯源项目。从产品品类到企业资质，从种植环境条件到人员管控，从清洗筛选到分拣包装，从销售到运输建立和完善溯源管理体系的各个环节，我校师生将所有数据载入到区块链中，打通农业生产、交易和流通等各个关键环节要素。通过区块链、大数据技术对载入先锋可信区块链中的基础数据进行整合运算处理，形成有价值、可用、不可篡改、透明公开的数据，给上层应用提供数据服务。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">井冈蜜柚通过科技力量不断提升产品附加值，在解决丰产又丰收的问题上探索出了新的路径，通过优质优价的定位，实现了生产优化升级，不但卖出了规模，也卖出了好价钱，使井冈蜜柚品牌变&ldquo;名牌&rdquo;，蜜柚农产品的商品变&ldquo;珍品&rdquo;，井冈蜜柚的质量变&ldquo;品质&rdquo;，打造数字化农业示范样板。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A51%3A51undefined?Expires=1953262311&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=2Y7ZlbRrulswfbAXbe0Cos0AONE%3D" alt="" width="650" height="455" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图4&nbsp;吉安井冈蜜柚溯源项目</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在1月29日的江西省两会会场上，&ldquo;一个上区块链的柚子&rdquo;脱颖而出成为了两会代表的热议话题，科技创新助力乡村振兴，第一个上蚂蚁链的井冈蜜柚成为了吉安农业产业</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">新的示范标准。&ldquo;区块链+井冈蜜柚&rdquo;在农业领域的先行先试也为下一步构建赋能实体经济、技术创新、管理创新、模式创新协同推进的区块链发展格局打下了良好的基础。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">五、基地共建</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校与鸾翔创杰母公司之一的链人国际咨询（北京）有限责任公司（以下简称：链人国际）联合成立了区块链人才培养基地，让学生学以致用。链人国际是区块链招聘就业服务第一品牌，拥有全国90%以上的市场份额，75%的服务用户是区块链各细分领域龙头企业。智谷星图与链人国际同为区块链国家职业技能标准编制单位，熟知岗位技能要求。我校通过结合上述企业优质资源联合政府、产业园、企业，举办人才双选会、交流会及校招等人才输送活动，为多家龙头企业输送高校实习生。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了留住更多优秀人才留赣发展，服务本地经济，我校联合合作企业组建&ldquo;区块链技术应用实训基地&rdquo;，利用先锋软件及合作企业的市场拓展能力，承接政府及企业项目，形成区块链技术研究、应用开发、项目运维与测试等多重能力的外包服务基地，为更多学生提供高质量就业机会。</span></p>');
INSERT INTO content VALUES (392, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校瞄准全球技术发展的前沿阵地，成立了全国首个区块链学院，率先设置区块链技术专业，目前学院在校生1186名。为进一步推进区块链技术与应用，培养高素质技术技能人才，2021年4月，我校区块链学院选择了1+X《区块链智能合约开发证书》作为试点证书，开启了与北京鸾翔创杰科技有限公司（以下简称：鸾翔创杰）的校企合作。双方共同负责区块链专业的培养方案编制、课程教学、职业培训、证书考试等育人环节，并面向江西省和全国推进师资培训、1+X书证融通，将成功模式推广至湖南、广东等地。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">一、书证融通</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校成为《区块链智能合约开发职业技能等级标准》的编写单位，与培训评价组织北京中链智培科技有限公司（以下简称：中链智培）共同编写了《区块链智能合约开发证书》的技能等级标准。同时，还与北京智谷星图教育科技有限公司（以下简称：智谷星图）逐步推进1+X中级证书教材的合作编写工作，该教材将由清华大学出版社出版。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><br style="box-sizing: border-box;" /><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A48%3A44blob?Expires=1953262124&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=p2q6o9lQmkrh%2FI0v0%2BohcN5PFMc%3D" alt="" width="650" height="445" /><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-indent: 2em;">图1 我校参与《区块链智能合约开发职业技能等级证书职业技能标准》编制工作</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">此外，学校在基于区块链1+X证书的区块链人才培养上起到了标杆与示范作用，成为江西省区块链1+X证书牵头院校。学校与鸾翔创杰联合编写了基于1+X证书课程体系的&ldquo;区块链技术应用专业&rdquo;人才培养方案修订稿；提供教材、教学支持工作；安排线上与线下结合的专业课培训，进行模拟考试筛选；组织1+X区块链证书的考试。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2021年6月11日，我校举办了全国首批&ldquo;1＋X&rdquo;区块链智能合约开发职业技能等级证书（中级）考试。区块链学院27位同学参加了此次考试，通过率高达80%。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A49%3A31blob?Expires=1953262171&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=LuOs%2BatQmhtWWXRrgdJD%2BRWtHtU%3D" alt="" width="650" height="501" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图2&nbsp;学校举办全国首批&ldquo;1＋X&rdquo;区块链智能合约开发职业技能等级证书（中级）考试</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">二、师资研修</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校联合智谷星图打造了&ldquo;双师型&rdquo;师资队伍。此外，学校还依托中国区块链智库的院士、教授、企业高管等优质师资，邀请腾讯、微众银行、蚂蚁、万向等区块链行业领军企业的一线工程师、实战专家，开展丰富且体系化的教学。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">今年上半年，我校举行了&ldquo;全国区块链师资能力提升培训班&rdquo;，来自全国各地9所高校的区块链技术、软件工程技术、信息安全与管理等相关专业带头人和分管教学工作的校(院)长、主任等人员共计51人参加。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图3&nbsp;学校举行&ldquo;全国区块链师资能力提升培训班&rdquo;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><a style="box-sizing: border-box; color: #337ab7; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;" name="_Hlk84857970"></a>三、平台共搭</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校已经联合智谷星图共同研发了区块链教学实训、实战、模考三大平台，覆盖区块链产业人才培养的全流程。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（一）教学实训平台。我校联合智谷星图研发五大实训产品：区块链技术应用（64课时）、智能合约技术与开发（64课时）、DApp应用开发（64课时）、联盟链开发（64课时）、区块链系统开发（64课时），上述实训课程对应区块链运维工程师、智能合约开发工程师、联盟链开发工程师等岗位核心技能要求。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（二）区块链实战平台。我校联合智谷星图研发的区块链实战平台是基于区块链真实环境所打造的区块链技术与应用开发实训平台，提供一站式开发工具。该平台接入的真实区块链系统包括：以太坊、智谷CTIS教育区块链、腾讯TBaaS、微众银行FISCO BCOS、Hyperledger、蚂蚁链、百度超级链、JD Chain、趣链飞洛平台等，不断拓展新环境，融入新技术。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（三）模拟考试系统。我校联合智谷星图研发的考试系统支持选择、判断、填空、编程、实操等各类题型，逐步实现教考分离。该系统已被工信部采用，作为区块链岗位能力提升培训及考试系统。同时，此考试系统录入相关题库后，也可用于其他社会培训及证书的考试，复用价值高。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">四、社会服务</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2020年9月，学校与先锋软件股份有限公司、数字江西科技有限公司展开校企合作，成立蚂蚁链（江西）研究院，依托蚂蚁链技术在吉安市打造了区块链农产品溯源项目。从产品品类到企业资质，从种植环境条件到人员管控，从清洗筛选到分拣包装，从销售到运输建立和完善溯源管理体系的各个环节，我校师生将所有数据载入到区块链中，打通农业生产、交易和流通等各个关键环节要素。通过区块链、大数据技术对载入先锋可信区块链中的基础数据进行整合运算处理，形成有价值、可用、不可篡改、透明公开的数据，给上层应用提供数据服务。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">井冈蜜柚通过科技力量不断提升产品附加值，在解决丰产又丰收的问题上探索出了新的路径，通过优质优价的定位，实现了生产优化升级，不但卖出了规模，也卖出了好价钱，使井冈蜜柚品牌变&ldquo;名牌&rdquo;，蜜柚农产品的商品变&ldquo;珍品&rdquo;，井冈蜜柚的质量变&ldquo;品质&rdquo;，打造数字化农业示范样板。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图4&nbsp;吉安井冈蜜柚溯源项目</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在1月29日的江西省两会会场上，&ldquo;一个上区块链的柚子&rdquo;脱颖而出成为了两会代表的热议话题，科技创新助力乡村振兴，第一个上蚂蚁链的井冈蜜柚成为了吉安农业产业</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">新的示范标准。&ldquo;区块链+井冈蜜柚&rdquo;在农业领域的先行先试也为下一步构建赋能实体经济、技术创新、管理创新、模式创新协同推进的区块链发展格局打下了良好的基础。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">五、基地共建</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校与鸾翔创杰母公司之一的链人国际咨询（北京）有限责任公司（以下简称：链人国际）联合成立了区块链人才培养基地，让学生学以致用。链人国际是区块链招聘就业服务第一品牌，拥有全国90%以上的市场份额，75%的服务用户是区块链各细分领域龙头企业。智谷星图与链人国际同为区块链国家职业技能标准编制单位，熟知岗位技能要求。我校通过结合上述企业优质资源联合政府、产业园、企业，举办人才双选会、交流会及校招等人才输送活动，为多家龙头企业输送高校实习生。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了留住更多优秀人才留赣发展，服务本地经济，我校联合合作企业组建&ldquo;区块链技术应用实训基地&rdquo;，利用先锋软件及合作企业的市场拓展能力，承接政府及企业项目，形成区块链技术研究、应用开发、项目运维与测试等多重能力的外包服务基地，为更多学生提供高质量就业机会。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校联合智谷星图打造了&ldquo;双师型&rdquo;师资队伍。此外，学校还依托中国区块链智库的院士、教授、企业高管等优质师资，邀请腾讯、微众银行、蚂蚁、万向等区块链行业领军企业的一线工程师、实战专家，开展丰富且体系化的教学。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">今年上半年，我校举行了&ldquo;全国区块链师资能力提升培训班&rdquo;，来自全国各地9所高校的区块链技术、软件工程技术、信息安全与管理等相关专业带头人和分管教学工作的校(院)长、主任等人员共计51人参加。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A51%3A18blob?Expires=1953262278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QGKMxpH93%2BV5cG7O4zryHMSN3OA%3D" alt="" width="650" height="356" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图3&nbsp;学校举行&ldquo;全国区块链师资能力提升培训班&rdquo;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><a style="box-sizing: border-box; color: #337ab7; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;" name="_Hlk84857970"></a>三、平台共搭</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校已经联合智谷星图共同研发了区块链教学实训、实战、模考三大平台，覆盖区块链产业人才培养的全流程。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（一）教学实训平台。我校联合智谷星图研发五大实训产品：区块链技术应用（64课时）、智能合约技术与开发（64课时）、DApp应用开发（64课时）、联盟链开发（64课时）、区块链系统开发（64课时），上述实训课程对应区块链运维工程师、智能合约开发工程师、联盟链开发工程师等岗位核心技能要求。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（二）区块链实战平台。我校联合智谷星图研发的区块链实战平台是基于区块链真实环境所打造的区块链技术与应用开发实训平台，提供一站式开发工具。该平台接入的真实区块链系统包括：以太坊、智谷CTIS教育区块链、腾讯TBaaS、微众银行FISCO BCOS、Hyperledger、蚂蚁链、百度超级链、JD Chain、趣链飞洛平台等，不断拓展新环境，融入新技术。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（三）模拟考试系统。我校联合智谷星图研发的考试系统支持选择、判断、填空、编程、实操等各类题型，逐步实现教考分离。该系统已被工信部采用，作为区块链岗位能力提升培训及考试系统。同时，此考试系统录入相关题库后，也可用于其他社会培训及证书的考试，复用价值高。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">四、社会服务</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2020年9月，学校与先锋软件股份有限公司、数字江西科技有限公司展开校企合作，成立蚂蚁链（江西）研究院，依托蚂蚁链技术在吉安市打造了区块链农产品溯源项目。从产品品类到企业资质，从种植环境条件到人员管控，从清洗筛选到分拣包装，从销售到运输建立和完善溯源管理体系的各个环节，我校师生将所有数据载入到区块链中，打通农业生产、交易和流通等各个关键环节要素。通过区块链、大数据技术对载入先锋可信区块链中的基础数据进行整合运算处理，形成有价值、可用、不可篡改、透明公开的数据，给上层应用提供数据服务。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">井冈蜜柚通过科技力量不断提升产品附加值，在解决丰产又丰收的问题上探索出了新的路径，通过优质优价的定位，实现了生产优化升级，不但卖出了规模，也卖出了好价钱，使井冈蜜柚品牌变&ldquo;名牌&rdquo;，蜜柚农产品的商品变&ldquo;珍品&rdquo;，井冈蜜柚的质量变&ldquo;品质&rdquo;，打造数字化农业示范样板。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-11-26%2012%3A51%3A51undefined?Expires=1953262311&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=2Y7ZlbRrulswfbAXbe0Cos0AONE%3D" alt="" width="650" height="455" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 10pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">图4&nbsp;吉安井冈蜜柚溯源项目</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em; text-align: center;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在1月29日的江西省两会会场上，&ldquo;一个上区块链的柚子&rdquo;脱颖而出成为了两会代表的热议话题，科技创新助力乡村振兴，第一个上蚂蚁链的井冈蜜柚成为了吉安农业产业</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">新的示范标准。&ldquo;区块链+井冈蜜柚&rdquo;在农业领域的先行先试也为下一步构建赋能实体经济、技术创新、管理创新、模式创新协同推进的区块链发展格局打下了良好的基础。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">五、基地共建</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我校与鸾翔创杰母公司之一的链人国际咨询（北京）有限责任公司（以下简称：链人国际）联合成立了区块链人才培养基地，让学生学以致用。链人国际是区块链招聘就业服务第一品牌，拥有全国90%以上的市场份额，75%的服务用户是区块链各细分领域龙头企业。智谷星图与链人国际同为区块链国家职业技能标准编制单位，熟知岗位技能要求。我校通过结合上述企业优质资源联合政府、产业园、企业，举办人才双选会、交流会及校招等人才输送活动，为多家龙头企业输送高校实习生。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了留住更多优秀人才留赣发展，服务本地经济，我校联合合作企业组建&ldquo;区块链技术应用实训基地&rdquo;，利用先锋软件及合作企业的市场拓展能力，承接政府及企业项目，形成区块链技术研究、应用开发、项目运维与测试等多重能力的外包服务基地，为更多学生提供高质量就业机会。</span></p>');
INSERT INTO content VALUES (393, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">11月20日，华为中国大学生ICT大赛2021实践赛江西省决赛圆满落幕。江西软件职业技术大学斩获了本科网络赛道的特等奖、一等奖、二等奖、三等奖及优秀奖。葛伟、姜瑞荣两位老师获得本科网络赛道最佳指导老师奖。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-12-01%2011%3A20%3A571.jpg?Expires=1953688857&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=xfpx4mu8qkjs4Hby%2BdqOH8vBp5c%3D" width="650" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-12-01%2011%3A22%3A01blob?Expires=1953688921&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=ZpPhihbwnRfom1FVFh%2FgiyR8vBk%3D" alt="" width="650" height="251" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-12-01%2011%3A22%3A32blob?Expires=1953688952&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=McR6HJ6%2F3jSa1z22totAyicMXXY%3D" alt="" width="650" height="254" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">今年3月22日，该赛事入选了2020&nbsp;全国普通高校大学生竞赛排行榜，这代表华为ICT大赛成为了中国高等教育学会认可的含金量高、参赛价值大的国家级竞赛项目之一。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">华为ICT大赛从9月起在江西省各高校开花结果，本次江西省省赛共有全省高校1300余名学生参加，我校领导高度重视此次竞赛，统筹安排，赛前，面对疫情防控常态化形势，采取线上线下协同宣传、辅导、答疑多种措施并行，鼓励同学们积极参与。备赛期间，指导老师精心辅导，认真组织训练；参赛选手刻苦努力备战，不断提高专业技术水平和能力，经过激烈的初赛、决赛的比拼，最终在省赛决赛中取得佳绩。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">下一阶段，华为中国大学生ICT大赛2021实践赛全国赛将在12月份开赛，学院荣获特等奖的3名同学将代表江西省和其他省的晋级选手同台竞技，期待他们激流勇进，再创佳绩!</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">此次大赛的比赛成绩深刻体现了&ldquo;以赛促教、以赛促学、以赛促改、以赛促建&rdquo;的办学理念，让学生的技术技能与企业应用需求融合，进一步地推动了我院相关专业与企业深层次的对接。</span></p>');
INSERT INTO content VALUES (394, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">根据国务院颁布的《国家职业教育改革实施方案》和《关于在职业院校实施&ldquo;学历证书+若干职业技能等级证书&rdquo;制度试点方案》等文件精神，进一步办好新时代职业教育，全面贯彻党的教育方针，把职业教育摆在教育改革创新和经济社会发展中更加突出位置，保证职业教育改革发展正确方向，按照教育厅&ldquo;1+X&rdquo;工作推进要求，江西软件职业技术大学于12月11日顺利开展&ldquo;1+X&rdquo;工业机器人操作与运维试点证书（初级）和&ldquo;1+X&rdquo;数字创意建模试点证书（中级）两场考试。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-12-13%2011%3A32%3A56blob?Expires=1954726376&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=XsM9xhkHFGGe1LQW8bI%2BhW5j1R0%3D" alt="" width="650" height="488" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在职业培训中心的指导和协助下，智能科技学院和VR与艺术学院积极的开展&ldquo;1+X&rdquo;试点证书的考核工作，在考前均进行了周密部署，在对申请参加本次考证的学生进行了理论及实操考试培训之后，精心安排考试工作。我校采用标准化考试方式，考试严格按照培训评价组织机构的整体部署要求执行，实行统一流程、统一规范、统一标准的总体要求，本次考试将对考生的理论知识、操作能力等方面进行综合考评。考试过程组织有序、保障到位，考试系统稳定，考点秩序良好，工作人员职责明确，监考教师坚守岗位，顺利完成此次考试工作。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-12-13%2011%3A33%3A58undefined?Expires=1954726438&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=hAKhYOMP5mBVbW29Re%2BE9OKRWnY%3D" alt="" width="650" height="488" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-align: justify; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">本次&ldquo;1+X&rdquo;职业技能等级证书考核认证，是我校把证书标准内容与专业课有机融入，优化课程实施体系，强化实践技能培养的一次体现。通过考核认证促进了我校对&ldquo;1+X&rdquo;证书制度试点与专业建设、课程建设等的紧密结合,推进了&ldquo;1&rdquo;和&ldquo;X&rdquo;的有机衔接，提升了教学质量，提高了人才培养质量，拓展了学生就业本领。本次考试的顺利结束，为后续&ldquo;1+X&rdquo;试点证书工作的全面实施做好了铺垫，同时也拓宽了学生的择业方向和渠道。</span></p>');
INSERT INTO content VALUES (395, '<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">为了推进我校创新创业教育改革，提升高校教师创新创业教育课程教学的能力，打造一支既有理论功底又具有实操能力的高素质创新创业教师团队，</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2022年1月6日-9日</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">为期三天的</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">创新创业师资培训</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">在</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">创客大厦路演大厅举行，</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">来自各</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">学院的</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">学员体验了一场</span>&ldquo;超越自己，追求卓越&rdquo;的</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">师资</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">培训。</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">开班仪式上，副校长张永革作了动员讲话，并对参加此次培训的学员提出了要求。</span></span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><img src="file:///C:\Users\ADMINI~1\AppData\Local\Temp\ksohtml25872\wps1.jpg" width="496" height="265" /><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">本期</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">创新创业师资</span></span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">培训目的是</span></span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">：</span></span><span style="font-family: 仿宋; font-size: 14pt;">1、掌握</span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">创新创业课程的教学目标、教学原则、教学方法和教学组织体系，能开展课堂教学；</span>2、能以全新理念和方法开展创新创业教育，深入开展大学生创新创业教育教学和指导工作；3、掌握创新创业课程教学和管理技能</span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">。</span></span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><img src="file:///C:\Users\ADMINI~1\AppData\Local\Temp\ksohtml25872\wps2.jpg" width="493" height="370" /><span style="font-family: 仿宋; font-size: 14pt;">&nbsp;</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">担任第二期创新创业</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">资培训的</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">授课讲师分别是</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">：</span></span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">石科明</span></span><span style="font-family: 仿宋; font-size: 14pt;">,</span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">国际劳工组织认证的国际创业培训师</span></span><span style="font-family: 仿宋; font-size: 14pt;">,</span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">全国创业工作指导委员会专家顾问团副主任</span></span><span style="font-family: 仿宋; font-size: 14pt;">,</span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">人社部国家级</span>SYB、lYB创业培训师、EYB创业培训讲师； 2017年全国首届创业培训讲师大赛总决赛的评委。黃虹辉，博士、国家级创业培训师、全国创业讲师大赛第二名、湖南省创新创业两团专家。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">三天培训</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">课程安排紧凑，内容丰富。</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">培训</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">讲师运用</span></span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">体验式、项目参与式等先进教学方法对</span></span><span style="font-family: 仿宋; font-size: 14pt;"><span style="font-family: 仿宋;">开展创新创业教育</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">的重大意义、成人学习原理、创业十步、创业培训技巧、创业训练（企业经营沙盘演练）、课程设计、监督与评估、创新创业示范课（应用头脑风暴法产生企业想法</span> <span style="font-family: 仿宋;">启动资金、损益表、现金流量表）等模块进行了深入浅出的讲解。</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">三天培训</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">，</span></span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">学员们收获满满，整个培训课程气氛热烈、思维火花不断迸发。参训教师站在理论的高度进行了学习和感悟，并观摩和体验到了如何去灵活驾驭教学方法和技巧。对高校创新创业教育体系、大学生创新创业实践指导及教学艺术有了更为系统和全面的认识、开阔了视野，提升了我校教师双创教育的教学能力，有利于推动我校打造适合应用型转型发展需求的</span>&ldquo;双师双能型&rdquo;师资队伍和创新创业师资队伍。培训结束后，大家高度肯定了培训效果，纷纷表示将把所学所得与课堂实际相结合，不断提高自身的教学水平。</span></p>');
INSERT INTO content VALUES (396, '<h4 style="text-align: center;" align="center">&nbsp;</h4>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">为了推进我校创新创业教育改革，提升高校教师创新创业教育课程教学的能力，打造一支既有理论功底又具有实操能力的高素质创新创业教师团队，</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2022年1月6日-9日</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">为期三天的</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">创新创业师资培训</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">在</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">创客大厦路演大厅举行，</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">来自各</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">学院的</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">学员体验了一场</span>&ldquo;超越自己，追求卓越&rdquo;的</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">师资</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">培训。</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">开班仪式上，副校长张永革作了动员讲话，并对参加此次培训的学员提出了要求。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-01-12%2016%3A26%3A18%E5%9B%BE%E7%89%874.png?Expires=1957335978&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=FgN3vA4nzK2qAupmlaULAJ26xdI%3D" alt="" width="594" height="401" /></span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="mso-spacerun: 'yes'; font-family: 仿宋; mso-ansi-font-weight: normal; mso-bidi-font-weight: bold; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">本期</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">创新创业师资</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; mso-ansi-font-weight: normal; mso-bidi-font-weight: bold; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">培训目的是</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; mso-ansi-font-weight: normal; mso-bidi-font-weight: bold; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; mso-ansi-font-weight: normal; mso-bidi-font-weight: bold; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">1、掌握</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;"><span style="font-family: 仿宋;">创新创业课程的教学目标、教学原则、教学方法和教学组织体系，能开展课堂教学；</span>2、能以全新理念和方法开展创新创业教育，深入开展大学生创新创业教育教学和指导工作；3、掌握创新创业课程教学和管理技能</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-01-12%2016%3A17%3A49%E5%9B%BE%E7%89%872.png?Expires=1957335469&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Y5HJtGjcM8nkozEzbGr5eZPtzgc%3D" alt="" width="580" height="392" />&nbsp;</span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">担任第二期创新创业</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">资培训的</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">授课讲师分别是</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">石科明</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">,</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">国际劳工组织认证的国际创业培训师</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">,</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">全国创业工作指导委员会专家顾问团副主任</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">,</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;"><span style="font-family: 仿宋;">人社部国家级</span>SYB、lYB创业培训师、EYB创业培训讲师； 2017年全国首届创业培训讲师大赛总决赛的评委。黃虹辉，博士、国家级创业培训师、全国创业讲师大赛第二名、湖南省创新创业两团专家。</span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">三天培训</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">课程安排紧凑，内容丰富。</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">培训</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">讲师运用</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">体验式、项目参与式等先进教学方法对</span><span style="mso-spacerun: 'yes'; font-family: 仿宋; font-size: 14.0000pt; mso-font-kerning: 0.0000pt;">开展创新创业教育</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">的重大意义、成人学习原理、创业十步、创业培训技巧、创业训练（企业经营沙盘演练）、课程设计、监督与评估、创新创业示范课（应用头脑风暴法产生企业想法</span> 启动资金、损益表、现金流量表）等模块进行了深入浅出的讲解。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-01-12%2016%3A30%3A22b48a88df0f0e39b57b05eaef979e38a.jpg?Expires=1957336222&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9xk4Rt56Znn7al5dGlFOqJ3V8Sw%3D" alt="" width="564" height="381" /></span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">三天培训</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">，</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">学员们收获满满，整个培训课程气氛热烈、思维火花不断迸发。参训教师站在理论的高度进行了学习和感悟，并观摩和体验到了如何去灵活驾驭教学方法和技巧。对高校创新创业教育体系、大学生创新创业实践指导及教学艺术有了更为系统和全面的认识、开阔了视野，提升了我校教师双创教育的教学能力，有利于推动我校打造适合应用型转型发展需求的</span>&ldquo;双师双能型&rdquo;师资队伍和创新创业师资队伍。培训结束后，大家高度肯定了培训效果，纷纷表示将把所学所得与课堂实际相结合，不断提高自身的教学水平。</span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; text-indent: 24.0000pt; mso-char-indent-count: 2.0000; text-autospace: ideograph-numeric; mso-pagination: widow-orphan; line-height: 27.0000pt; background: #ffffff; margin: 5.0000pt 0.0000pt 5.0000pt 0.0000pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 12pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="p" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; text-indent: 0.0000pt; mso-pagination: widow-orphan; line-height: 27.0000pt; background: #ffffff; margin: 5.0000pt 0.0000pt 5.0000pt 0.0000pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 12pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>');
INSERT INTO content VALUES (397, '<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">月</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">17</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">日下午，创新创业学院在创客大厦召开本学期第一次教研会议，本学期担任创新创业课程的全体教师参加了会议。会议由创新创业院长倪锋教授主持。</span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">本次教研活动围绕创新创业课程为什么学、学什么、怎么学为主线</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">等</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">三个</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">方面进行了深入研讨。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-02-20%2009%3A50%3A34%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220220094928.jpg?Expires=1960681834&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=GBsVl3iDB37vaeCQERl0FyYJIFU%3D" alt="" width="905" height="407" /></span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">首先倪院长就</span>&ldquo;为什么学&rdquo;这个问题解答了老师的疑问。目前社会需求，时代需求和教改需求，三个需求要求创新创业课程成为职业本科生的一门必修基础课程。接着倪院长讲解了创新创业课程&ldquo;学什么&rdquo;，创新创业课程重点培养学生的创业精神、创业思维、创业方法。针对&ldquo;怎么学&rdquo;倪院长提出采用混合式教学--自主学习、基于问题式学习、实践中学习三种教学方法来提高课堂效率。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 21pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;<img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-02-20%2009%3A51%3A21%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220220094948.jpg?Expires=1960681881&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=B9Qg5Mn9oDO1eS2EF8dLVbK70OI%3D" alt="" width="908" height="408" /></span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">最后会议</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">布置了本学期的教学任务，提出了教学要求，</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">并</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">安排</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">了</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">本门课程教学质量管理的工作。强调了每位任课老师上课时都要备好六大件：</span>&ldquo;教学大纲、教学进度表、教材、教案、课件、点名册。&rdquo;</span></p>
<p class="p" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: justify; text-justify: inter-ideograph; vertical-align: baseline; line-height: 24.0000pt; margin: 0.0000pt 0.7500pt 0.0000pt 0.7500pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">通过集体备课，教师们相互学习和借鉴，不仅能提升教学水平和教学质量，而且为教学创新提供交流探讨的平台，教师们深刻认识到自己担任这门</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">创新创业课程教学</span><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">任务的责任重大、意义深远。</span></p>');
INSERT INTO content VALUES (398, '<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2022年1月26日，《中国元宇宙白皮书》发布会在北京正式举行。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">本次《中国元宇宙白皮书》发布为保障中国元宇宙行业的健康发展、引领中国元宇宙科技创新、促进中国元宇宙的技术进步、提高中国元宇宙的科普水平，由北京信息产业协会、中关村数字媒体产业联盟、中国科技新闻学会大数据与科技传播专委会、中国市场信息调查业协会区块链委员会、北信产发（北京）科技产业发展有限公司、北京星汉云图文化科技有限公司的</span>130多位院士、学者、专家、企业家、投资人、艺术家等，历时2个多月，最终形成了逾50万字的《中国元宇宙白皮书》。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">白皮书分为</span>9篇26章536页，专家们分别从元宇宙的缘起、现状、技术、产业、法律与监管、伦理与风险、经济、人才和畅想等角度进行了深入的思考并分享了各自观点，是目前国内元宇宙领域方向明确、观点权威、视角完整、思考深入的著作。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">中国科技新闻学会大数据与科技传播专业委员会副会长兼秘书长石峰、中国大数据网执行总编兼</span>CEO刘冬冬、北京信息产业协会常务副理事长邝世诚、中关村数字媒体产业联盟执行主席王斌分别代表白皮书编写组织方出席了发布会并作致辞。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">来自产业界的专家赵天齐、孟虹、王运嘉分别就数字人应用、艺术元宇宙和元宇宙法律做了分享。</span></span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">来自国科创新研究院的首席科学家龚才春博士详细介绍了白皮书的整体结构、主要内容以及编写的过程，并介绍了编委专家们的组成情况。白皮书</span>130余位编委专家来自各行各业，基本上处于目前国内较前沿的元宇宙研究和产业应用的第一线，凝聚了广泛的智慧和思想。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">龚才春博士认为，互联网陷入了内卷化的负向循环，两年多的新冠疫情又培养了大家的线上习惯，人工智能、大数据、区块链、物联网、数字孪生、虚拟现实等技术已经达到一定奇点，这些都促使了元宇宙的横空出世。元宇宙是人们对于互联网体验要求进一步提升的必然产物，是信息化、数字化的进一步升华。龚才春博士总结了元宇宙的分层技术架构，包括硬件技术层、接入技术层、基础软件层、分布式技术层、数字创作层和应用技术层。《中国元宇宙白皮书》给出了各产业元宇宙化的实施探索，也总结元宇宙未来的经济运行规律，给出了未来元宇宙可能面临的伦理和道德风险，提出元宇宙最缺的是人才的观点。最后，众多专家也在《白皮书》畅想了元宇宙美好的未来。</span></span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">《中国元宇宙白皮书》的发布，将向社会大众普及元宇宙正确概念和应用场景，促进全社会对元宇宙技术、未来发展趋势、对人们工作生活可预见的改变形成正确的认知，将对元宇宙相关产业持续健康发展发挥重要促进作用，本次发布的白皮书得到了国家相关部委领导的大力支持和肯定，同时发布会上邀请多家中央媒体参会，共同见证《中国元宇宙白皮书》的发布。</span></span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">龚才春博士还在发布会宣布了北京信息产业协会元宇宙专家委员会（筹）的下一步工作计划。在农历虎年春节后，元宇宙专家委员会将择时召开成立大会，每年都将出版《中国元宇宙白皮书》。在</span>2022年将全力打造优质、精品、权威的《中国元宇宙产业白皮书》、《中国元宇宙技术白皮书》、《中国元宇宙人才发展白皮书》、《中国元宇宙未来白皮书》、《中国元宇宙法律监管白皮书》、《中国元宇宙伦理道德白皮书》、《中国元宇宙经济白皮书》、《中国元宇宙未来白皮书》等。北京信息产业协会元宇宙专家委员会2022年还将起草元宇宙相关标准2-3项，承办&ldquo;首届中国元宇宙大会&rdquo;，推动中国元宇宙研究院的成立，推动各高校的元宇宙产业学院的建设，打造中国元宇宙之都，推动一大批元宇宙产业园的落地，推动我们元宇宙产业的快速健康发展。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">本次发布会现场邀请北京信息产业协会常务副理事长邝世诚、北京信息产业协会副秘书长邢军、中关村数字媒体产业联盟执行主席王斌、中关村大数据产业联盟副秘书长颜阳、中国科技新闻学会大数据与科技传播专委会秘书长石峰、住建部科技与产业化发展中心处长曹吉昌、中国通信企业协会无线接入系统专业委员会常务副秘书长郑甲兔、北京邮电大学国际学院院长郭莉、中央美术学院网络信息中心主任孟虹、中国传媒大学协同创新中心副主任曹三省、中国传媒大学互联网信息研究院创新创业导师张胜杰、中国大数据网执行总编兼</span> CEO刘冬冬、北京邮电大学副教授王冬宇、开普云信息科技股份有限公司董事长汪敏、企业网D1net CEO范脡、中关村科学城城市大脑股份有限公司技术总监梅一多、北京枫玉科技有限公司董事长王运嘉、北京星汉云图文化科技有限公司创始人及IIDR数字视觉研究实验室主任何伟、色空艺术创始人沈普芳、新华网物联网技术总监葛振斌、翼享（北京）科技发展有限公司董事长陈铸、企业数字化转型培训百人峰会创始人马兆林、中民协元宇宙工委副秘书长高泽龙、北京聚力维度科技有限公司创始人兼CTO赵天齐、建信金科极速工场运营总监徐红熙、中国环境保护产业协会科技部主任刘媛、中关村科学城城市大脑股份有限公司合作总监田振、中国信达资产管理股份有限公司高级副经理卢洪波、国科创新研究院首席科学家龚才春等领导、专家、学者参加，本次发布会同时通过腾讯会议等平台同步直播。</span></p>
<p class="p" style="margin: 0pt 0.75pt; text-indent: 28pt; padding: 0pt; text-align: justify; vertical-align: baseline; line-height: 24pt;" align="justify"><span style="font-family: 仿宋; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 仿宋;">《中国元宇宙白皮书》的发布，将向社会大众普及元宇宙概念和应用场景，促进社会对元宇宙技术、未来发展趋势、对人们工作生活可预见的改变形成正确的认知，将对元宇宙相关产业持续健康发展发挥积极作用。</span></span></p>');
INSERT INTO content VALUES (399, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp; 2022年1月15日&nbsp; ，冬日艳阳高照，很是暖和。在江西软件职业技术大学区块链学院阶梯教室里，来自先锋软件集团和学校的全体中层及以上干部，正在聚精会神地聆听着省人大代表、先锋软件集团董事长、学校创始人陈苏畅谈以&ldquo;元宇宙 新未来&rdquo;为主题的报告。&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-01-17%2009%3A29%3A28%E5%9B%BE%E7%89%871.png?Expires=1957742968&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=xUNsVDuhigKtTDkru0edO%2BFGmk0%3D" width="600" height="350" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp; &nbsp; &nbsp; &nbsp; 陈苏董事长在专题报告上，用通俗易懂的案例和深入浅出的语言，阐述了元宇宙是什么，元宇宙的过去、现在和未来，分析了先锋软件集团和学校的优势，提出了怎样抓住机遇、怎么干等。学校副校长梅龙，先锋软件集团技术总监朱军，学校区块链学院副院长江海分别在报告会上作了主旨发言。最后，学校董事长陈方平作了精彩总结。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp; &nbsp; &nbsp; &nbsp; 元宇宙需要复杂的底层技术逻辑支撑。其中，区块链、人工智能、数字孪生、人机交互、物联网等面向数据的新一代信息技术的演进并非偶然，而是从Web2.0向Web3.0演进的技术准备。因此，从技术上来看，元宇宙是基于Web3.0技术体系和运作机制支撑下的可信数字化价值交互网络，是以区块链为核心的Web3.0数字新生态。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp; &nbsp; &nbsp; &nbsp; 先锋软件集团和学校自2015年开始，在区块链技术领域开始了战略性研究，聚焦于基础研究、区块链研发与应用、人才培养和产业推进等，成立了全球的首家区块链学院，组建了区块链应用技术研发中心、蚂蚁链（江西）研究院等，建设了区块链国际交流中心、区块链专家小村等，推动成立了江西省区块链学会、江西省区块链行业协会、江西省区块链专家委员会等。学校VR与艺术学院在2016年就设置了虚拟现实技术及相关专业，2021年申报的&ldquo;职业本科虚拟仿真示范实训基地&rdquo;项目被确定为国家职业教育示范性虚拟仿真实训基地培育项目。先锋软件集团和学校是软件企业办软件大学的命运共同体，因此，在这样坚实的技术基础上，更要抓住机遇，集中优势兵力，在&ldquo;元宇宙&rdquo;这条赛道上，加速布局。</span></p>');
INSERT INTO content VALUES (400, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">2月9日下午，先锋软件集团、江西软件职业技术大学召开专题会议，认真学习省委省政府双&ldquo;一号工程&rdquo;精神，并研究贯彻落实措施。省大人代表、先锋软件集团董事长、学校创始人陈苏主持会议，集团、学校中层及以上干部参加学习会。</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">会上，大家观看了&ldquo;全省深化发展和改革双&ldquo;一号工程&rdquo;推进大会&rdquo;专题新闻，学习了有关文件精神，分析了行业形势等。省委、省政府在春节上班的第一天召开全省深化发展和改革双&ldquo;一号工程&rdquo;推进大会，大力推动实施数字经济做优做强&ldquo;一号发展工程&rdquo;、营商环境优化升级&ldquo;一号改革工程&rdquo;，研究部署全面深化改革攻坚行动,意义非同寻常。</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">集团和学校都要以此为契机，在夯实已有区块链技术优势的同时，结合学校在区块链、软件、VR等方面的优势和特色，抓住机遇，集中优势兵力，加速布局&ldquo;元宇宙&rdquo;赛道。要继续坚持校企融合、产学互动的培养模式，探索更多&ldquo;高层次&rdquo;技术技能人才培养的产教融合新途径，持续打造软件、区块链乃至元宇宙人才高地。</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">元宇宙是基于Web3.0技术体系和运作机制支撑下的可信数字化价值交互网络，是以区块链为核心的Web3.0数字新生态。先锋软件集团和学校自2015年开始，在区块链技术领域开始了战略性研究，聚焦于基础研究、区块链研发与应用、人才培养和产业推进等，成立了全球的首家区块链学院，组建了区块链应用技术研发中心、蚂蚁链（江西）研究院等，建设了区块链国际交流中心、区块链专家小村等，推动成立了江西省区块链学会、江西省区块链行业协会、江西省区块链专家委员会等。这坚实的技术支持，为集团、学校布局&ldquo;元宇宙&rdquo;赛道夯实了基础。</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-02-10%2020%3A01%3A361.jpg?Expires=1959854496&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HArP1c%2FPzAj4p35IpJlZQn%2F%2FPl8%3D" width="650" height="450" /></p>');
INSERT INTO content VALUES (401, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-indent: 2em;">&nbsp;2月18日，井冈山市政府与先锋软件、江西软件职业技术大学签订战略合作框架协议，三方携手共建井冈山先锋数字经济产业园和江西软件职业技术大学新校区。政校企深度融合，聚力开启数字经济新篇章。同时，这是先锋软件公司、江西软件大学依托优势学科，加速区块链、元宇宙等赛道布局的新举措，也是探索用数字经济改变革命老区经济社会发展的一种新尝试。</span></p>
<section class="_135editor" style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #333333; background-color: #ffffff;" data-role="paragraph">
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px;"><video controls="controls" width="988" height="494">
<source src="E:\2022-02-20 10_02_0912.mp4" type="video/mp4" /></video> &nbsp;</p>
</section>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp;<span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-indent: 2em;">此次签约意义非同寻常，是积极落实响应江西数字经济做优做强&ldquo;一号发展工程&rdquo;、营商环境优化升级&ldquo;一号改革工程&rdquo;，加快推进井冈山数字经济建设，促进井冈山的经济和社会发展的有力举措。新建设的井冈山先锋数字经济产业园和江西软件大学新校区将目光精准聚焦人才培养、数字经济与智能化时代产业发展，打造&ldquo;数字工匠&rdquo;高地。&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); width: 998px; display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-02-19%2011%3A57%3A1111.jpg?Expires=1960603031&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=XApntkthp4r2s%2FMvOdogHOq6pAI%3D" width="650" height="419" />&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">&nbsp; &nbsp; &nbsp;</span></span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-indent: 2em;">江西软件大学新校区将包含区块链、软件工程、网络工程、信息技术、新媒体、VR、导航工程、智能科技等专业，努力探索培养数字经济高层次技术技能型人才。井冈山先锋数字经济产业园将实施区块链&ldquo;十个一工程&rdquo;，涵盖区块链应用技术研究院的建设、国家级区块链研发平台或机构的打造、区块链和数字经济应用示范工程、区块链和数字经济创新项目等。&ldquo;十个一工程&rdquo;的实施将争取把井冈山打造成为国内领先的区块链产业基地。江西软件大学新校区和井冈山先锋数字经济产业园占地面积1000亩，建筑面积70万平方米，总投资30亿元，建设分三个周期完成。2025年项目全面完成后，可容纳4万余软件工程师和学生，为软件、互联网企业提供大量的高层次技术技能型人才，将吸引大批软件、互联网企业及其他相关机构和研发中心等入驻井冈山，为井冈山数字经济的发展提供强有力的技术和人才支撑。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); width: 998px; display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-02-19%2011%3A58%3A542.jpg?Expires=1960603134&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=dqiVYSkTjZnJkAWMpMfQ8Bg7RQY%3D" width="650" height="439" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp; &nbsp; &nbsp;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp;&nbsp; 软件企业创办软件大学，形成了命运共同体。具有近20年办学历史的江西软件职业技术大学，是全国首批15所开展本科层次试点高校。自2015年开始，先锋软件认为区块链是新一代互联网核心的底层技术，成立了全球的首家区块链学院，组建了区块链应用技术研发中心、蚂蚁链（江西）研究院等，建设了区块链国际交流中心、区块链专家小村等，推动成立了江西省区块链学会、江西省区块链行业协会、江西省区块链专家委员会等；学校历来重视政校企深度融合，先后与蚂蚁集团、中国联通、南昌临空经济区等合作，深耕区块链技术，打造区块链人才高地。先锋软件和学校发扬已有的特色和优势，顺应新发展的理念，紧扣江西数字经济实际，在2022年省人大会议期间，陈苏董事长作为吉安代表团的省人大代表，提交了《以区块链技术为突破口，推动江西数字经济创新发展》《超前布局元宇宙新业态，抢占数字经济发展新高地》两个建议，受到了各方关注。江西软件职业技术大学新校区、井冈山先锋数字经济产业园的&ldquo;诞生&rdquo;，将更好地为区块链应用研究、人才培养、产业推进等作贡献，为区域数字经济建设作贡献。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<section style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #333333; background-color: #ffffff;" data-role="outer">
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">附：</span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px 0px 0cm; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 30.8px; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 16pt; font-family: 宋体; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 46.9333px;">井冈山市与先锋软件股份有限公司、江西软件职业技术大学合作建设数字经济产业园与新校区签约仪式</span></span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 30.8px; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 16pt; font-family: 宋体; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 46.9333px;">发言稿</span></span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-align: center;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">（先锋软件集团董事局主席&nbsp;&nbsp;陈苏）</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">尊敬的少玄书记、文江市长，各位领导、各位嘉宾：</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 30pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">上午好！</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">首先，我代表在北京因疫情不能前来签约的江西软件大学名誉校长倪光南院士、李衍达院士、庄力可博士和学术委员会名誉主任郑纬民院士以及先锋软件集团、江西软件大学1.8万名员工和师生向各位领导致以崇高的敬意。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">回想35年前，我作为江西省委讲师团的一名讲师，到井冈山中学支教一年，那段经历至今历历在目。从那时起，我就与井冈山结下了深厚的缘分，对井冈山人民的朴实、勤奋留下了深刻的印象，也深受井冈山精神的鼓舞和影响，因此一直以来对井冈山都有着特别的感情。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">5年前，我在吉安市全票当选为江西省人大代表，继续得以续写与井冈山的缘分。这些年重返井冈山很多次，感觉井冈山有着巨大的变化，日新月异，但也总感觉井冈山的经济发展总欠缺些什么，为中国革命做出巨大牺牲的井冈山人民应该过上更富裕、更幸福的生活。因此我也一直思考，如何能为井冈山、为吉安做一些工作，贡献一份自己的力量。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">5年来，少玄书记一直希望我们来吉安投资发展数字经济，我们也在考虑此事，曾多次组团来考察。随着时代的发展，新一代互联网技术的不断兴起和迅猛发展，带来了数字经济的大发展。我认为这是一个机会，是一个能帮助吉安，帮助井冈山尝试跨越式发展的历史机遇，也是我能身体力行为吉安和井冈山做一些工作的机会。先锋软件集团28年来一直致力软件产业的发展和软件人才的培养，近几年主要致力于区块链技术和产业的发展。我们组建了区块链产业研究院，与国内一些头部企业合作组建了专业从事区块链的科技公司，江西软件职业技术大学也组建了全国乃至全球第一所区块链学院。而今天的互联网技术发展，也已经逐步从2.0时代过渡到3.0时代，互联网3.0的底层技术正是区块链，未来元宇宙的发展，底层技术也是区块链。因此2019年10月，习近平总书记发表重要讲话，要求将区块链作为我国核心技术自主创新的重要突破口。也正是在2019年，先锋开始组建吉安先锋区块链技术有限公司，尝试开展了区块链+井冈蜜柚等区块链在现代农业的探索发展，并协助吉安市政府，出台了《吉安市区块链技术应用和产业发展三年行动计划》。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">正是基于运用区块链等新一代互联网技术来推动数字经济发展的考虑，今天先锋软件集团决定在井冈山投资建设数字经济产业园，帮助井冈山发展数字经济。但经济的发展，人才是首要问题，目前井冈山技术人才也相对缺乏，因此我们又决定将江西软件职业技术大学新校区投资建设在井冈山，希望通过学校的人才培养，能吸引一批国内外软件与互联网企业来井冈山共同发展。我们将全力整合国内外优势资源，尝试共同帮井冈山探索出一条数字经济发展的新路子。未来3-5年，先锋软件集团将在井冈山投资约30亿元，在井冈山先锋数字经济产业园和江西软件职业技术大学井冈山新校区合计建设70万平米，力争使园区从业人数和学校在校生规模合计达到3-4万人，争取使革命老区的井冈山发展成为新时期的数字经济新区。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">原本我们计划用三年的时间完成新校区和产业园一期工程，现在井冈山市委市政府要求7个月完成一期工程，这对我们来说是个巨大的挑战，责任重大，使命艰巨，先锋团队面临着又一次严峻的考验。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在与吉安市和井冈山市的前期交流期间，我们深深的感受到了革命老区年轻一代干部所展现的良好风貌，我们再一次感谢少玄书记、文江市长，同时，感谢今天到场的玉兰书记、大胜部长、海云常委副市长，周密副市长，以及井冈山市正华书记，东升市长的大力支持，我们深深的感受到了，你们用扎实的工作体现了井冈山办事不用求人，井冈山办事依法依规，井冈山办事便捷高效，井冈山办事暖心爽心，在发展数字经济产业方面大胆创新，敢于求变。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">我们坚信，在吉安市委市政府的正确领导下，在井冈山市委市政府的鼎力支持下，在井冈山精神的鞭策鼓励下，先锋团队将不遗余力，扎实做好每一项工作，认真落实每一个项目，争取为井冈山革命老区的建设做出更大的贡献。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; text-indent: 28pt;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">最后，再次诚挚感谢吉安市委、市政府！感谢井冈山市委、市政府！感谢江西省区块链行业协会、江西省区块链学会以及蚂蚁集团、软银中国等各单位的大力支持！也祝愿合作项目能取得圆满成功！谢谢！</span></p>
</section>');
INSERT INTO content VALUES (402, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-indent: 28px; text-align: justify;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; letter-spacing: 0px;">为拓宽广大师生的知识视野，培养学生创新意识，提高学生创业能力。2022年3月8日下午，创新创业学院特邀</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #333333; letter-spacing: 1px;">跨境天使创始人</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; letter-spacing: 0px;">詹朋朋博士作题为《创新创业创造：职场竞争力密钥》的&ldquo;先锋讲堂&rdquo;学术交流会。讲座由创业学院院长倪峰主持，全校师生代表500余人参加讲座。</span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-indent: 28px; text-align: justify;">&nbsp;</p>
<p class="MsoNormal" style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-10%2010%3A23%3A52blob?Expires=1962239032&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QaLKToYruNFpR45cYzgLlPji%2BN0%3D" width="650" height="487" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-align: justify;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; letter-spacing: 0px;">&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 0px 17px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 37px; background: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; letter-spacing: 0px;">詹朋朋博士在讲座中从如何提升我们的职场竞争力、大学生如何在参与创新创业创造活动中取得最大收获、如何通过参与创新创业大赛让自己飞速成长三个主题与同学们分享了相关经验，并重点向大家讲解了商业计划书的写作方法以及创业竞赛中的实战技巧。</span></p>
<p style="box-sizing: border-box; margin: 0px 0px 17px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-indent: 37px; background: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; letter-spacing: 0px;">詹博士从评委角度如何看待高分项目的特点等问题，让所有对创新创业迷惑的同学更加的清楚了方向。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #333333; letter-spacing: 0px;">同时</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; letter-spacing: 0px;">詹博士</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #333333; letter-spacing: 0px;">希望我校大学生从改变自己、关注身边变化开始，积极培养创新思维，实现自身价值。&nbsp;</span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-indent: 28px; text-align: justify;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; letter-spacing: 0px;">整场报告会散发出热情洋溢的气息，讲座结束后，创新创业学院院长倪锋教授对本次活动中同学们的互动热情和创业激情给予了肯定，也对詹朋朋博士来校指导双创工作表示热烈的欢迎与感谢。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-indent: 28px; text-align: justify;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-indent: 28px;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; font-family: 微软雅黑, 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; letter-spacing: 0px;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-10%2010%3A24%3A21undefined?Expires=1962239061&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=3wXW8mOS1e6zF7CEQvsQAtzNUbw%3D" width="650" height="487" /></span></p>');
INSERT INTO content VALUES (403, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">花为媒，春之歌。阳春三月的南昌城，想要寻找一片绝美的赏花地，南昌市第五届郁金香花展是首选。此次花展于三月在南昌梅岭国家森林公园北翼、毗邻赣江新区中医药城的南昌绿谷核心区先锋小镇惊艳亮相。展出的百万株郁金香凝聚了江西软件职业技术大学一万六千余名师生的智慧与汗水；这场有着&ldquo;博爱、高雅、善良&rdquo;寓意的花展以其最为高雅脱俗的姿态，浪漫迎客。<br style="box-sizing: border-box;" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-07%2011%3A33%3A5549b4eb1453961080a167c58bfbb63a7.jpg?Expires=1961984035&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=CGjEXX61yNRCifFOtNWQ6OVFE5M%3D" alt="" width="650" height="450" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">连续成功举办五届</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">精彩纷呈亮点不断</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">走进先锋小镇，六十余品种、百万株郁金香在溪流、山水间竞相开放，带着姹紫嫣红与芳香扑面而来，向人们一展其风姿。紫色神秘高贵，红色典雅大气，粉色娇俏可爱，白色纯洁动人，黄色明媚活泼，每一朵都闪耀着不一样的美，相互映衬，如织锦般绚丽。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-02%2015%3A47%3A492021-06-29%2014_20_001.jpg?Expires=1961567269&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=1jGj27gdnvG94jOnF%2Fz0zp18g%2B0%3D" alt="" width="650" height="450" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">南昌市郁金香花展连续成功举办五届，每届都精彩纷呈亮点不断。首届郁金香花展在瑶湖举行，一展出便惊艳了市民们。此后，郁金香花展从瑶湖&ldquo;移步&rdquo;先锋小镇，由江西软件职业技术大学的师生们精心培育浇灌。第二届郁金香花展展出前夕，连续四个多月的阴雨天气影响了郁金香种植，全校师生克服困难，悉心栽培呵护，让百万株郁金香冲破阴云，为二十八万游客带来绚丽色彩；第三届郁金香花展受到新冠疫情影响，为了让居家办公、足不出户的人们感受到春天的气息，花展开启了直播模式，吸引了一百多万人次&ldquo;云赏花&rdquo;，同时也为伟大的抗疫战士们致敬，为坚强乐观、团结自律的中国人献礼。第四届郁金香花展正值中国共产党建党百年，作为庆祝建党百年系列活动之一，花展精选了众多颜色火红鲜艳的郁金香品种，向伟大的党和祖国告白。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-07%2016%3A01%3A272021-06-29%2014_20_322.1.jpg?Expires=1962000087&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Bv7zm10peUiPUUKeFjD0sj8h7sM%3D" alt="" width="650" height="450" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">如今，第五届郁金香花展也如约而至。江西软件职业技术大学的师生们精心设计，分批次种植花卉，让人们有更长时间享受这片最美、最艳丽的花海。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">师生联袂打造花展景观</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">播撒劳育、美育、德育&ldquo;种子&rdquo;</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了将第五届郁金香花展办好，江西软件职业技术大学全体师生从2021年底便开始前期松土、施肥、浇水、除草、播种，到花展期间所有的维护及志愿服务工作，全部由学校师生承担。在这个过程中，万名师生不仅学到了花卉种植培育知识，同时体会到平凡劳动中的愉悦，把劳动教育和美育、德育的&ldquo;种子&rdquo;在心中深深种下。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在第五届南昌市郁金香花展中，环境设计专业实践教学被赋予了特殊意义。在专家教师工作室的带领下，学生不仅参与学校园林景观设计和教学建筑设计，还设计花卉造型。师生联袂共同打造精美花展花艺景观，给市民们带来享受的视觉盛宴。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">花园式生态文明校园</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">辐射联动周边催热&ldquo;美丽经济&rdquo;</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">先锋小镇与江西软件职业技术大学共同打造了一个花园式生态文明校园，它们将创客农场、生态旅游及花园式生态文明校园等有机融合在了一起。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-02%2015%3A51%3A082021-06-29%2015_49_0023.2.jpg?Expires=1961567468&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=iB8CuGK6YZBWZn00jlmt%2Fm9zyes%3D" alt="" width="650" height="450" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校连续四年承办了南昌市郁金香花展，为南昌带来良好的社会效益和经济效益。通过花展，先锋小镇构建了田园综合体，有机融合创客农场、文化创意、生态旅游、岭南电商村及田园社区，构建生态校园，辐射联动罗亭义坪村是一个自然村、罗亭集镇，实现产业优化、链条延伸，丰富周边居民休闲文化生活的同时，为地方区域经济发展提供了助力，推动环境保护工作。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">绚烂的郁金香、秀美的山村、脱</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">贫致富、生态建设&hellip;&hellip;展现出先锋小镇山水林田湖草的美丽画卷，以及为这幅美丽画卷付出汗水的江软人。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">美景与科技相融</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 17px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">感受全国首个软件职业本科高校蜕变</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">来到先锋小镇赏花，不妨来江西软件职业技术大学看看。区块链专家小村、全球首个区块链学院、国家体育产业示范项目&mdash;&mdash;先锋创客小镇电子竞技基地、VR与艺术学院&hellip;&hellip;在这里，你能感受到前沿高科技的独特魅力，沉浸式体验VR/AR技术的新潮流，聆听区块链、元宇宙等高端讲座。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-07%2015%3A55%3A11f9837bf3c3db57d2b8e493dc78c1413.png?Expires=1961999711&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=80sdysxijk6TJ88JxFTMKiw2Neg%3D" alt="" width="650" height="450" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">美景与科技相融，不仅让游客体验更丰富，也让大家见证学校的实现华丽蜕变。在江西省双&ldquo;一号工程&rdquo;推动数字经济与营商环境深度融合的时代背景下，学校抢抓双&ldquo;一号工程&rdquo;的历史机遇，在现有教育教学资源和科技创新技术的基础上，坚持创业创新、知识管理的校训，深化校企合作，与井冈山市政府、先锋软件集团达成战略合作，共建井冈山先锋数字经济产业园和江西软件职业技术大学新校区，聚力开启数字经济新篇章，向社会交出职业本科教育试点的满意答卷。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: inherit; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-07%2015%3A54%3A40b19fec476b5d8f6482e26715d92914b.png?Expires=1961999680&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=XAfGbItIOcf8T8KBGK%2BkfYVxSuA%3D" alt="" width="650" height="450" /></span></p>');
INSERT INTO content VALUES (404, '<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">近日，清华大学新闻与传播学院新媒体研究中心发布《元宇宙发展研究报告2.0版》。《元宇宙发展研究报告2.0版》从元宇宙概念起源、概念与属性、技术与产业链、场景应用、风险点及治理、热点问题、远未来展望七个方面，梳理了元宇宙的发展历程。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><img class="content-picture" style="border: 0px none; vertical-align: middle; max-width: 100%; margin: 0.6em auto; display: block;" src="https://inews.gtimg.com/newsapp_bt/0/14511138448/1000" /></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">&nbsp;</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">元宇宙产业生态（国外）</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><img class="content-picture" style="border: 0px none; vertical-align: middle; max-width: 100%; margin: 0.6em auto; display: block;" src="https://inews.gtimg.com/newsapp_bt/0/14511138449/1000" /></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">&nbsp;</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">元宇宙产业生态（国内）</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">什么是元宇宙？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">元宇宙是整合多种新技术产生的下一代互联网应用和社会形态，它基于扩展现实技术和数字孪生实现时空拓展性，基于AI和物联网实现虚拟人、自然人和机器人的人机融生性，基于区块链、Web3.0、数字藏品/NFT等实现经济增值性。在社交系统、生产系统、经济系统上虚实共生，每个用户可进行世界编辑、内容生产和数字资产自所有。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">元宇宙是三维化的互联网，通过XR、数字孪生等技术实现。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">三维时空催生虚拟人和实体化机器人，虚拟人和实体化机器人依靠AI引擎实现。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">虚实空间和个体的本体存在创造经济活动，依靠区块链、Web3.0、数字藏品/NFT等技术或机制实现。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">三维化互联网、三维化时空</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">虚拟人、机器人、物联网</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">区块链、Web 3.0、数字藏品/NFT</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">标准的元宇宙构建步骤</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">数字孪生：</span>现实世界完全镜像到虚拟世界中，在虚拟空间内建立包括人、物品、环境等要素在内的拟真的动态孪生体。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">虚拟原生：</span>虚拟世界里面的人或物能够自动生成并运转起来（例如自己的虚拟分身、物品等），不需要借助真实场景来参与。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">虚实共生：</span>现实世界信息与虚拟世界信息融合，且能相互共生。例如在虚拟世界拍的照片能在现实中发朋友圈并打印。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">虚实联动：</span>通过人工智能引擎支撑高仿人机器人和虚拟人，并与现实世界中的自然人进行交互。同时，场景和资产也构成广泛的虚实联动。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">创建元宇宙三原则</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">算力最小原则：在一个业务的诸多实现方案中优先选择计算量最小的方案。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">极限满足原则：一项技术发展到满足人的极限值后，研发动力将急剧下降。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">0BUG被发现原则：尽可能不让元宇宙用户感知到软件bug的存在，否则将大大削弱其在虚拟环境中的沉浸感。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">元宇宙的四大拓展</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">生存空间拓展：</span>元宇宙提供了跨虚实和跨生死的生存空间拓展。人类以前主要生活的空间是现实世界。元宇宙来临后，人类的生存空间拓展至虚拟空间，实现虚实无界和生死无界。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">视角维度拓展：</span>现实世界中，自然人看世界都是第一人称视角（FPV）。在元宇宙中，虚拟人的离身交互赋予了自然人第三人称视角，重构了个体看待周围环境的方式，超脱了自身的视觉生态，从而体验到不同生态位的感受。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">感官体验拓展：</span>现实世界的各种感官体验是综合且混杂的。在元宇宙中，经由媒介环境的构建，个体对移动互联网的视觉和听觉拓展为视觉、听觉、触觉、温度等方方面面感官体验，无限丰富和延伸。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">思想实践拓展：</span>元宇宙之前，探索宇宙是人类的主要目标。元宇宙的出现拓展了人类的思想实践。创建宇宙和探索宇宙变得同等重要，两者是相辅相成的。个体的思想实践也趋向于&ldquo;两栖化&rdquo;。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">元宇宙和六大新经济</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">单身经济：元宇宙提供了更多样化的交友方式和选择，独身群体或成重要消费力量。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">适老经济：2021年两会上，&ldquo;适老化&rdquo;引发热议，&ldquo;老年人数字困境问题&rdquo;被首次写入政府工作报告。元宇宙时代，高仿机器人、虚拟数字人在一定程度上将提升老年人生活品质。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">焦虑经济：元宇宙的个性智能满足，或将降低用户焦虑。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">忙人经济：足不出户即可感知世界，为忙人提供职场与生活便利。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">潮牌经济：潮牌企业加速布局元宇宙，开启虚拟潮牌交易新形态。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">颜值经济：用户可以在元宇宙中定制形象或人设，虚拟人或将实现性别和颜值的平权。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">元宇宙热点七问</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">1.元宇宙是资本泡沫吗？</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">元宇宙领域各产业目前仍处于探索阶段，既需要扶持，也需要监管。概念热度可能被资本助推，但从长远发展来看，互联网符合&ldquo;达维多定律&rdquo;特征，即先进入市场的玩家将抢占超过50%的份额。因此，对该领域加速研究势在必行，如此才能更好的引导产业发展，造福利民。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">2.本土元宇宙能摆脱&ldquo;卡脖子&rdquo;问题吗？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">大国争先搭建元宇宙&ldquo;新基建&rdquo;：美国&mdash;&mdash;以Meta、微软、英伟达等科技企业牵头发布技术蓝图，全面推动元宇宙&ldquo;政治战略&rdquo;。在硬件入口、后期基建、底层架构方面有优势。韩国&mdash;&mdash;科学技术和信息通信部在2021年5月发起成立了&ldquo;元宇宙联盟&rdquo;。偶像经济与虚拟数字人结合，本土产业较成熟。中国&mdash;&mdash;经济产业省发布了《关于虚拟空间行业未来可能性与课题的调查报告》。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">美国公司拥有强大的算力和成熟的基础性工具和技术（例如游戏引擎、VR、AR等）。同时，其全球生态意识、大刀阔斧的蛙跳式突破创新，和实实在在的平台产品推进，值得中国企业学习。我国应该加大核心技术的扶持力度，包括硬件设施基础建设和软件开发环境两个维度，并优先扶持强感官体验、能直接带来生产力效应的行业，如教育、工业、太空探索等领域，实现产业链的健康快速发展。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">3.普通人如何参与元宇宙发展？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">体验：各大互联网公司、媒体、研究机构将逐步建立元宇宙体验点，来访者能够亲身体验虚拟现实设备、驱动数字虚拟人、建立对元宇宙的感性认识。此外，一些知名品牌在虚拟平台打造旗舰店，带来集游戏、创作、定制、消费为一体的虚实联动体验。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">投资：从投资理财的角度，可以在充分认识市场风险的前提下，谨慎购买元宇宙概念股票、基金产品。也可以根据兴趣爱好，在符合法律政策的前提下购买品类丰富的数字藏品/NFT、虚拟资产。当下一些厂商还推出了元宇宙联名商品，引发大众的抢购热潮。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">劳动：每个人都可以创作和出售自己的数字作品，获取收入。部分小众、低成本的文化产品可能迎来广阔市场。未来也会催生出新的职业（如创作虚拟造型的捏脸师、虚拟三维艺术家、虚拟资产顾问等）。全新的工作模式下，生产活动更加灵活高效，可能会产生新的工时制度，缩短工作时间，让普通人得到更大解放。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">4.元宇宙玩家如何实现虚实平衡？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><img class="content-picture" style="border: 0px none; vertical-align: middle; max-width: 100%; margin: 0.6em auto; display: block;" src="https://inews.gtimg.com/newsapp_bt/0/14511138491/1000" /></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">&nbsp;</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">5.未来元宇宙可能有哪些开发热点？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">基础设施：5G/6G网络体系架构、自主芯片设计、云计算+边缘计算、AI赋能中心、工业互联网平台、区块链引擎、游戏引擎。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">内容生态：C端应用：游戏社交领域应用开发，打造全新休闲娱乐模式。B端应用：为科研、工业制造、医疗、教育等领域助力。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">&ldquo;六理&rdquo;框架：数理思维开拓、物理规则制定、地理空间创造、心理状态调节、事理逻辑判断、伦理秩序维护。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">6.元宇宙会导致失业率骤增吗？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">职业是社会生产方式的体现。元宇宙必然会淘汰一批工业社会的旧职业，但也会催生更多更具创造性的职业。元宇宙将会带来新的货币生态，新机制在改变旧有产业时，也会形成新业态。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><img class="content-picture" style="border: 0px none; vertical-align: middle; max-width: 100%; margin: 0.6em auto; display: block;" src="https://inews.gtimg.com/newsapp_bt/0/14511138492/1000" /></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">&nbsp;</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><span style="font-weight: bolder;">7.元宇宙的产品是怎样的？</span></p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;">当前元宇宙产品的设计呈现出趋同的&ldquo;MADE&rdquo;结构，包括形象、体验、开发、交易四个部分。</p>
<p class="one-p" style="margin: 0px 0px 2em; padding: 0px; line-height: 2.2; overflow-wrap: break-word; font-family: 'Microsoft Yahei', Avenir, 'Segoe UI', 'Hiragino Sans GB', STHeiti, 'Microsoft Sans Serif', 'WenQuanYi Micro Hei', sans-serif; font-size: 18px;"><img class="content-picture" style="border: 0px none; vertical-align: middle; max-width: 100%; margin: 0.6em auto; display: block;" src="https://inews.gtimg.com/newsapp_bt/0/14511138493/1000" /></p>');
INSERT INTO content VALUES (405, '<h1 style="margin: 0px; padding: 0px; outline: 0px; font-weight: 400; font-size: 20px; max-width: 100%; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; color: #4b4b4b; font-family: 微软雅黑, Arial, 宋体; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; color: #ff0000; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">教育部2022年工作要点</strong></span></h1>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　2022年是新时代新征程中具有特殊重要意义的一年，我们党将召开二十大。这是我们党在进入全面建设社会主义现代化国家、向第二个百年奋斗目标进军新征程的重要时刻召开的一次十分重要的代表大会。迎接学习贯彻党的二十大，是贯穿今年党和国家全局工作的主线，教育工作要聚焦这条主线，作出实质性的贡献。2022年教育工作的总体要求是：以习近平新时代中国特色社会主义思想为指导，深入学习贯彻党的十九大和十九届历次全会精神，认真贯彻落实习近平总书记关于教育的重要论述，深刻认识&ldquo;两个确立&rdquo;的决定性意义，增强&ldquo;四个意识&rdquo;、坚定&ldquo;四个自信&rdquo;、做到&ldquo;两个维护&rdquo;，弘扬伟大建党精神，坚持稳中求进工作总基调，完整、准确、全面贯彻新发展理念，服务构建新发展格局，坚持和加强党对教育工作的全面领导，全面贯彻党的教育方针，落实立德树人根本任务，着力转变观念、守正创新、攻坚克难、守住底线，加快教育高质量发展，推进教育现代化、建设教育强国、办好人民满意的教育，培养德智体美劳全面发展的社会主义建设者和接班人，以实际行动迎接党的二十大胜利召开。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　<strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">一、坚定不移用习近平新时代中国特色社会主义思想铸魂育人，确保教育领域始终成为坚持党的领导的坚强阵地</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　1.学习宣传阐释党的创新理论。把学习贯彻习近平新时代中国特色社会主义思想作为首要政治任务，深入学习贯彻习近平总书记关于教育的重要论述。全力做好迎接党的二十大胜利召开和学习宣传贯彻，出台《直属机关学习宣传贯彻党的二十大精神工作方案》，开展高校师生迎接、学习、宣传党的二十大专项行动，汇聚形成教育系统广大干部师生喜迎党的二十大浓厚氛围。巩固拓展教育系统党史学习教育成果，推动建立常态化长效化制度机制，深入推进党的历史和创新理论进教材、进课堂、进头脑，实施伟大建党精神研究重大专项，深化&ldquo;四史&rdquo;教育。深化习近平新时代中国特色社会主义思想原创性系统性学理化学科化研究阐释，启动实施面向2035高校哲学社会科学高质量发展行动计划，推动高校加快构建中国特色哲学社会科学，布局设立习近平新时代中国特色社会主义思想研究重大专项、中国特色哲学社会科学研究重大专项，推出一批重大研究成果，推进教育系统习近平新时代中国特色社会主义思想研究中心（院）建设。<span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; box-sizing: border-box !important; overflow-wrap: break-word !important;">　</span></p>
<section style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">2.始终把政治建设摆在首位。把习近平总书记重要指示批示作为政治要件，作为党组会&ldquo;第一议题&rdquo;，部党组加强统筹协调，推进重大决策部署落地。持续开展直属机关&ldquo;让党中央放心、让人民群众满意的模范机关&rdquo;创建，分类指导推进直属机关党建高质量发展。构建高质量高校党建工作体系，会同中央有关部门指导推动落实《中国共产党普通高等学校基层组织工作条例》，健全党委领导下的校长负责制。举办全国高校书记校长提高政治能力专题培训班，实现全国公办本科高校书记校长全覆盖轮训。纵深推进新时代高校党建示范创建和质量创优，实施院（系）党组织书记政治能力提升计划、教师党支部书记&ldquo;双带头人&rdquo;队伍质量攻坚计划、大学生党支部书记骨干培养计划，提升高校基层党组织政治功能。健全中小学校党组织领导的校长负责制，加强党对中小学校的全面领导。调研推动《民办学校党建工作重点任务》贯彻落实，指导各地加快推进民办学校章程建设，推动党建有关要求进章程。进一步提高建议提案办理工作能力和效果。提高离退休干部党建工作标准化规范化水平，组织干部离退休制度建立40周年纪念活动。推进新时代关工委建设。</section>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　3.维护教育系统安全稳定。坚持马克思主义在意识形态领域指导地位，严格落实意识形态工作责任制，加强直属机关和高校意识形态阵地管理，指导高校筑牢&ldquo;三微一端&rdquo;等阵地。强化保密宣传教育。深化巩固校园安全专项整顿成效。优化教育舆情监测、研判、报告、处置等流程机制。从严从紧科学精准做好教育系统新冠肺炎疫情常态化防控，确保师生生命健康。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　4.坚定不移推进全面从严治党。聚焦&ldquo;两个维护&rdquo;强化政治监督，严明政治纪律和政治规矩。持之以恒坚持严的主基调，压实管党治校政治责任。按照&ldquo;当下改、长久立、系统治&rdquo;要求，健全中央巡视整改长效机制，持续巩固深化整改成果。抓好直属机关、直属高校重点领域廉政风险防控，严格规范直属机关&ldquo;三评一赛&rdquo;，清理规范直属单位对外合作，从严管理面向中小学生的全国性竞赛活动。强化内部审计监督，完善审计查出问题整改长效机制。严格监督执纪问责，加强对违纪违法案件的查处和通报曝光力度，强化教育警示作用。完成巡视全覆盖任务，推进巡视巡察上下联动，健全巡视整改促进机制。严格落实中央八项规定及其实施细则精神，一严到底纠治&ldquo;四风&rdquo;，树立新风，推动形成严的氛围，优化政治生态和育人环境。</p>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　5.深入实施&ldquo;十四五&rdquo;教育发展规划。通过编写辅导读本等多种形式做好宣传解读。召开部署工作会议，推动各地将规划落实到本地区教育各领域、各层面、各环节。制定实施分工方案，强化年度工作计划和规划有效衔接。聚焦关键领域薄弱环节，深入实施教育强国推进工程，发挥中央预算内投资导向作用，改善各级各类学校办学条件。建立&ldquo;十四五&rdquo;规划纲要教育领域工程项目台账，逐项细化时间表、路线图，定期跟踪调度。开展规划实施年度监测评估。印发实施《关于构建教育高质量发展体系的指导意见》。重视教育科学研究，加强战略思考和系统谋划，开展有组织的重大教育科研。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　6.落实教育优先发展战略地位。坚持国家财政性教育经费占国内生产总值（GDP）比例&ldquo;不低于4%&rdquo;，保证财政教育支出强度，加快支出进度，确保&ldquo;两个只增不减&rdquo;。加强义务教育教师工资收入保障，确保义务教育教师平均工资收入水平不低于当地公务员平均工资收入水平。坚持优化增效、补短扬长，新增教育投入更多用于薄弱环节，新增教育支出更多用于提高教师待遇。完善普惠性学前教育经费保障机制，出台国家层面学前教育生均公用经费标准，推动地方提高并落实公办园生均财政拨款标准或生均公用经费标准、普惠性民办园生均补助标准，提高幼儿园教师工资收入水平。指导各省（区、市）适时调整非义务教育阶段学费（保教费）、住宿费标准。推动各地严格落实普通高中生均公用经费标准，探索职业教育按专业大类差异化生均拨款制度。完善教育经费统计体系，加强财政教育投入和预算支出进度监测监督。完善教育行业国有资产管理制度，提高资产使用效益。全面加强校办企业国有资产监管。加强精准资助，推进资助育人，全面落实各项学生资助政策。落实过紧日子的要求，严肃财经纪律。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">&nbsp;</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　7.建设高素质专业化干部队伍。强化教育培训和实践锻炼，提高直属系统干部政治能力和专业素养。坚持新时代好干部标准，以正职和优秀年轻干部为重点，把政治标准放在首位，选优配强直属系统领导班子。加大统筹力度，积极推进干部交流，优化干部成长路径。做实做细管理监督，完善考核评价机制，强化关心关爱，激励干部担当作为。落实深化事业单位改革试点任务。深入推进直属高校人事制度改革。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">二、加快完善德智体美劳全面培养的育人体系，促进学生健康成长全面发展</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　8.深入推进&ldquo;双减&rdquo;。继续把&ldquo;双减&rdquo;工作摆在突出位置、重中之重，巩固成果、健全机制、扫除盲点、提升水平、维护稳定、强化督导。完善部际专门协调机制，推动各地健全工作机制。加强党的全面领导，指导培训机构全面贯彻党的教育方针，落实立德树人根本任务。着力巩固学科类培训机构压减成果，在法定节假日、休息日、寒暑假指导各地开展常态巡查、坚决关停。加大对隐形变异培训查处力度，开展专项治理。规范培训收费行为，加强培训预收费监管。推动校外教育培训监管立法，加强执法力量，提升执法能力，抓好执法巡查。针对一些监管盲点，开展系统调研，指导各地规范管理。指导各地对非学科类培训机构，区分体育、文化艺术、科技等类别，抓紧明确主管部门，体现公益属性，实现常态化监管，防止出现新的野蛮生长。指导各地落实高中阶段学科类培训严格参照义务教育阶段执行的政策要求。建立全国校外教育培训专家委员会。组建校外培训社会监督员队伍，拓宽社会监督渠道，形成全社会参与监管并广泛支持校外培训治理的良好氛围。进一步提高学校作业设计水平、课后服务水平和课堂教学水平，健全课后服务经费保障机制，拓宽课后服务资源渠道，开展课后服务精品课程资源推介。利用&ldquo;双减&rdquo;工作监测平台，持续跟踪监测相关指标数据。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　9.全面推动学校思政课建设。推进习近平新时代中国特色社会主义思想进教材进课堂进头脑，发挥思政课铸魂育人主渠道作用。召开&ldquo;大思政课&rdquo;建设推进会，实施&ldquo;大思政课&rdquo;建设方案。重点开好&ldquo;习近平新时代中国特色社会主义思想概论&rdquo;课程，加强以习近平新时代中国特色社会主义思想为核心内容的课程群建设，组织开展习近平新时代中国特色社会主义思想大学习领航计划系列主题活动。设立一批实践教学基地，建设全国高校思政课教研系统，建好高校思政课教学创新中心。研制普通高校本科专业类课程思政教学指南。统筹推进本硕博、大中小学思政课一体化建设，支持建设一批思政课一体化基地，研制关于进一步加强中小学思政课建设的意见。会同中央宣传部召开马克思主义学院建设推进会，推进马克思主义理论学科本硕博一体化人才培养，提升马克思主义学院建设管理水平。实施高校思政课教师能力提升攻坚计划，&ldquo;一校一策&rdquo;推动配齐建强思政课教师队伍，加强研修基地建设，办好&ldquo;周末理论大讲堂&rdquo;、骨干教师研修班，建立健全思政课教师&ldquo;手拉手&rdquo;帮扶机制。分专业大类深入推进职业院校课程思政建设，举办职业学校思想政治教育课程教师教学能力比赛和中职学校班主任能力比赛。继续开展各类示范培训，提高中小学德育队伍专业能力。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　10.加强和改进学校思想政治工作。全面实施时代新人培育工程。深化思想政治工作质量提升工程和&ldquo;三全育人&rdquo;综合改革，健全&ldquo;国家&mdash;省级&mdash;高校&rdquo;三级网络思政体系运行机制。推进职业院校&ldquo;三全育人&rdquo;典型学校建设。推进&ldquo;一站式&rdquo;学生社区综合管理模式，实现对1000所左右高校有效覆盖。持续推动各地各高校落实高校辅导员配备需求，加强高校辅导员素质能力提升精准赋能平台建设。开展&ldquo;青春使命&rdquo;&ldquo;技能成才强国有我&rdquo;&ldquo;学习新思想做好接班人&rdquo;&ldquo;开学第一课&rdquo;等主题教育活动，加强校园文化建设。推进绿色低碳发展系统纳入国民教育体系。发挥&ldquo;五老&rdquo;优势，继续开展&ldquo;新时代好少年&rdquo;主题教育读书活动、&ldquo;读懂中国&rdquo;活动。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　11.促进学生身心健康全面发展。践行健康第一理念，实施学校体育和体教融合改革发展行动计划，举办首届中国青少年足球联赛，筹备首届全国学生（青年）运动会。办好成都第31届世界大学生夏季运动会和晋江第18届世界中学生夏季运动会。启动实施中国青少年健康教育行动计划，继续推进健康中国中小学健康促进专项行动。强化高校学生体质健康促进工作，实现儿童青少年总体近视率比2021年下降0.5到1个百分点。实施全国健康学校和急救教育试点学校建设计划。完善大中小学相衔接的美育课程体系，强化美育教师队伍建设，开展美育浸润行动计划，建设一批美育名师工作室。举办全国第七届中小学生艺术展演，启动大中小学生艺术展演改革。推进中考美育改革试点。推进大中小学劳动教育，全面加强涉农高校耕读教育，推进职业院校劳动教育，开展中小学生职业启蒙教育。指导中小学劳动教育实验区开展工作，持续开展大中小学生劳动素养发展状况监测。加强和改进学生心理健康教育工作，实施学生心理健康促进计划，做好科学识别、实时预警、专业咨询和妥善应对。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　12.加快构建中国特色高质量教材体系。总结《全国大中小学教材建设规划（2019&mdash;2022年）》实施情况，督促指导地方和高校健全教材领导和工作机制。印发教材工作责任追究指导意见。印发修订后的义务教育课程方案和课程标准，启动各学科教材编修。完成中等职业学校三科统编教材和数学等七科公共基础课程教材编审，于2022年秋季学期投入使用。修订已出版相关教育部马工程重点教材，完成在编在审马工程重点教材。实施《新时代马克思主义理论研究和建设工程教育部重点教材建设推进方案》，启动第一批新教材的编写、遴选、修订。推进马克思、恩格斯、列宁关于哲学社会科学及各学科重要论述摘编编写。推进首批9种中国经济学教材编写，启动中国新闻学、中国法学教材编写，加快建设一批原创性高水平哲学社会科学教材。出台&ldquo;十四五&rdquo;普通高等教育本科教材建设规划，遴选建设一批&ldquo;十四五&rdquo;职业教育国家规划教材。全面规范教材、教辅及课外读物进校园管理，严格教材审核把关，加强数字教材建设与管理。完善中小学地方课程管理制度。加强首届全国教材建设奖获奖成果宣传推广。遴选确定一批国家教材建设重点研究基地。启动研制新时代大中小学教材建设规划。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　13.加强学校铸牢中华民族共同体意识教育。以增进共同性为方向，推动铸牢中华民族共同体意识教育与中小学德育和高校思想政治工作紧密融合。进一步提高各类民族班专项计划精准度契合度。继续实施新疆班西藏班校园足球融合赛事。开展&ldquo;组团式&rdquo;援疆教育人才选派工作。会同有关部门加强铸牢中华民族共同体意识研究基地建设与管理。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　14.提升国家通用语言文字普及水平和质量。研制国家语言发展规划。落实《国家语言文字事业&ldquo;十四五&rdquo;发展规划》。实施国家通用语言文字普及提升工程和推普助力乡村振兴计划，指导普通话普及率低于全国平均水平的省份实施&ldquo;一地一策&rdquo;。加强民族地区推广普及国家通用语言文字，推进学前儿童普通话教育，实施国家通用语言文字示范培训计划。传承弘扬中华优秀语言文化，实施中华经典诵读工程、古文字与中华文明传承发展工程、中华思想文化术语传播工程、中国语言资源保护工程，办好第四届中华经典诵写讲大赛。加强全球中文学习平台建设。加强高等学校语言文字工作。建设国家语言文字推广基地。加强语言文字规范化标准化信息化建设，发布《中小学生普通话水平测试等级标准》。实施《国家语委&ldquo;十四五&rdquo;科研规划》，推进语言文字人才队伍、科研机构、语言学学科建设。印发加强新时代语言文字国际合作交流文件。编制实施《国际中文教育发展规划（2021-2025年）》，完善国际中文教育标准体系。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　<strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">三、积极回应群众关切，不断促进教育发展成果更多更公平惠及全体人民</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　15.推进义务教育优质均衡发展。出台构建优质均衡的基本公共教育服务体系的意见，指导县域义务教育优质均衡创建工作，召开义务教育优质均衡发展经验交流会。研制集团化办学指导意见。全面落实免试就近入学全覆盖和&ldquo;公民同招&rdquo;，指导各地完善学校划片政策。深入做好随迁子女就学工作。修订出台学籍管理办法，严格规范学籍管理。深化基础教育综合改革，总结推广第一批实验区成果，遴选建立第二批基础教育综合改革实验区。持续推进基础教育优秀教学成果推广应用计划。充分发挥基础教育教学指导委员会指导教学改革作用。开展基础教育精品课遴选工作。建立利用社会资源支持学校教育教学和课后服务的有效机制。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　16.统筹推进乡村教育振兴和教育振兴乡村工作。研制教育系统乡村振兴指导性文件，贯穿打通县域基础教育、市域职业教育和省域高等教育，形成具有教育特色、发挥教育优势的乡村振兴工作法。持续巩固拓展教育脱贫攻坚成果，推进控辍保学从动态清零转向常态清零。把乡村教育融入乡村建设行动,更好发挥农村中小学的教育中心、文化中心作用。扩大实施中小学银龄计划。会同有关部门实施&ldquo;八一爱民学校&rdquo;援建，做好东部地区对口支援国家乡村振兴重点帮扶县中职、普高工作。做好直属高校定点帮扶，培育一批精准帮扶典型项目和创新试验项目，探索在乡村振兴领域建立成果转化平台。做好农村义务教育学生营养改善计划实施工作，落实县级政府主体责任，大力推进食堂供餐。完善&ldquo;三区&rdquo;人才支持计划教师专项计划，引导人才向艰苦地区和基层一线流动。引导农村职业教育和成人教育示范县主动对接当地经济社会发展需求，发挥百所乡村振兴人才培养优质校引领作用，助力培养高素质农民和农村实用人才。</p>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　17.加快发展学前教育、普通高中教育和特殊教育。实施&ldquo;十四五&rdquo;学前教育发展提升行动计划，进一步提升学前教育普及普惠水平，推动各地以县为单位完善普惠性资源布局规划，加强城镇新增人口、流动人口集中地区和乡村幼儿园建设。开展城镇小区配套园治理&ldquo;回头看&rdquo;。加大公办园教师核编补充力度，按同工同酬要求落实教师待遇。指导各地推进幼小衔接试点，全面提升保教质量。加强县域普通高中建设，实施&ldquo;十四五&rdquo;县域普通高中发展提升行动计划，启动实施县中托管帮扶工程。加快推动普通高中特色多样发展，全面实施新课程新教材，以强化特色引领高中学校健康发展，严格落实公办民办普通高中同步招生和属地招生政策。启动实施&ldquo;十四五&rdquo;特殊教育发展提升行动计划，推进特殊教育拓展融合提升，&ldquo;一人一案&rdquo;提高残疾儿童少年义务教育普及水平，推动特殊教育向两端延伸发展。加强标准化特殊教育学校和校园无障碍环境建设，推进特殊教育资源中心和资源教室建设。研制加强专门教育管理办法。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　18.促进高校毕业生更加充分更高质量就业。实施&ldquo;就业创业促进行动&rdquo;，健全就业创业促进机制，推动就业创业工作提质增效。完善市场化社会化就业机制，建设打造一批全国性、区域性、行业性大学生就业市场。引导毕业生到中小企业就业、灵活就业，促进创新创业带动就业。健全毕业生基层就业支持体系，推动优化各类政策性岗位招考时间安排。建立健全就业育人支持体系，强化就业指导服务，打造一批就业指导名师、金课和优秀教材。实施宏志助航计划，重点帮扶就业困难毕业生群体。推动就业与招生培养联动改革，实施供需对接就业育人项目。落实就业&ldquo;一把手&rdquo;工程，配齐建强就业工作队伍。组织开展就业育人典型案例和毕业生就业创业典型人物总结宣传工作。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　<strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">四、全面提升教育服务能力，为构建新发展格局提供坚强支撑</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　19.<span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; white-space: pre-wrap; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;"> </span>加快培养、引进国家急需的高层次紧缺人才。积极参与建设国家战略人才力量，着力集聚一批战略科学家、学术领军人才和高水平创新团队，培养一大批具有国际竞争力的优秀青年人才。加强基础学科人才培养，印发《关于加强基础学科人才培养的意见》，实施基础学科专业、课程、教材、实践条件等专项建设行动。积极探索拔尖创新人才早期发现和选拔培养机制，加大强基计划实施力度，支持实施本硕博一体化人才培养改革。研制《关于加强碳达峰碳中和人才培养体系建设行动方案》。启动国家产教融合研究生联合培养基地建设，培养工程技术和国防科技人才。印发《关于加强和改进新时代高等学校人才队伍建设的意见》。修订《&ldquo;长江学者奖励计划&rdquo;管理办法》，实施好国家重大人才工程。大力加强人才国际交流。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　20.支撑高水平科技自立自强。加快战略科技力量建设，强化有组织科研，坚持&ldquo;四个面向&rdquo;，组织大任务、建设大平台、组建大团队。主动与行业部门、地方政府和骨干企业对接，共同凝练科学技术问题，组织重大攻关任务。加快前沿科学中心、集成攻关大平台等重大平台的建设培育，推动国家重点实验室重组、国家工程研究中心建设，加快国家重大科技基础设施建设，完善教育部重点实验室和工程研究中心布局，建设首批基础学科研究中心和医药基础研究创新中心。服务国家区域发展战略，推进产学研深度融合，组织高校与地方成立联合创新中心、与企业开展协同攻关，加强科技成果转移转化能力建设。支持战略科技人才和领军人才为首席科学家组织大团队，启动实施科技领军人才团队和优秀青年团队项目。提升高校创新开放合作水平，支持高校牵头发起国际大科学计划和工程。推进教育部哲学社会科学实验室建设，积累总结试点经验。优化高校人文社科重点研究基地结构体系。启动建设社科创新团队。发挥高校智库作用，提高咨政建言质量和社会服务能力。加强科研伦理规范和监管，加强科研诚信教育，弘扬科学家精神，营造良好创新生态。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　21.增强职业教育适应性。引导中职学校多样化发展，培育一批优质中职学校。实施中职、高职办学条件达标工程。稳步发展职业本科教育，支持整合优质高职资源设立一批本科层次职业学校。深化产教融合、校企合作，推动职业教育股份制、混合所有制办学，推动职业教育集团（联盟）实体化运作，支持校企共建&ldquo;双师型&rdquo;教师培养培训基地、企业实践基地。印发新版专业简介和一批专业教学标准。推进实施《职业学校学生实习管理规定》，加强实习管理。发展中国特色学徒制，推进岗课赛证综合育人。实施先进制造业现场工程师培养专项计划，加强家政、养老、托育等民生紧缺领域人才培养。积极推动技能型社会建设，大力营造国家重视技能、社会崇尚技能、人人享有技能的社会环境。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">&nbsp; &nbsp; &nbsp; &nbsp;22.提升高等教育服务创新发展能力。调整优化学科专业结构，发布实施新一版学科专业目录及管理办法，发布首批急需学科专业引导发展清单及管理办法，试点建设一批学科交叉中心。实施新时代高等教育育人质量工程，建设高质量人才培养体系。统筹卓越拔尖人才培养，深入实施卓越拔尖人才培养计划，加强和改进科学教育、工程教育，深入推进新工科、新医科、新农科、新文科建设，加快培养理工农医类专业紧缺人才。加强卓越工程师培养，推动高校和企业共同设计培养目标、制定培养方案、实施培养过程，实行校企&ldquo;双导师制&rdquo;。打造一批未来技术学院、现代产业学院、高水平公共卫生学院和专业特色学院，推进国家产教融合创新平台建设，培育建设一批特色化高端医疗装备工程实践创新教学中心，推进虚拟教研室试点建设。布局建设新型高水平理工科大学。印发《关于加快新农科建设推进高等农林教育创新发展的意见》，研制《普通高等医学教育临床教学基地建设和管理规定》。加快紧缺领域新形态教学资源建设。规范高等学校在线开放课程教学管理。实施新时代振兴中西部高等教育攻坚行动，打造中西部高等教育发展&ldquo;西三角&rdquo;，实施&ldquo;慕课西部行计划&rdquo;2.0，精准实施对口支援西部高校工作，深入实施高校银龄教师支援西部计划。发挥四方联动机制作用，纵深推进部省合建工作。加强部部共建合作，启动省部共建2.0。<span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #ff4c41; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;">建设一批国家级创新创业学院、创新创业实践教育中心，办好第八届中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛，广泛开展&ldquo;青年红色筑梦之旅&rdquo;活动，办好中国大学生工程实践与创新能力大赛，深入实施国家级大学生创新创业训练计划，办好第十五届全国大学生创新创业年会。</strong></span>召开直属高校工作咨询委员会第三十一次全体会议。组建第八届全国高等学校设置评议委员会，指导各地编制实施&ldquo;十四五&rdquo;时期高校设置规划，统筹开展高校设置工作与独立学院转设。合理确定高校办学规模和结构，加强高校异地办学等机构规范管理。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　23.深入推进&ldquo;双一流&rdquo;建设。扎根中国大地、瞄准世界一流，引导建设高校强化学科重点建设，加强马克思主义理论学科建设，实施一流学科培优行动和基础学科深化行动。按照基础研究、工程技术、人文社会科学人才培养的不同规律和需求标准，完善多元评价体系和常态化监测系统，逐步淡化一流大学建设高校和一流学科建设高校的身份色彩，选择具有鲜明特色和综合优势的建设高校赋予一定建设自主权，探索分类特色发展模式。开展教育部与各省（区、市）新一轮&ldquo;双一流&rdquo;重点共建，加大统筹协调，支持各高校&ldquo;双一流&rdquo;建设。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　24.提高继续教育服务供给能力。加快构建服务全民终身学习的教育体系。规范发展高等继续教育，出台关于推进新时代普通高校举办学历继续教育改革的实施意见，加强对普通高等学校举办非学历教育规范管理，对直属高校非学历教育领域问题进行专项整治。修订高等学历继续教育专业设置管理办法，研制专业教学基本要求和办学基本条件要求、校外教学点及社会助学活动管理办法。推进国家资历框架和国家学分银行研究与实践。制订自学考试工作实施细则，推进自学考试内容和形式改革。推进国家开放大学创新发展，推动社区教育办学网络建设。持续开展社区教育&ldquo;能者为师&rdquo;特色课程推介共享行动。加快发展老年教育，加快推进国家老年大学筹建工作，开展老年人运用智能技术教育培训，开展&ldquo;智慧助老&rdquo;优质工作案例、教育培训项目及课程资源推介行动。推进学习型城市建设，办好全民终身学习活动周。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: center; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　<strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">五、深化改革扩大开放，持续为教育发展注入强大动力</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　25.深化新时代教育评价改革。坚决推进&ldquo;破五唯&rdquo;，落实部门、部内、地方、高校工作清单，加强典型经验总结和宣传推广。加大对违反&ldquo;十不得一严禁&rdquo;行为监测和整改力度。出台幼儿园保教质量评估指南，落实义务教育质量评价指南、普通高中办学质量评价指南。研制《中学生综合素质评价工作指南》《学生发展指导工作指南》。落实哲学社科领域破除&ldquo;唯论文&rdquo;、正确认识和规范使用高校人才称号等文件，突出创新价值、能力、贡献的评价导向。组织开展第九届高等学校科学研究优秀成果奖（人文社会科学）评选。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">26.积极稳妥推进考试招生制度改革。推进中考改革、推动各省（区、市）全面推进招生录取综合改革，加快实现省级统一命题，继续组织开展中考命题评估。深化高考综合改革，稳妥启动第五批高考综合改革，指导有关省份因地制宜出台改革方案并抓好组织实施。深化考试内容改革，健全德智体美劳全面考查的内容体系，加强对学生关键能力的考查。深入实施高职院校分类考试，着力选拔培养高素质技术技能人才。严格规范高校艺术类专业、高水平运动队考试招生管理，进一步提高艺术体育人才选拔水平和质量。深入实施&ldquo;高考、研考护航行动&rdquo;，平稳有序做好高考、研考组织工作。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　27.推动区域教育创新发展。深化&ldquo;四点一线一面&rdquo;，强化统筹，提升区域办学水平和服务创新能力。推进京津冀教育协同发展，重点推进首批疏解项目选址、经费支持。做好长三角教育现代化监测评估，发布长三角教育现代化指数。推动黄河流域九省区教育协同发展。积极落实关于推进粤港澳大湾区高等教育合作发展规划，支持高起点新机制创建高水平大学及办学合作。推动新时代教育服务东北振兴取得新成效。推进海南国际教育创新岛建设，推进境外高水平大学、职业院校在海南自由贸易港设立理工农医类学校。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　28.实施教育数字化战略行动。强化需求牵引，深化融合、创新赋能、应用驱动，积极发展&ldquo;互联网+教育&rdquo;，加快推进教育数字转型和智能升级。推进教育新型基础设施建设，建设国家智慧教育公共服务平台，创新数字资源供给模式，丰富数字教育资源和服务供给，深化国家中小学网络云平台应用，发挥国家电视空中课堂频道作用，探索大中小学智慧教室和智慧课堂建设，深化网络学习空间应用，改进课堂教学模式和学生评价方式。建设国家教育治理公共服务平台和基础教育综合管理服务平台，提升数据治理、政务服务和协同监管能力。强化数据挖掘和分析，构建基于数据的教育治理新模式。指导推进教育信息化新领域新模式试点示范，深化信息技术与教育教学融合创新。健全教育信息化标准规范体系，推进人工智能助推教师队伍建设试点工作。建立教育信息化产品和服务进校园审核制度。强化关键信息基础设施保障，提升个人信息保护水平。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　29.全面推进依法治教。深入推进习近平法治思想进教材进课堂进头脑。配合做好职业教育法、学前教育法、学位法、教师法审议，推进国家通用语言文字法修订，推动终身学习法、教育法典化立法研究，继续实施规章建设行动计划。落实家庭教育促进法，会同相关部门研制构建家校社协同育人的指导意见，推动学校提升家庭教育指导能力，探索在高校开设家庭教育选修课。深化教育领域&ldquo;放管服&rdquo;改革，编制教育部权责清单，强化文件合法性审查。进一步健全教育行政执法和执法监督机制，研制《教育行政执法与监督办法》。优化教育政务服务，推进&ldquo;一网通办&rdquo;和标准化、规范化、便利化建设。落实统计督查整改任务，深入推进教育统计现代化改革，加强统计数据治理，强化统计监督职能。推动高校章程修订，深入推进依法治校，抓好法律法规在学校的落实落地。落实教育系统&ldquo;八五&rdquo;普法规划，开展青少年法治教育，持续办好全国学生&ldquo;学宪法 讲宪法&rdquo;系列活动和&ldquo;宪法晨读&rdquo;活动，推进教师网络法治教育培训。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　30.深化教育督导体制机制改革。推进《教育督导条例》修订，指导各地制定《教育督导问责实施办法》。继续把&ldquo;双减&rdquo;督导作为教育督导&ldquo;一号工程&rdquo;，加大督办、通报、约谈和问责力度。做好省级人民政府履行教育职责评价，继续把&ldquo;双减&rdquo;&ldquo;两个只增不减&rdquo;和落实义务教育教师工资收入&ldquo;不低于&rdquo;情况作为评价重点。稳步推进学前教育督导评估，启动中小学幼儿园校（园）长任期结束综合督导评估试点。召开全国县域义务教育基本均衡发展总结大会，认定一批&ldquo;优质均衡&rdquo;县（市、区）。做好国家义务教育质量监测，研究开展高中教育质量监测试点。修订中等职业学校办学能力评估办法和高等职业院校适应社会需求能力评估办法，启动第四轮职业院校评估。修订高等学校本科教学工作合格评估办法，研制&ldquo;十四五&rdquo;期间本科教育教学审核评估计划，做好年度合格评估和审核评估工作。做好高等教育质量监测国家数据平台建设，开展本科教学质量报告工作，探索开展质量监测预警。支持专业机构做好本科专业认证。发布专业学位水平评估和学科评估结果，对评估结果较差的单位予以督导。研制高校评估归口管理办法，减轻高校负担。开展博士硕士学位论文和本科毕业论文（设计）抽检。加大高校评估整改督导复查力度。探索建设教育督导信息化平台。组织北京、上海、江苏、浙江做好PISA2022正式测试。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">&nbsp; &nbsp; &nbsp; &nbsp;31.支持和规范民办教育健康发展。持续深化民办教育分类管理改革，发挥民办教育工作部际联席会议制度作用，完善民办学校分类扶持、分类管理的政策举措，指导各地加快出台配套政策。积极稳慎推进规范民办义务教育发展专项工作，加快优化义务教育结构，确保义务教育学位主要由公办学校和政府购买服务方式提供。研制民办学校举办者变更管理办法，维护教育公益属性，研制加强对民办学校全方位督导的指导文件，引导民办教育有序健康高质量发展。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　32.推进高水平教育对外开放。举办中外高级别人文交流机制会议，推进共建&ldquo;一带一路&rdquo;教育行动高质量发展，加强同东盟职业教育、学历互认等合作，建立中国&mdash;东盟教育高官磋商机制，办好中国&mdash;东盟教育交流周。实施&ldquo;未来非洲&mdash;中非职业教育合作计划&rdquo;，举办国际性职业教育大会，主办金砖国家教育部长会议，建立金砖国家职业教育联盟和举办职业教育技能大赛，推进&ldquo;鲁班工坊&rdquo;建设。加强对欧高层次和技术技能人才培养工作，做实做细与俄乌等国留学生交流，深化国际产学研用合作，开展具有法人资格的中外合作办学机构、内地与港澳地区合作办学机构培养模式改革试点。深化国家公派出国留学体制机制改革，健全出国留学人员行前培训工作机制。打造更具国际竞争力的留学教育，改革中国政府奖学金招生培养机制，推进来华留学生国情教育教材和课程建设。发布实施《外籍教师聘任和管理办法（试行）》，启用外籍教师综合信息服务平台。推动和支持香港、澳门特别行政区政府履行教育管治主体责任，支持并推动内地优质基础教育资源赴香港举办内地课程学校，探索海峡两岸教育融合发展，巩固内地（大陆）与港澳台教育交流平台，完善港澳台学生培养管理工作。推进海外中国学校试点建设。深化与联合国教科文组织战略合作，推进上海合作组织框架下教育合作，积极参与全球教育治理，持续做好国际组织人才推送工作，探索开展围绕开放科学的国际合作，继续办好国际人工智能与教育会议、世界慕课与在线教育大会、&ldquo;一带一路&rdquo;青年创意与遗产论坛等。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　<strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">六、把教师作为教育发展的第一资源，打造高素质专业化创新型教师队伍</strong></p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　33.加强教师思想政治和师德师风建设。持续推进高校教师思想政治建设专项工作。落实《关于完善高校教师思想政治和师德师风建设工作体制机制的指导意见》。选树宣传教师典型，持续做好师德教育。做好首批全国高校黄大年式教师团队总结推广，完成第二批创建。推进教师考核评价改革，强化教师思想政治素质考察。开展高校教师思想政治和师德师风情况专项检查，严肃查处师德师风案件，通报师德违规典型案例，严格落实师德师风问题&ldquo;黑名单&rdquo;制度，探索建立师德违规案例指导制度。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　34.全面夯实教师发展之基。实施新时代基础教育强师计划，重点建设一批国家师范教育基地、国家教师队伍建设改革实验区，实施师范教育协同提质计划。实施中西部欠发达地区优秀教师定向培养计划。优化部属师范大学师范生公费教育政策。实施中小学教师发展协同提质计划。统筹师范生培养和教师在职培训内容，加强对课程教材方面的培养和培训力度。加快完善职业教育教师培养培训体系，实施职业院校教师素质提高计划，设立国家级示范培训项目。鼓励高水平综合性大学举办教师教育。</p>
<p style="margin: 0px; padding: 16px 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #333333; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; overflow: hidden; box-sizing: border-box !important; overflow-wrap: break-word !important; border: 0px initial initial;">　　35.完善教师管理与待遇保障。完善中小学教师资格考试政策。推动各地加强中小学教职工编制保障。研究完善中小学岗位设置管理办法，提高中小学中级、高级岗位结构比例。加强工资待遇保障，提高教龄津贴标准，落实好乡村教师生活补助政策，逐步提高乡村教师待遇，支持艰苦边远地区改善乡村教师周转宿舍。深化义务教育教师&ldquo;县管校聘&rdquo;管理改革，有序推进教师交流轮岗。推进中小学教师减负工作，严控进校园事项，督促各地落实已经出台的中小学教师减负清单。继续实施&ldquo;乡村优秀青年教师培养奖励计划&rdquo;。开展2022年国家级教学成果奖评审。</p>');
INSERT INTO content VALUES (406, '<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;进入21世纪的第三个十年，数字产业化与产业数字化在全球范围内全面推进，以数据要素与数字技术的广泛使用为标志的数字经济时代已然到来。2020年我国数字经济规模达到39.2万亿元，保持了高位的年均增长速度，数字经济在我国国民经济中的重要地位进一步凸显。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;2022年《政府工作报告》中提出，&ldquo;促进数字经济发展。加强数字中国建设整体布局。建设数字信息基础设施，逐步构建全国一体化大数据中心体系，推进5G规模化应用，促进产业数字化转型，发展智慧城市、数字乡村。加快发展工业互联网，培育壮大集成电路、人工智能等数字产业，提升关键软硬件技术创新和供给能力。完善数字经济治理，培育数据要素市场，释放数据要素潜力，提高应用能力，更好赋能经济发展、丰富人民生活。&rdquo;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;数字经济具有高创新性、强渗透性、广覆盖性，不仅是新的经济增长点，也是改造提升传统产业的支点和构建现代化经济体系的重要引擎。面对世界百年未有之大变局，高等教育如何更好地抓住数字经济这一世界科技革命和产业变革的新机遇，推动经济发展质量变革、效率变革、动力变革，对于我国构建新发展格局、实现高质量发展，具有十分重大的现实意义。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; line-height: 2em; text-align: center; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #007aaa; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; box-sizing: border-box !important; overflow-wrap: break-word !important;">数字经济的内涵和特征表现</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 关于数字经济包含的具体内容，在中国国家统计局于2021年5月发布的《数字经济及其核心产业统计分类（2021）》中，将数字经济严格划分为数字产业化和产业数字化两个部分。其中，数字产业化对应数字经济核心产业，具体包括计算机通信和其他电子设备制造业、电信广播电视和卫星传输服务、互联网和相关服务、软件和信息技术服务业等，是数字经济发展的基础。产业数字化指应用数字技术和数据资源为传统产业带来的产出增加和效率提升，是数字技术与实体经济的融合。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;对于数字经济的内涵和特征表现，专家学者有很多表述。湖南工商大学党委书记、中国工程院院士陈晓红认为，数字经济的主要特征体现在三个方面。第一，数据支撑。数据资本取代实体资本成为支撑价值创造和经济发展的关键生产要素，是数字经济最本质的特征。数据资本是指包含海量信息的流通数据经由分析处理技术衍生出的集成信息资产（如大数据）。利用数据资本挖掘消费者潜在需求是开拓新商业模式、创新产品服务的关键。第二，融合创新。新一代信息技术发展使创新过程脱离了从知识积累、研究到应用的线性链条规律，创新阶段边界逐渐模糊，各阶段相互作用，创新过程逐渐融为一体。第三，开放共享。数字经济时代各类数字化平台加速涌现，以开放的生态系统为载体，将生产、流通、服务和消费等各个环节逐步整合到平台，推动线上线下资源有机结合，创造出许多新的商业模式和业态，形成平台经济。这三条新特征贯穿数字经济发展的全过程，成为中国经济数字化转型的主要动力。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; line-height: 2em; text-align: center; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #007aaa; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; box-sizing: border-box !important; overflow-wrap: break-word !important;">数据是数字经济时代的关键要素</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 关于数字技术的简单理解是与电子计算机相伴相生的各项科学技术，目前最常见的是被合称为&ldquo;大智移云物区&rdquo;的大数据、人工智能、移动互联、云计算、物联网和区块链技术。数字技术的发展彻底改变了信息这一人类知识载体的运算、加工、存储、传送、传播、还原与处理方式，催生了数据这一新的生产要素，进而改变人类经济社会活动的基本组织形式。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 专家学者们认为，当前数字经济发展势头依然十分强劲，新业态、新模式不断涌现。要掌握数字经济发展主动权，保障网络安全、国家安全，就必须早日突破核心技术难题。要加强关键核心技术，如高端芯片、关键基础软件等领域的研发突破和迭代应用，同时要提升工业互联网、人工智能、区块链的创新能力，加强量子信息、先进计算、未来网络这些前沿技术布局。力争在一些领域实现&ldquo;换道超车&rdquo;，尽快实现高水平自立自强。只有夯实技术基础、掌握核心技术，才能把控好数字经济的&ldquo;命门&rdquo;，把发展数字经济自主权牢牢掌握在自己手中。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 哈尔滨工业大学（深圳）校长周玉表示，&ldquo;最近黑龙江省委省政府继续实施&lsquo;头雁计划&rsquo;等一系列政策，吸引年轻的创新创业人才来到黑龙江，哈工大也将继续在智能制造、人工智能等新的产业领域发挥引领示范作用。&rdquo;周玉认为，大数据具有巨大产业发展潜力和广泛应用前景，加快推进黑龙江省的大数据产业发展，对于加快培育战略性新兴产业，进一步提升社会治理能力，具有十分重要的意义。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; line-height: 2em; text-align: center; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #007aaa; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; box-sizing: border-box !important; overflow-wrap: break-word !important;">培育数字文化产业&nbsp; 推进行业健康发展</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;数字文化产业是文化产业的重要发展方向，是建设文化强国的重要组成部分在带动经济增长、提供就业岗位、促进文化传播等方面有积极作用。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 北京理工大学人文与社会科学学院院长李健认为，可以从源头出发，加快打造优质可持续的数字文化内容生态。政策引导从业企业下大力气培育和鼓励创作者，进一步利用好中华文化的&ldquo;富矿&rdquo;，用情用力用心讲好中国故事，创作出符合时代发展的精品力作；推进相关部门与地方政府持续加大与游戏、影视、网文、动漫等数字文创企业的主动对接合作，进一步引导国内数字文化企业与民俗和区域文化从业者、研究者进行平台交流，开展更加体系化的对接与共创，增强数字文化产品创作的内生动力。同时，还应该进一步加强知识产权保护力度，持续治理影视、文学、动漫、游戏作品侵权等行业乱象，保护数字文化行业从业者的合法权益。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 专家建议，司法机关进一步推进数字文化产业领域相关侵权诉讼的理论研判与司法实践，有力打击针对原创数字内容的新型侵权行为，进一步发挥相关法律对创作者的支持作用；建议相关部门加大协同治理与惩处力度，有效打击数字文化领域的网络灰黑产乱象，持续推进行业健康发展。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 针对新兴商业模式遇到的IP纠纷等问题，需要进一步制定相关制度规范，形成有序竞争、良性发展的市场规则，兼顾行业发展、社会效益以及业内各主体的利益。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 中国科学院大学马一德教授认为，快速发展变化的数字经济对社会治理提出了新的制度需求。他因此建议，在数字经济治理中，完善数据产权保护的法律机制应当成为重点工程。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; background-color: #ffffff; line-height: 2em; text-align: center; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #007aaa; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; box-sizing: border-box !important; overflow-wrap: break-word !important;">加快推进高等教育&ldquo;智改数转&rdquo;</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 随着数字经济的进一步发展，也将对高等教育提出更高要求。一方面，数字经济的发展需要专业、高效的数字经济人才培养体系予以支撑；另一方面，数字技术的发展又反过来改变高等教育的基本模式，推动教育理念、教学方法和教育形态的不断创新。应利用数字信息技术提升教育改革，搭建数字化的社会实践平台，通过数字技术搭建就业创业服务体系，利用信息技术树立大学生就业、创业观，全面提升大学生就业创业能力。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 展望未来，数字经济在中国经济中的占比必将进一步提升，数字产业规模必将不断扩大，产业数字化进程必将进一步深入。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &ldquo;智能化改造和数字化转型是高等教育&lsquo;新基建&rsquo;的重要内容，其核心是提升信息技术的应用融合程度和管理服务信息系统的智能化，重塑大学形态。&rdquo;苏州大学校长熊思东提出，当前，应加快促进高等教育&ldquo;智改数转&rdquo;，为教育数字转型提供可推广、可复制的成功经验。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 熊思东认为，在高等教育新基建推进中仍面临缺乏可参比的建设标准指引、缺乏融合等问题，高校网络平台资源建设与现代信息技术应用还未实现有效衔接，缺乏适应当下、面向未来的解决方案。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; &nbsp;为此，他建议加强顶层设计，把&ldquo;智改数转&rdquo;作为高校新基建核心内容，加强统筹协调，制定统一标准。在此基础上，增大投入力度，设立专项经费支持高校&ldquo;智改数转&rdquo;，加大支持力度，让高校&ldquo;敢转&rdquo;&ldquo;愿转&rdquo;&ldquo;会转&rdquo;，鼓励高校积极培养适应高等教育&ldquo;智改数转&rdquo;的人才。此外，还应积极推动校企合作，推进智慧治理，关注信息安全，让高校&ldquo;智改数转&rdquo;规范有序高效推进。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</span></section>
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp; &nbsp; &nbsp; 对于数字经济背景下的高等教育如何进一步融合发展，我们充满期待。</span></p>');
INSERT INTO content VALUES (407, '<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 'Microsoft Yahei'; font-size: 16px; letter-spacing: 0.544px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">近年来，互联网、大数据、云计算、人工智能、区块链等技术加速创新，日益融入经济社会发展各领域全过程。</span><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 'Microsoft Yahei'; font-size: 16px; letter-spacing: 0.544px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">习近平总书记深刻地指出，数字经济发展速度之快、辐射范围之广、影响程度之深前所未有，正在成为重组全球要素资源、重塑全球经济结构、改变全球竞争格局的关键力量。</span></p>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 1.75em; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 'Microsoft Yahei'; font-size: 16px; letter-spacing: 0.544px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">立足前沿谋发展，迎&ldquo;风&rdquo;起舞展风采！</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 'Microsoft Yahei'; font-size: 16px; letter-spacing: 0.544px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">刚刚召开的江西省深化发展和改革双&ldquo;一号工程&rdquo;推进大会，明确了打造全国数字经济发展新高地等&ldquo;一地四区&rdquo;总体定位的时间表和路线图，吹响了深入推进数字经济做优做强&ldquo;一号发展工程&rdquo;的冲锋号。</span><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 'Microsoft Yahei'; font-size: 16px; letter-spacing: 0.544px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">全省上下要把思想和行动统一到省委、省政府决策部署上来，切实以&ldquo;第一等&rdquo;的举措，深入推进数字经济做优做强&ldquo;一号发展工程&rdquo;，加快打造全国数字经济发展新高地。</span></section>
<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Paragraph"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">当今世界，产业数字化、数字产业化势不可挡。</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">谁抓住数字经济时代先机、抢占未来发展制高点，谁就能实现变道超车、换挡提速、跨越赶超。江西正处于厚积薄发、爬坡过坎、转型升级的关键阶段，大力发展数字经济是顺应新一轮科技革命和产业变革的必由之路，是落实&ldquo;作示范、勇争先&rdquo;目标定位的必然要求，是推动全省高质量跨越式发展的重要引爆点。近年来，江西数字经济政策不断完善、平台加速建设、核心产业发展强劲，VR、移动物联网等已成为江西数字经济发展的&ldquo;新名片&rdquo;。数字经济日益成为江西经济增长的主引擎、转型升级的主动能、创业创新的主阵地。<br style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Break" /></span></p>
<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Paragraph"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">千帆竞发，百舸争流。</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">我们要清醒认识到，江西数字经济发展虽然起步较早、势头良好，但总量不大、竞争力不强、人才短缺等问题也非常突出。同时，发展数字经济是一项系统工程，涵盖产业生态、数据要素、技术创新等诸多内容。我们一定要切实增强使命感紧迫感危机感，找准突破口和发力点，按照&ldquo;一地四区&rdquo;总体定位，精准发力、精耕细作，全方位、系统性发展数字经济，努力在全国版图中占得&ldquo;应有地位&rdquo;。<br style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Break" /></span></p>
<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Paragraph"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">要聚焦重点领域，精准深耕产业赛道，加快培育数字产业新优势。</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">做优做强数字经济重点在于强化数字引擎、数字应用、数字赋能，不仅要做到&ldquo;量&rdquo;的倍增，同时要实现&ldquo;质&rdquo;的跃升。要按照&ldquo;精细化、专业化、赛道化&rdquo;思维，集中优势资源做深做细产业赛道，特别是要聚焦基础赛道、新兴赛道、融合赛道，加快VR、物联网、大数据、区块链、智能网联汽车等优势产业链和数字产业集群建设，抢占数字产业化制高点，全面提升数字产业规模能级；聚焦数字经济主攻赛道，开展&ldquo;5020&rdquo;项目攻坚行动，招引一批投资规模大、科技含量高、带动能力强的数字经济重大项目，不断激发数字经济发展的开放活力。<br style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Break" /></span></p>
<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Paragraph"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">要聚焦融合应用，强化数字赋能和应用场景建设，加快迈出产业升级新步伐。</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">数字经济是新旧动能转换的核心驱动力。要充分发挥数字技术对经济发展的放大、叠加、倍增作用，深入实施上云用数赋智工程，赋能制造业、服务业、农业转型升级，塑造产业数字化转型新优势；深化&ldquo;赣服通&rdquo;&ldquo;赣政通&rdquo;等应用场景建设，推进供给多元应用，加快应用示范推广，全域构建与数字化发展高度契合的多元应用场景，以场景优势抢占数字经济发展先机。<br style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Break" /></span></p>
<p style="margin: 0px 8px 10px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; line-height: 2em; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-node-type="Paragraph"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">要聚焦科技创新，加速数字技术创新和人才队伍建设，打造&ldquo;雨林型&rdquo;数字经济新生态。</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 0.544px; font-family: 'Microsoft Yahei'; font-size: 16px; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;">要牵住自主创新这个&ldquo;牛鼻子&rdquo;，全力争创国家技术创新中心、产业创新中心、制造业创新中心，精准实施关键技术攻坚行动，力争形成更多具有自主知识产权的核心技术；研究出台数字经济人才专项政策，大力开展赣籍数字经济人才回归专项行动，加大高层次人才和团队招引力度，完善创新激励机制，促进人才引得进、留得住、用得好，让数字经济人才潮涌赣鄱。</span></p>');
INSERT INTO content VALUES (408, '<p class="MsoNormal" style="line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各省、自治区、直辖市教育厅（教委）</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">，</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">新疆生产建设兵团教育局，有关部门（单位）教育司（局），部属各高等学校、部省合建各高等学校，国家开放大学：</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">为深入贯彻落实习近平总书记关于教育的重要论述和给第三届中国</span>&ldquo;互联网＋&rdquo;大学生创新创业大赛&ldquo;青年红色筑梦之旅&rdquo;大学生重要回信精神，落实《国务院办公厅关于深化高等学校创新创业教育改革的实施意见》《国务院办公厅关于进一步支持大学生创新创业的指导意见》等文件精神，全面深化高校创新创业教育改革、提升大学生创新创业能力、加快培养创新创业人才，纵深推进大众创业万众创新，定于2022年4月至10月举办第八届中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛。现将有关事项通知如下。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">一、大赛主题</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">我敢闯，我会创。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">二、总体目标</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">更中国、更国际、更教育、更全面、更创新，传承和弘扬红色基因，聚焦</span>&ldquo;五育&rdquo;融合创新创业教育实践，激发青年学生创新创造热情，线上线下相融合，打造共建共享、融通中外的国际创新创业盛会，开启创新创业教育改革新征程。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;">&mdash;&mdash;更中国</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">。更深层次、更广范围体现红色基因传承，充分展现新发展阶段高水平创新创业教育的丰硕成果，集中展示新发展理念引领下创新创业人才培养的中国方案，提升高等教育新时代感召力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;">&mdash;&mdash;</span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">更国际。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">深化创新创业教育国际交流合作，汇聚全球知名高校、企业和创业者，服务以国内大循环为主体、国内国际双循环相互促进的新发展格局，搭建全球性创新创业竞赛平台，提升中国高等教育的影响力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;">&mdash;&mdash;更教育。</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">落实立德树人根本任务，推动思想政治教育、专业教育与创新创业教育深度融合，弘扬劳动精神，加强学生创新实践能力培养，造就理想信念坚定、勇于创新创造的新时代青年奋斗者，提升高等教育新时代塑造力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;">&mdash;&mdash;更全面。</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">鼓励各学段学生积极参赛，形成创新创业教育在高等教育、职业教育、基础教育、留学生教育等各类各学段的全覆盖，打通创新创业人才培养各环节，提升高等教育新时代引领力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;">&mdash;&mdash;更创新。</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">丰富竞赛形式和内容，优化赛制选拔，改革赛事组织，激发全社会创新创业创造动能，促进高校创新成果转化应用，服务国家创新发展，提升高等教育新时代创造力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">三、主要任务</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">以赛促教，探索人才培养新途径。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">全面推进高校课程思政建设，深入推进新工科、新医科、新农科、新文科建设，不断深化创新创业教育改革，引领各类学校人才培养范式深刻变革，形成新的人才培养质量观和质量标准，切实提高学生的创新精神、创业意识和创新创业能力。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">以赛促学，培养创新创业生力军。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">服务构建新发展格局和高水平自立自强，激发学生的创造力，激励广大青年扎根中国大地了解国情民情，在创新创业中增长智慧才干，坚定执着追理想，实事求是闯新路，把激昂的青春梦融入伟大的中国梦，努力成长为德才兼备的有为人才。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">以赛促创，搭建产教融合新平台。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">把教育融入经济社会发展，推动成果转化和产学研用融合，促进教育链、人才链与产业链、创新链有机衔接，以创新引领创业、以创业带动就业，推动形成高校毕业生更高质量创业就业的新局面。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">四、大赛内容</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt; background: #ffffff;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（一）</span></span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">主体赛事</span></span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">包括</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">高教主赛道、</span>&ldquo;青年红色筑梦之旅&rdquo;赛道、职教赛道、萌芽赛道和产业命题赛道（详见附件1&mdash;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">5</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">）。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt; background: #ffffff;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（二）</span>&ldquo;</span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">青年红色筑梦之旅</span></span><span style="font-family: 楷体_GB2312; font-size: 16pt;">&rdquo;</span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">活动</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（详见附件</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">2</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">）。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt; background: #ffffff;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（三）</span></span><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">同期活动。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">即</span>&ldquo;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">创撷硕果</span>&rdquo;</span><span style="font-family: 等线; font-size: 16pt;">&mdash;&mdash;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">国际大学生创新创业成果展</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">、</span>&ldquo;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">创联虹桥</span>&rdquo;</span><span style="font-family: 等线; font-size: 16pt;">&mdash;&mdash;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">大赛优秀项目资源对接会、</span>&ldquo;创<span style="font-family: 仿宋_GB2312;">享未来</span>&rdquo;</span><span style="font-family: 等线; font-size: 16pt;">&mdash;&mdash;</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">&ldquo;新工科、新医科、新农科、新文科&rdquo;世界高等教育发展校长论坛</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">五、组织机构</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（一）大赛由教育部、中央统战部、中央网络安全和信息化委员会办公室、国家发展改革委、工业和信息化部、人力资源社会保障部、农业农村部、中国科学院、中国工程院、国家知识产权局、国家乡村振兴局、共青团中央和重庆市人民政府共同主办，重庆大学承办。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（二）大赛设立组织委员会（以下简称大赛组委会），由教育部和重庆市人民政府主要负责同志担任主任、教育部和重庆市分管负责同志担任副主任、教育部高等教育司主要负责同志担任秘书长、有关部门（单位）负责同志作为成员，负责大赛的组织实施。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（三）大赛设立专家委员会，负责项目评审等工作。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（四）大赛设立纪律与监督委员会，负责对赛事组织、参赛项目评审、协办单位相关工作等进行监督，对违反大赛纪律的行为予以处理。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（五）大赛总决赛由中国建设银行冠名支持，各省级教育行政部门可积极争取中国建设银行分支机构对省级赛事的赞助支持。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（六）各省级教育行政部门可成立相应的赛事机构，负责本地比赛的组织实施、项目评审和推荐等工作。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">六、参赛要求</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（一）参赛项目能够紧密结合经济社会各领域现实需求，充分体现高校在新工科、新医科、新农科、新文科建设方面取得的成果，培育新产品、新服务、新业态、新模式，促进制造业、农业、卫生、能源、环保、战略性新兴产业等产业转型升级，促进数字技术与教育、医疗、交通、金融、消费生活、文化传播等深度融合（各赛道参赛项目类型详见附件）。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（二）参赛项目应弘扬正能量，践行社会主义核心价值观，真实、健康、合法。不得含有任何违反《中华人民共和国宪法》及其他法律法规的内容。所涉及的发明创造、专利技术、资源等必须拥有清晰合法的知识产权或物权。如有抄袭盗用他人成果、提供虚假材料等违反相关法律法规和违背大赛精神的行为，一经发现即刻丧失参赛资格、所获奖项等相关权利，并自负一切法律责任。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（三）</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">参赛项目只能选择一个符合要求的赛道报名参赛，根据参赛团队负责人的学籍或学历确定参赛团队所代表的参赛学校，且代表的参赛学校具有唯一性。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">参赛团队须在报名系统中将项目所涉及的材料按时如实填写提交。已获本大赛往届总决赛各赛道金奖和银奖的项目，不可报名参加本届大赛。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（四）参赛人员（不含产业命题赛道参赛项目成员中的教师）年龄不超过</span>35岁（1987年3月1日及以后出生）。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（五）各省级教育行政部门及各有关学校要严格开展参赛项目审查工作，确保参赛项目的合规性和真实性。审查主要包括参赛资格以及项目所涉及的科技成果、知识产权、财务状况、运营、荣誉奖项等方面。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">七、比赛赛制</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（一）大赛主要采用校级初赛、省级复赛、总决赛三级赛制（不含萌芽赛道以及国际参赛项目）。校级初赛由各院校负责组织，省级复赛由各地负责组织，总决赛由各地按照大赛组委会确定的配额择优遴选推荐项目。大赛组委会将综合考虑各地报名团队数（含邀请国际参赛项目数）、参赛院校数和创新创业教育工作情况等因素分配总决赛名额。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（二）大赛共产生</span>3500个项目入围总决赛（港澳台地区参赛名额单列），其中高教主赛道2000个（国内项目1500个、国际项目500个）、&ldquo;青年红色筑梦之旅&rdquo;赛道500个、职教赛道500个、萌芽赛道200个、产业命题赛道300个。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（三）高教主赛道每所高校入选总决赛项目总数不超过</span>5个，&ldquo;青年红色筑梦之旅&rdquo;赛道、职教赛道每所院校入选总决赛项目各不超过3个。产业命题赛道每道命题每所院校入选项目总数不超过3个。萌芽赛道每所学校入选全国总决赛的项目总数不超过2个。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">八、赛程安排</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（一）参赛报名（</span>2022年</span><span style="font-family: 楷体_GB2312; font-size: 16pt;">4</span><span style="font-family: 楷体_GB2312; font-size: 16pt;">&mdash;7月）。</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">参赛团队通过登录全国大学生创业服务网（网址：</span>cy.ncss.cn）或微信公众号（名称为&ldquo;全国大学生创业服务网&rdquo;或&ldquo;中国互联网十大学生创新创业大赛&rdquo;）任一方式进行报名。在服务网&ldquo;资料下载&rdquo;板块可下载学生操作手册指导报名参赛，微信公众号可进行赛事咨询。评审规则将于近期公布，请登录全国大学生创业服务网查看具体内容。各省级教育行政部门及各有关学校负责审核参赛对象资格。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">报名系统开放时间为</span>2022年</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">4</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">月</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">15</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">日，报名截止时间由各地根据复赛安排自行决定，但不得晚于</span>7月31日。国际参赛项目通过全球青年创新领袖共同体促进会官网进行报名（网址：www.pilcchina.org），具体安排另行通知。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（二）初赛复赛（</span>2022年6&mdash;8月）。</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各地各学校登录</span>cy.ncss.cn/gl/login进行大赛管理和信息查看。省级管理用户使用大赛组委会统一分配的账号进行登录，校级账号由各省级管理用户进行管理。初赛复赛的比赛环节、评审方式等由各校、各地自行决定，赛事组织须符合本地新冠肺炎疫情常态化防控要求并制定应急预案。各地应在8月15日前完成省级复赛，并完成入围总决赛的项目遴选工作（推荐项目应有名次排序，供总决赛参考）。国际参赛项目的遴选推荐工作另行安排。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（三）总决赛（</span>2022年10月）</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">。大赛设金奖、银奖、铜奖；另设省市组织奖、高校集体奖及若干单项奖。入围总决赛的项目将通过网评和会评，择优进入总决赛现场比赛，决出各类奖项。大赛组委会通过全国大学生创业服务网、国家</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">24365大学生就业服务平台</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">（</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;">https://www.ncss.cn/</span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">）为参赛团队提供项目展示、创业指导、人才招聘、资源对接等服务，各项目团队可登录上述网站查看相关信息，各地可利用网站提供的资源，为参赛团队做好服务。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">九、工作要求</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（一）宣传发动。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各地各校要认真做好大赛的宣传动员和组织工作，确保参赛师生充分了解大赛、积极参与大赛。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（二）协调组织。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各省级教育行政部门要统筹协调高教、职教和基教等职能处室共同参与，组织做好省内比赛和项目推荐工作。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（三）提供支持。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各校要做好学校初赛组织工作，为在校生和毕业生参与竞赛提供必要的条件和支持。华为技术有限公司将为参赛团队提供多种资源支持。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（四）扩大共享。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各地各校要结合实施教育数字化战略行动，依托国家高等教育智慧教育平台，加强创新创业教育资源共享，推动创新创业项目对接和落地转化。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 楷体_GB2312; font-size: 16pt;"><span style="font-family: 楷体_GB2312;">（五）疫情防控。</span></span><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">各地要根据新冠肺炎疫情常态化防控工作要求，遵守属地管理原则，科学制订赛事活动疫情防控工作方案及应急处置预案，安全有序推进大赛的组织筹备。</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 黑体; font-size: 16pt;"><span style="font-family: 黑体;">十、其他</span></span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;"><span style="font-family: 仿宋_GB2312; font-size: 16pt;"><span style="font-family: 仿宋_GB2312;">本通知所涉及内容的最终解释权，归第八届中国国际</span>&ldquo;互联网+&rdquo;大学生创新创业大赛组委会所有。</span></p>
<p class="MsoNormal" style="text-indent: 32pt; line-height: 27pt;">&nbsp;</p>');
INSERT INTO content VALUES (409, '<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-04-20%2015%3A32%3A14%E9%99%88%E8%8B%8F.jpg?Expires=1965799934&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HDCh1MjVzU4xpyNkxU7yYPV%2FrOA%3D" alt="" width="213" height="300" /></p>
<p style="text-align: center;">创业导师</p>
<p style="text-align: center;">&nbsp;陈苏</p>
<p style="text-align: center;">江西软件职业技术大学董事长、先锋软件集团董事长、党委书记、江西省政协委员</p>
<p style="text-align: center;">江西省工商联主席</p>
<p style="text-align: center;">江西省工商总会副会长</p>
<p style="text-align: center;">江西省党代会代表</p>
<p style="text-align: center;">中国开源运动领军人物</p>
<p style="text-align: center;">中国优秀民营科技企业家</p>
<p style="text-align: center;">改革开放40年优秀赣商</p>
<p style="text-align: center;">香港&ldquo;紫金花杯杰出企业家奖&rdquo;</p>
<p style="text-align: center;">2020年度退役军人创业光荣榜</p>
<p style="text-align: center;">南昌市退役军人就业创业促进会会长</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>');
INSERT INTO content VALUES (410, '<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff;">各市、县（区）人民政府，省政府各部门：</p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;">大学生是大众创业万众创新的生力军，支持大学生创新创业具有重要意义。为有效解决大学生创新创业实践中的关键问题，进一步提升大学生创新创业能力，根据《国务院办公厅关于进一步支持大学生创新创业的指导意见》（国办发〔2021〕35号）精神，结合我省实际，经省政府同意提出如下实施意见。</p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">一、总体要求</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;">坚持以习近平新时代中国特色社会主义思想为指导，深入贯彻落实党的十九大和十九届历次全会精神，以及习近平总书记视察江西重要讲话精神，聚焦&ldquo;作示范、勇争先&rdquo;目标定位,全面贯彻党的教育方针，落实立德树人根本任务，按照省第十五次党代会的部署要求，紧紧围绕&ldquo;六个江西&rdquo;建设，不断深化创新创业教育改革，促进大学生全面发展，实现大学生更加充分更高质量就业，为新时代江西改革发展培养造就更多创新创业&ldquo;赣鄱新军&rdquo;。</p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">二、进一步提升大学生创新创业能力</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">(一)将创新创业教育贯穿人才培养全过程。</span></strong>坚持立德树人基本导向，建立健全思想引领、课堂教学、自主学习、实训实践、指导帮扶、文化激励融为一体的高校创新创业教育体系，使创新精神、创业意识和创新创业能力成为评价人才培养质量的重要指标。建设一批省级创新创业学院、产业学院、未来技术学院、协同创新研究院、产业技术研究院，健全校校、校企、校所、校地协同的创新创业人才培养机制。打造一批创新创业教育特色示范课程。加强创新创业教育教材编写工作，建设一批省级创新创业教育优秀教材。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省人力资源社会保障厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">(二)提升教师创新创业教育教学能力。</span></strong>配齐配强创新创业教师队伍。鼓励教师把国际前沿学术发展、最新研究成果融入课堂教学。积极实施高校教师服务企业计划，落实高校双创指导教师到行业企业挂职锻炼的激励保障政策，鼓励应用型学科专业的在岗教师同时成为对口行业企业的工程师，建设一支&ldquo;双师双能型&rdquo;师资队伍。探索建立驻校企业家（工程师）制度，吸引更多优秀人才到高校担任双创导师。继续举办好全省&ldquo;互联网+&rdquo;大学生创新创业大赛指导教师技能培训及展示活动，建设一批省级双创导师培训基地，定期开展培训。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省科技厅、省人力资源社会保障厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>三<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>强化大学生创新创业专项训练。</span></strong>创新高校培训模式，面向大学生开展以政策解读、经验分享、实践指导等为主要内容的高质量、有针对性的创新创业培训，提升创新创业能力。深入实施大学生创新创业训练计划，支持各类创新创业大赛对大学生创业者给予倾斜。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省人力资源社会保障厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">三、进一步优化大学生创新创业机制</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（四<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>降低大学生创新创业门槛。</span></strong>持续优化我省企业开办一网通办平台，为大学生创业提供高效便捷的登记服务。鼓励各类孵化机构面向大学生创新创业团队免费开放一定比例的孵化空间，并将开放情况纳入大学科技园、众创空间的考核评价。政府投资开发的孵化机构，应给予入驻创新创业的高校毕业生提供一站式、低成本、开放式的孵化服务。政府投资开发的孵化器等创业载体应安排30%左右的场地，免费提供给高校毕业生。有条件的地方可对高校毕业生到孵化器创业给予租金补贴。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">(责任单位：省科技厅、省人力资源社会保障厅、省教育厅、省市场监管局)</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>五<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>便利化助力大学生创新创业。</span></strong>完善科技创新资源开放共享机制，鼓励各地、各高校和科研院所的科技创新资源，面向大学生开放共享，提供低价、优质的专业服务，支持大学生创新创业。建好&ldquo;校企通&rdquo;等发布平台，鼓励行业企业面向高校和大学生发布技术创新需求清单，引导大学生精准创业。探索新形势下&ldquo;政产学研用&rdquo;科技成果转移转化新模式，引导大学生参与开展技术攻关活动。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省科技厅、省发展改革委、省教育厅、省国资委）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>六<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>落实大学生创新创业保障政策。</span></strong>落实好大学生创业帮扶政策，加大对创业失败大学生的扶持力度，按规定提供就业服务、就业援助和社会救助。鼓励有条件的地方按照市场规律，探索建立创业风险补贴、商业险保费补助等类型的大学生创业风险救助机制，进而研究更加精准、更加有效的帮扶措施，并及时总结经验、适时推广。毕业后创业的大学生按政策规定缴纳&ldquo;五险一金&rdquo;，减少大学生创业的后顾之忧。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">(责任单位：省人力资源社会保障厅、省教育厅、省民政厅、省财政厅、省医保局)</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">四、进一步推进创新创业服务平台建设</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>七<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>构建高校大学生创新创业实践平台。</span></strong>充分发挥大学科技园、产业园、创业园、创客空间等实践平台的作用，免费向在校大学生开放，为大学生创新创业开展专业化孵化服务。允许大学生创业项目在校内进行集群登记注册。结合学校学科专业特色优势，联合有关行业企业，建设一批校外大学生双创实践教学基地。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省科技厅、省人力资源社会保障厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>八<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>发挥大众创业万众创新示范基地带动作用。</span></strong>深入实施创业就业&ldquo;校企行&rdquo;专项行动。推动企业示范基地和高校示范基地通过共建双创学院、专业实验室、虚拟仿真实验室、创业实验室和实训中心等方式，建立长期稳固的合作关系。指导高校示范基地所在城市主动规划和布局高校周边产业，积极承接大学生创新成果和人才要素，打造&ldquo;校企共荣&rdquo;&ldquo;城校共生&rdquo;的创新创业生态。推动省属国有企业、科研院所及相关公共服务机构利用自身技术、人才、场地、资金等优势，为大学生建设集研发、孵化、投资等于一体的创业创新平台。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省发展改革委、省教育厅、省科技厅、省国资委）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">五、进一步加大财税、金融相关政策扶持力度</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>九<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>继续加大对高校创新创业教育的支持力度。</span></strong>省财政在现有支持政策的基础上，将创新创业教育和大学生创新创业情况作为资金分配的重要因素。各地、各有关部门要整合政府和社会资金，支持高校学生创新创业活动，高校要优化经费支出结构，多渠道统筹安排资金，逐步加大对创新创业的投入，并纳入学校年度预算。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省财政厅、省教育厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>落实落细减税降费政策。</span></strong>2025年12月31日前，高校毕业生在毕业年度内从事个体经营，符合规定条件的，在3年内按每户每年14400元为限额依次扣减其当年实际应缴纳的增值税、城市维护建设税、教育费附加、地方教育附加和个人所得税。2022年12月31日前，对月销售额15万元以下的增值税小规模纳税人免征增值税，对小微企业和个体工商户按规定减免所得税。对创业投资企业、天使投资人投资于未上市的中小高新技术企业以及种子期、初创期科技型企业的投资额，按规定抵扣所得税应纳税所得额。按照规定落实好国家级、省级科技企业孵化器和大学科技园以及国家备案众创空间的相关税收优惠政策。做好纳税服务，建立对接机制，强化精准支持。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省财政厅、省税务局）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十一<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>落实普惠金融政策。</span></strong>鼓励金融机构按照市场化、商业可持续原则对大学生创业项目提供金融服务，解决大学生创业融资难题。落实创业担保贷款及贴息政策，将高校毕业生个人最高贷款额度提高至30万元，对高校毕业生创办符合条件的小微企业，最高贷款额度提高至600万元，其中300万元以内贷款按国家、省现行政策予以贴息，鼓励各地对300万元至600万元之间的贷款进行贴息；经金融机构认定，对高校毕业生10万元以内、获得设区市级以上荣誉的高校毕业生30万元以内的贷款申请，以及具有博士学位、正高专业技术职称、高级技师职业资格的人员创办的小微企业，申请100万元以内创业担保贷款，原则上免除担保、反担保手续；鼓励各地降低贷款利率，简化办理流程，支持符合条件的高校毕业生创业就业。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省财政厅、省人力资源社会保障厅、人行南昌中心支行、江西银保监局）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">六、进一步促进大学生创新创业成果转化</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十二<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>完善成果转化机制。</span></strong>研究设立大学生创新创业成果转化服务机构与成果转换平台，推进知识产权全过程管理，建立相关成果与行业产业对接长效机制，举办知识产权拍卖会、科技成果对接会等活动，促进大学生创新创业成果在有关行业企业推广应用。做好大学生创新项目的知识产权确权、保护等工作，探索建立服务大学生的知识产权特派员制度，选派专业人员帮助大学生解决知识产权转移转化难题，强化激励导向，加快落实以增加知识价值为导向的分配政策，落实成果转化奖励和收益分配办法。加强面向大学生的科技成果转化线上、线下培训课程建设，并纳入创新创业教育课程体系。鼓励高校创新创业学院设立大学生创新成果转化专职岗位。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省科技厅、省教育厅、省知识产权局）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十三<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>强化成果转化服务。</span></strong>推动地方、企业和大学生创新创业团队加强合作对接，拓宽成果转化渠道，提升转化服务能力，为高校科技成果转化和大学生创新创业项目落地提供帮助。汇集地方政府、企业、高校及社会资源，加强对历届中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛中涌现的优秀项目进行后续跟踪，落实相关税收优惠政策，支持其科技成果转化，推动一批大赛优秀项目落地，形成大学生创新创业示范效应。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省科技厅、省发展改革委、省财政厅、省国资委、省税务局）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">七、进一步组织参加中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛等赛事</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十四<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>完善省级大赛可持续发展机制。</span></strong>鼓励地市政府支持有条件的高校承办省赛，压实主办职责，进一步加强组织领导和综合协调，落实配套支持政策和条件保障。支持高校进一步完善大赛激励措施，对于参赛学生，在入学推免、奖学金评选、学分认定、论文成果认定等方面上给予适当倾斜；对于指导教师，在职称评定、非津贴工作量认定等方面完善激励政策；对于参与大赛组织工作且所在学校取得优异成绩的管理岗位人员，学校要给予评优评先等方面的奖励，实施职员制的学校可考虑给予有突出贡献的人员晋档的奖励。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省国资委、江西证监局、中国建设银行江西省分行）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十五<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>激发大学生创新创业活力。</span></strong>强化大赛创新创业教育实践平台的作用，将学生开展创新实验、发表论文、获得专利和自主创业等情况折算为学分，将学生参与项目实验、项目打磨、路演答辩等活动认定为实践学习，研究生参赛成绩可用于充抵毕业业绩条件，激发不同学段学生参赛的积极性和主动性。建立健全中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛与各级各类创新创业比赛联动机制。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省科技厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;">八、进一步加强创新创业信息服务</strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;"><strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">(</span></strong>十六<strong style="box-sizing: border-box;"><span style="box-sizing: border-box;">)</span></strong>建立大学生创新创业信息服务平台。</span></strong>汇集创新创业帮扶政策、产业激励政策和全国创新创业教育优质资源，加强信息资源整合，做好政策发布、解读等工作。及时收集国家、区域、行业需求，实现通过&ldquo;赣服通&rdquo;、江西省人社公共服务平台等多渠道为大学生精准推送行业和市场动向等信息。加强对创新创业大学生和项目的跟踪、指导、服务，畅通供需对接渠道，积极举办大学生创新创业项目需求与投融资对接会。鼓励有条件的学校在各学院、班级指定专职人员负责创新创业管理工作，提升创新创业信息服务质量。<strong style="box-sizing: border-box;"><span style="box-sizing: border-box; font-family: 楷体, 楷体_GB2312, SimKai;">（责任单位：省教育厅、省发展改革委、省人力资源社会保障厅）</span></strong></p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;">建立由省教育厅牵头，省发展改革委、省财政厅、省科技厅、省人力资源社会保障厅、省民政厅等部门参与的大学生创新创业工作联席会议制度，定期专题研究，加强协调指导，确保支持大学生创新创业各项政策落地实施。将创新创业纳入高校教育教学评估指标体系和学科评估指标体系。各地、各高校要研究制定支持大学生创新创业的政策措施，及时帮助大学生解决实际问题。大力宣传促进大学生创新创业的重要性，及时总结推广经验做法，选树创新创业成功典型，打造敢为人先、宽容失败、社会支持的创新创业良好生态。</p>
<p style="box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; color: #333333; text-align: right; font-family: 微软雅黑; line-height: 2em; font-size: 16px; background-color: #ffffff; text-indent: 2em;">2022年4月6日</p>');
INSERT INTO content VALUES (411, '<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">&nbsp; &nbsp; &nbsp;近日，教育部印发了《教育部关于举办第八届中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛的通知》（以下简称《通知》），正式启动第八届大赛。教育部高等教育司负责人就《通知》相关问题回答了记者提问。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">一、请介绍一下第八届大赛的总体背景情况</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛已经成为我国深化创新创业教育改革的重要载体和关键平台，成为覆盖全国所有高校、面向全体大学生、影响最大的高校双创盛会，七年来，围绕&ldquo;更中国、更国际、更教育、更全面、更创新&rdquo;的总体目标，培养了一大批有理想、有本领、有担当的源源不断的青春力量。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　2022年是习近平总书记给大赛&ldquo;青年红色筑梦之旅&rdquo;活动大学生回信五周年。我们将深入贯彻落实总书记重要回信精神，总结经验、继往开来，落实国办《关于进一步支持大学生创新创业的指导意见》要求，全力以赴办好第八届大赛，以赛促教、以赛促学、以赛促创，再拓新思路、再现新形象、再上新台阶，打造共建共享、融通中外的国际创新创业盛会，以优异成绩迎接党的二十大胜利召开。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">二、第八届大赛总决赛将在重庆举行，请问有什么特殊考虑？</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：2020年9月1日，习近平总书记主持召开中央深改委第十五次会议审议《关于新时代振兴中西部高等教育的意见》，强调要激发中西部高等教育内生动力和发展活力，推动形成同中西部开发开放格局相匹配的高等教育体系。去年9月，中央印发了专门文件。这是党中央对全面提升中西部高等教育发展水平作出的重大战略部署。重庆市是振兴中西部高等教育的战略支点，是打造西南地区高等教育对外开放的桥头堡。在重庆举办大赛，将积极引导广大青年学生在中西部建功立业，进一步激发中西部高等教育内生动力和发展活力，推动提升中西部高等教育发展水平，有力支撑中西部经济振兴、文化振兴、教育振兴、人才振兴。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">三、本届大赛在进一步回归和突出育人本质上有哪些措施？</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：高等教育的根本任务是立德树人。本届大赛将进一步回归和突出育人本质，引导各地各高校深化高校创新创业教育改革，厚植大众创业万众创新土壤。在评审规则设置方面，我们考虑将更突出教育导向，加大教育分值所占比重，&ldquo;引领教育&rdquo;将成为重要考察点。在评审过程中，我们将更加聚焦学生在创新创业实践中的成长与发展，对项目的创意过程、专业知识运用情况、专业教育与创新创业教育结合情况、学科交叉融合情况等进行多维度考察。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">四、本届大赛如何支持更多在校大学生项目脱颖而出？</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：一是单设本科生参赛组别。在参赛规模最大的高教主赛道中，根据学生所处学习阶段，我们单独设置本科生参赛组别，让本科生集中在同一&ldquo;起跑线&rdquo;赛跑，充分反映本科生创新创业水平和成果。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　二是强调在校生原始创新。取消原高教主赛道师生共创组，同时加强参赛项目真实性核查，让更多具有原始创新创意的在校大学生特别是本科生深度参赛，引导高校更加关注和支持在校大学生创新创业。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　三是提高本科生项目入围比例。适度提高本科生项目入围总决赛比例，让更多&ldquo;稚嫩&rdquo;而&ldquo;不平凡&rdquo;的本科生项目脱颖而出。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　四是注重学生创业实效。关注大学生在创办企业中发挥的作用和贡献度，体现&ldquo;真创业&rdquo;&ldquo;实创业&rdquo;。在本科生初创组和成长组中，明确项目负责人须为参赛企业法定代表人，并对负责人及团队的股权要求进行了适当调整。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">五、本届大赛与&ldquo;新工科、新医科、新农科、新文科&rdquo;建设如何深度融合？</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：&ldquo;新工科、新医科、新农科、新文科&rdquo;是新时代高等教育的新教改、新质量、新体系、新文化，本届大赛深度结合&ldquo;四新&rdquo;建设，带动高校人才培养范式变革。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　一是高教主赛道按照&ldquo;四新&rdquo;分类。在高教主赛道中，本科生、研究生两大组别均按照新工科、新医科、新农科、新文科四种类型报名参赛。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　二是&ldquo;红旅&rdquo;活动通过&ldquo;四新&rdquo;赋能。以&ldquo;四新&rdquo;助力&ldquo;新农村、新农业、新农民、新生态&rdquo;建设，引导师生扎根基层创新创业，推动乡村振兴取得新进展。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　三是产业命题赛道结合&ldquo;四新&rdquo;征题。要求企业围绕&ldquo;四新&rdquo;对应的产业和行业领域，基于企业发展真实需求进行命题申报，真正让高校&ldquo;四新&rdquo;建设与产业实际连接起来，促进高校创新成果转化应用，校企协同培育产业新领域。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　<strong style="margin: 0px; padding: 0px; border: 0px; overflow: hidden;">六、本届大赛正式设立产业命题赛道，在参赛条件及奖项方面有哪些新变化？</strong></p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　答：去年的第七届大赛，我们首次设置了产业命题赛道，取得了很好的成效。今年，在总结上届大赛相关经验和成效的基础上，我们对产业命题赛道的参赛对象、奖项数量进行了调整，旨在进一步搭好建强教育端与产业端的互通桥梁。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　在参赛对象方面，允许跨校组建、师生共同参赛，通过产业出题、高校揭榜、同题共答、真题真做的方式，打通高校智力资源和企业发展需求，师生协同解决企业发展中所面临的技术、管理等现实问题。</p>
<p style="margin: 0px; padding: 16px 0px; border: 0px; overflow: hidden; font-size: 32px; color: #4b4b4b; font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Helvetica Neue', STHeiti, 'Microsoft Yahei', Tahoma, Simsun, sans-serif, Helvetica, 微软雅黑; background-color: #ffffff;">　　在奖项数量方面，为进一步激发高校、企业参赛热情，总奖项数有较大增长，由100项增加至300项。其中，金奖数由15项增至30项、银奖数由35项增至60项、铜奖数由50项增至210项。</p>');
