INSERT INTO content VALUES (416, '<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">2月18日，井冈山市与先锋软件股份有限公司、江西软件职业技术大学签订合作建设新校区与数字经济产业园协议签约仪式在吉安市委一号会议室举行。</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; background-color: #ffffff; text-align: center;"><img style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; outline: 0px; max-width: 780px;" src="http://www.jgs.gov.cn/uploadfile/3/Attachment/e1328699f0.png" data-layer="photo" /></p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">　　吉安市委书记王少玄，市委副书记、市长罗文江，副书记肖玉兰，王大胜，漆海云，傅正华，周密、廖东生等吉安市和井冈山市领导，先锋软件集团董事局主席陈苏，财务总监胡友莱出席了签约仪式。</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; background-color: #ffffff; text-align: center;"><img style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; outline: 0px; max-width: 780px;" src="http://www.jgs.gov.cn/uploadfile/3/Attachment/5d353127ee.jpeg" data-layer="photo" /></p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px; color: #333333; font-family: 微软雅黑; font-size: 17px; text-align: justify; background-color: #ffffff;"><span style="box-sizing: border-box; padding: 0px; margin: 0px; border: 0px; outline: 0px;">　　为了落实省市&ldquo;双一号工程&rdquo;，推进招大引强、项目&ldquo;双赛制&rdquo;工作进展，井冈山市加大力度引进数字经济产业园项目，此次签约的井冈山数字经济产业园项目，总投资约30亿元。由先锋软件股份有限公司和江西软件职业技术大学共同投资，在井冈山市进行数字经济产业园和江西软件职业技术大学井冈山新校区一体化建设，将实施区块链十大重点工程，包含区块链应用技术研究院、区块链技术研发公共平台，数字经济投资基金，区块链和数字经济应用示范工程等，致力于打造江西区块链产业发展高地，国内领先的区块链产业基地；江西软件职业技术大学井冈山校区作为产业发展的人才基地，主要开展区块链、大数据、VR、软件工程、信息安全等专业的职业本科人才培养，力争用3至5年时间，将园区建成占地面积1000亩，建筑面积70万㎡。园区从业人员和在校学生规模合计3至4万人，形成产教融合，产城融合一体化的发展规模。</span></p>');
INSERT INTO content VALUES (417, '<p style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;近日，教育部公布了《关于第一期供需对接就业育人项目立项名单的通知》（教学司函〔2022〕7号），江西软件职业技术大学四个项目经过高校申请、用人单位申报、专家审核、立项单位信息核查等环节，获准立项。</p>
<p class="ql-align-center" style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; text-align: center; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;"><img style="border: 0px; margin: 10px auto 0px; padding: 0px; display: block; max-width: 100%; height: auto;" src="https://p6.itc.cn/images01/20220411/47cd5e0b9d9c490aaa68ec09453fe6f0.png" /></p>
<p style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp; 这四个项目分别是我校与深信服科技股份有限公司、深圳信盈达科技有限公司的定向人才培养培训项目；与深圳市讯方技术股份有限公司、北京安博大成教育科技有限责任公司的就业实习基地。合作项目内容涵盖面广，为我校强化就业与人才培养联动机制，加深校企合作、推进协同育人提供了有效路径。</p>
<p class="ql-align-center" style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; text-align: center; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;"><img style="border: 0px; margin: 10px auto 0px; padding: 0px; display: block; max-width: 100%; height: auto;" src="https://p6.itc.cn/images01/20220411/c0dd855fb3df4193a9596fb04dd4f4ff.png" /></p>
<p style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;学校一直秉承&ldquo;创业创新、知识管理&rdquo;校训，倡导&ldquo;学好软件，报效祖国&rdquo;使命，坚持&ldquo;校企融合，产学互动&rdquo;办学模式，实践&ldquo;三好一专、十一工程&rdquo;人才培养体系，形成了&ldquo;用企业家育人理念培养学生&rdquo;&ldquo;请工程师当老师&rdquo;&ldquo;拿真实的项目进行实训&rdquo;的校企深度融合发展思路。此次四个供需对接育人项目的成功立项，是对学校长期开展产教融合、校企合作工作的肯定，体现了学校落实党中央、国务院&ldquo;稳就业&rdquo;&ldquo;保就业&rdquo;的决策部署，是深化产教融合、校企合作，推动人才培养与就业有机联动、人才供需有效对接的具体措施，为进一步拓宽人才培养思路、深化校企、校地多向多维度合作提供了优质平台。</p>
<p style="border: 0px; margin: 0.63em 0px 1.8em; padding: 0px; font-size: 16px; counter-reset: list-1 0 list-2 0 list-3 0 list-4 0 list-5 0 list-6 0 list-7 0 list-8 0 list-9 0; color: #191919; font-family: 'PingFang SC', Arial, 微软雅黑, 宋体, simsun, sans-serif; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; 下一步，学校将与用人单位共同加强过程管理，落实落细合作内容，保证项目顺利实施。同时，以此为契机，积极拓展就业实习基地，为毕业生创造更多就业实习机会，促进毕业生就业工作高质量发展。</p>');
INSERT INTO content VALUES (418, '<p><a title="第六届中国国际互联网加大学生创新创业大赛" href="https://www.ixigua.com/6899661124023616008?fromvsogou=1&amp;utm_source=sogou_duanshipin&amp;utm_medium=sogou_referral&amp;utm_campaign=cooperation">https://www.ixigua.com/6899661124023616008?fromvsogou=1&amp;utm_source=sogou_duanshipin&amp;utm_medium=sogou_referral&amp;utm_campaign=cooperation</a></p>');
INSERT INTO content VALUES (419, '<p><a title="第五届中国&ldquo;互联网+&rdquo;创新创业大赛总决赛冠军争夺赛" href="https://www.bilibili.com/video/av71256179?fromvsogou=1&amp;bsource=sogou&amp;fr=seo.bilibili.com">https://www.bilibili.com/video/av71256179?fromvsogou=1&amp;bsource=sogou&amp;fr=seo.bilibili.com</a></p>');
INSERT INTO content VALUES (420, '<p><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-03-10%2010%3A24%3A21undefined?Expires=1962239061&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=3wXW8mOS1e6zF7CEQvsQAtzNUbw%3D" /></p>');
INSERT INTO content VALUES (421, '<p style="margin: 0px; padding: 0px; border: 0px; font-size: 17px; font-family: 微软雅黑, 'Microsoft YaHei', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; max-inline-size: 100%; clear: both; min-height: 1em; cursor: text; caret-color: #ff0000; text-align: justify; text-indent: 2em; box-sizing: border-box !important; outline: none 0px !important;"><span style="margin: 0px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; max-inline-size: 100%; cursor: text; caret-color: red; box-sizing: border-box !important; outline: none 0px !important;">为拓宽师生的学术视野，提高科技创新意识，激发科技创新潜力，提高科技创新能力，营造浓厚的校园学术氛围。6月5日下午2点，北京理工大学特种机器人技术创新中心主任、工学博士、教授、博士生导师，国务院特殊津贴专家，中国大学生创新创业最佳指导教师罗庆生莅临江西软件职业技术大学&ldquo;先锋讲堂&rdquo;，为全校师生开展&ldquo;大学生双创人才培养的理论与实践&rdquo;的学术交流讲座。中国青少年科技辅导员协会监事长李晓亮以及软件学院师生与智能科技学院师生200余人参加此次讲座。<br style="max-inline-size: 100%; margin: 0px; padding: 0px; box-sizing: border-box !important; outline: none 0px !important;" /></span></p>
<p style="text-indent: 0em; margin: 0px; padding: 0px; border: 0px; font-size: 17px; font-family: 微软雅黑, 'Microsoft YaHei', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; max-inline-size: 100%; clear: both; min-height: 1em; cursor: text; caret-color: #ff0000; box-sizing: border-box !important; outline: none 0px !important;"><span style="margin: 0px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; max-inline-size: 100%; cursor: text; caret-color: red; box-sizing: border-box !important; outline: none 0px !important;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-06-07%2010%3A09%3A35IMG_5439.jpg?Expires=1938391775&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=w0qPQt%2B8FKX0%2FEPZfgr1FWf9Mr0%3D" alt="" width="800" height="481" /><br style="max-inline-size: 100%; margin: 0px; padding: 0px; box-sizing: border-box !important; outline: none 0px !important;" /></span></p>
<p style="margin: 0px; padding: 0px; border: 0px; font-size: 17px; font-family: 微软雅黑, 'Microsoft YaHei', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; max-inline-size: 100%; clear: both; min-height: 1em; cursor: text; caret-color: #ff0000; text-align: justify; text-indent: 2em; box-sizing: border-box !important; outline: none 0px !important;"><span style="margin: 0px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; max-inline-size: 100%; cursor: text; box-sizing: border-box !important; outline: none 0px !important;">罗庆生教授首先用一段酷炫、动感的短视频向大家展示了现代高科技发明实例，讲座现场气氛热烈，师生们惊叹声不断。随后，罗庆生教授从创新教育目标、创新指导工作、创新成果展示、创新经验总结四个方面由浅入深的讲解了在5G时代大学生双创人才如何培养的理论与实践。他强调，在创新教育时，要瞄准科技前沿，创新科技体制，加强创新人才队伍建设，转化现实生产力。在5G发展的新时代，要探索确实有效的实践能力训练教学方法，这样在推进素质教育的同时，可以大大提升师生的实践能力。在大学生科技创新时，要注重八步法，即火眼金睛、博览群书、权衡再三、科学研究、精打细算、动脑寻梦、动手学匠、装配调试、总结归纳。他还着重强调，搞科研、做学问的人要眼观六路、耳听八方，多看多听勤思考。讲座最后还设置了提问环节，罗庆生教授详细耐心为同学们答疑解惑。</span></p>
<p style="margin: 0px; padding: 0px; border: 0px; font-size: 17px; font-family: 微软雅黑, 'Microsoft YaHei', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 34px; color: #333333; max-inline-size: 100%; clear: both; min-height: 1em; cursor: text; caret-color: #ff0000; box-sizing: border-box !important; outline: none 0px !important;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-family: 'Microsoft YaHei'; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-06-07%2010%3A09%3A35IMG_5442.jpg?Expires=1938391775&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=LV7%2FTKKupjk0cpjUuwKC4zeeUx0%3D" alt="" width="800" height="564" /></p>
<p style="margin: 0px; padding: 0px; border: 0px; font-size: 17px; font-family: 微软雅黑, 'Microsoft YaHei', Arial, sans-serif; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; max-inline-size: 100%; clear: both; min-height: 1em; cursor: text; caret-color: #ff0000; text-align: justify; text-indent: 2em; box-sizing: border-box !important; outline: none 0px !important;"><span style="margin: 0px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; max-inline-size: 100%; cursor: text; box-sizing: border-box !important; outline: none 0px !important;">讲座结束后，同学们纷纷表示收获颇丰，对本次讲座的生动讲解和精彩案例留下了深刻的印象，激发了创新兴趣，启发了创新思维。此次讲座也为不久后要举办的&ldquo;互联网+大赛&rdquo;校赛打下了坚实的基础，也是江西软件职业技术大学创业创新特色教育的课外活动的丰富形式之一，在加强了学生创业创新浓厚氛围同时，也进一步积极贯彻落实了十九大报告中习近平总书记关于创新的重要讲话精神。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-06-07%2010%3A09%3A35IMG_5453.jpg?Expires=1938391775&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=vWhh9PEYSO1ZNkhZO0s8mztsUzo%3D" alt="" width="800" height="513" /></p>');
INSERT INTO content VALUES (422, '<p><a title="喜讯！陈苏董事长上榜江西省退役军人优秀创业者人物榜" href="https://mp.weixin.qq.com/s/pthblGUF2eGJkAMfHvPDRg">https://mp.weixin.qq.com/s/pthblGUF2eGJkAMfHvPDRg</a></p>');
INSERT INTO content VALUES (423, '<p><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-05-24%2019%3A31%3A57IMG_4380.jpg?Expires=1937215917&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Cbo4CkJLmdUaEbzjKLI1czN4YlE%3D" /></p>');
INSERT INTO content VALUES (424, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; text-align: justify;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; background-color: #ffffff; text-indent: 32px;">&nbsp; &nbsp; &nbsp; 4月14日下午，由校团委、创新创业学院举办的江西软件职业技术大学创新创业协会成立大会在创客中心路演大厅隆重举行。先锋集团董事长陈苏，校党委副书记、副校长高建国，副校长张永革等领导出席了大会。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-04-15%2016%3A06%3A08IMG_0399.jpg?Expires=1933833968&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=MhDdRiRPn%2BwBMYjIU1I7HfM%2Bsmc%3D" width="991" height="539" /><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-align: justify; text-indent: 32px; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp; 会上，陈苏董事长向</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-align: justify; text-indent: 2em; background-color: #ffffff;">师生作了精彩的专题演讲。他首先</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-align: justify; text-indent: 32px; background-color: #ffffff;">对创新创业协会的成立表示了祝贺，并号召全校同学积极加入到这个充满朝气的协会中去。随后，他向师生们讲述了自己的创业史，并介绍了江西先锋天使咖啡，一杯咖啡成就创业梦的故事。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-04-15%2016%3A06%3A10IMG_0460.jpg?Expires=1933833970&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=MFsxCD70Ge31vnYHsSSoVtLaQ8I%3D" width="999" height="721" /><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059; text-align: justify; text-indent: 32px; background-color: #ffffff;">&nbsp; &nbsp; &nbsp; &nbsp; 陈苏董事长表示，创新创业对学校发展和学生成长具有重要意义，要切实发挥协会对学生的号召力，激励和带领更多大学生开展创新创业实践，要在学校大力营造创新创业校园文化，齐心协力做大、做强、做优我校创新创业这篇大文章。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-04-15%2016%3A06%3A11IMG_0426.jpg?Expires=1933833971&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=spx8w94m%2FmzHSAGRp0Ql7MLA4p4%3D" width="1013" height="626" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">大会还宣读了校团委对协会的批复、协会章程以及协会干部名单等。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 32px; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近年来,我校高度重视大学生创新创业意识与能力的培养,在多方面给予了大力支持,营造了良好的大学生创新创业氛围。创新创业协会的成立不仅进一步优化了学生的创业环境，还调动了学生创新创业的积极性，提高学生创新创业的能力。</span></p>');
INSERT INTO content VALUES (425, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">2022年4月23日，江西软件职业技术大学雀石战队不负众望，凭借精湛的技术、超群的实力，一举拿下WUCG（世界大学生电子竞技联赛）总决赛英雄联盟组冠军。本场比赛吸引了60万网友在线观看。雀石战队夺冠的一瞬间，全校16000名师生热血沸腾。此次夺冠，是江西软件职业技术大学电竞队夺得的又一世界级桂冠，也史无前例实现了WUCG赛事的三连冠。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-04-23%2019%3A18%3A14%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220423190727.jpg?Expires=1966072694&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=d2lFBBtsADL1cO6cZH0fZUWvggU%3D" width="651" height="365" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #000000;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 18.6667px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">荣光加冕续写传奇</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">赛前，雀石战队一直是大家瞩目的焦点。作为英雄联盟江软时代的代表战队，它曾先后拿下了2019年WUCG世界冠军、2020WUCG英雄联盟总冠军以及第八届、第九届英雄联盟高校联赛全国冠军等，战绩显赫。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">战队教练张佳介绍，WUCG作为全国最成功的高校电竞赛事品牌，去年一度受到特殊情况的影响，导致本应在去年就进行的决赛，延期至今年4月22日，这对战队成员的状态保持提出了很大的挑战。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><span style="background-color: #ffffff;">每天中午1点到晚上12点，吃饭、休息不超过2小时，训练、比赛、打排位；临睡前，对当天的训练和比赛进行复盘，提升队员对游戏的理解。高强度的训练没有辜负队员们，在4月23日的决赛场上，雀石战队配合默契，与对方斗智斗勇，最终以3:0的比分完美收官，为观众们呈现了许多精彩瞬间，也为自己赢得了冠军宝座。</span></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">经此一役，雀石战队作为WUCG的三冠王，随着WUCG登陆东南亚、拉丁美洲、南美、北美等地，其影响力也开始从全国走向世界，江软电竞王朝、雀石电竞传奇荣耀不断，展现了学校电竞的硬实力。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #000000;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 18.6667px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">前沿培养模式打造圆梦&ldquo;捷径&rdquo;</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">在庆祝雀石战队夺冠的人群中，江西软件职业技术大学创客小镇电竞基地中300多名电竞专业的学生显得格外激动，这次夺冠更加坚定了他们的信心，让他们看见自己未来可期。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">江西软件职业技术大学是国内首批、江西首家设置电子竞技专业的高校。先锋软件集团董事长、学校创始人陈苏十年前到韩国大邱进行考察，看见市长与电竞选手一起在电子竞技嘉年华打游戏，也看见电竞具备成为支柱性产业的可能，有了引进电竞的想法，最终与熊焱教育&ldquo;携手&rdquo;办学，开设电子竞技运动与管理专业，专业的基础课程由学校负责，而关于电竞的核心课程则交给白星亮与他的熊焱教育。这一选择无疑是学校&ldquo;校企融合、产学互动&rdquo;培养模式最为成功的例证之一。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-04-23%2019%3A54%3A29%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220423195345.jpg?Expires=1966074869&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=2eer%2Fxu1Pdhu3RiLYwiU79hKSZg%3D" alt="" width="650" height="431" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">为了给电竞学子搭造一条通往电竞梦的道路，提供更为广阔的平台，先锋创客小镇电竞基地应运而生。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">先锋创客小镇电竞基地成立专门项目领导组，同时组建了管理运营公司，并建立具备科学管理、科技支撑的自我管理、自主发展的现代化人才培养基地，以完善的管理制度、健全的服务体系（配备专业设备、雄厚师资、完备后勤）、专门资金保障，围绕电子竞技人才培养、赛事策划、游戏运营、战队建设、网络主播等五个方面，打造庞大电子竞技互动产业群的平台。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-04-23%2019%3A41%3A31%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220423194016.jpg?Expires=1966074091&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=mqQcSZ013pjeHn18386lFIKE4iM%3D" alt="" width="650" height="488" /></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">至今，先锋创客小镇电子竞技基地先后被国家体育总局、科技部、新闻出版总署等单位授予全国先进单位的称号。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #000000;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 18.6667px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">前沿技术让电竞教育硕果累累</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">熊焱教育总经理、学校电竞专业负责人白星亮曾介绍道，&ldquo;开放程度&rdquo;是公司选择与学校合作的重要原因。教练张佳也曾表示，拿了冠军，学校不仅不会分我们的奖金，还会额外给我们奖励。学校的支持能让电竞战队没有了后顾之忧。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-04-23%2019%3A22%3A16%E5%9B%BE%E7%89%871.jpg?Expires=1966072936&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=rUdOd9w3jLE7SZ0T7TvBRnXVt6M%3D" width="650" height="423" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">的确，江西软件职业技术大学由国家软件百强企业先锋软件股份有限公司创办，有着自己天然的优势。学校具有鲜明的职业教育属性和特色，形成了校企命运共同体，坚持&ldquo;校企融合，产学互动&rdquo;的办学模式，这些都为电竞队的成功打下了基础。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">学校先进的理念不仅体现在教育理念和办学思路方面，前沿科技也是其成功的重要因素。与许多战队的训练方式不同的是，在江西软件职业技术大学的电竞基地，区块链技术+电竞早已贯穿日常训练的方方面面，也是学校电竞教育蓬勃发展的重要原因。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">队员们通过&ldquo;区块链+大数据&rdquo;可以提炼并分析训练视频中每位队员的数据，总结经验方法，不断调整训练方式和战术，提升个人能力和团队默契。不仅如此，学校还利用&ldquo;区块链+大数据&rdquo;获得国内外最尖端的科学训练方式，帮助提高电竞战队训练水平；使用数字加密货币打赏，保证电竞队员收益；用智能合约不可更改的特性保障选手的合法权益。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">开放包容，勇立潮头是这所高校的特色，在这里，电竞专业教育寻得了沃土，电竞教育硕果累累。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 14pt; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 18.6667px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased;">继往开来开拓新局</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">尽管江西软件职业技术大学电竞队已取得不俗战绩，从国内的英雄联盟江软王朝慢慢走向世界，但学校并没有停止探索职业教育的步伐，一直在开拓新局。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 14px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 28px; color: #333333; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2022-04-23%2019%3A46%3A09%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220423194604.jpg?Expires=1966074369&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RODD8QrLjJvXaNrXBanR%2B%2BLS4wE%3D" alt="" width="650" height="413" /></span></p>');
INSERT INTO content VALUES (426, '<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; text-indent: 32px; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">人力资源和社会保障部</span><span style="margin: 0px; padding: 0px;">4月27日发布数据显示，今年以来，我国就业局势总体保持基本稳定。从城镇新增就业看，一季度，全国城镇新增就业285万人，完成全年目标的26%；从失业率看，一季度，全国城镇调查失业率平均值为5.5%，与上年同期基本持平。</span></span></p>
<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">　　据人力资源和社会保障部就业促进司副司长陈勇嘉介绍，今年以来，人力资源和社会保障部继续实施一系列阶段性、组合式稳就业保民生政策，进一步加大援企稳岗、技能提升、兜底保障力度，积极助力</span><span style="margin: 0px; padding: 0px;">&ldquo;六稳&rdquo;&ldquo;六保&rdquo;。</span></span></p>
<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">　　首先，持续强化稳企稳岗等就业保障政策。对餐饮、零售、旅游、民航、公路水路铁路运输等特困行业，在今年二季度实施暂缓缴纳养老保险费，将已实施的阶段性缓缴失业和工伤保险费政策范围由餐饮、零售、旅游业扩大至上述行业。一季度，延续实施阶段性降低失业保险费率政策为企业减负</span><span style="margin: 0px; padding: 0px;">347亿元。延续执行失业保险保障阶段性扩围政策，今年年底前继续向参保失业人员发放失业补助金，向参保失业农民工发放临时生活补助。提高中小微企业失业保险稳岗返还比例，符合条件的地区从60%最高提至90%。一季度，向39.3万户企业发放稳岗返还15.7亿元，惠及职工1080万人。符合条件地区再拿出4%失业保险基金结余用于职业技能培训，并向受疫情影响、暂时无法正常经营的中小微企业发放一次性留工培训补助。</span></span></p>
<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">　　其次，促进重点群体就业。实施百万就业见习岗位募集计划，帮助高校毕业生积累经验、提升能力。组织开展公共就业服务进校园活动，提升服务精准度。发布就业创业政策服务指南，便利高校毕业生知晓政策、享受政策。聚焦全年脱贫人口务工规模不低于</span><span style="margin: 0px; padding: 0px;">3000万人，加强对防止返贫监测对象的就业帮扶政策扶持，截至3月底，全国脱贫人口务工规模为3135万人。</span></span></p>
<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">　　与此同时，加强劳动者技能培训。组织实施重点培训工程和计划，深入实施康养职业技能培训计划，推行中国特色企业新型学徒制，进一步加强重点群体和急需紧缺职业（工种）培训，提升培训质量。累计发放职业培训券</span><span style="margin: 0px; padding: 0px;">2278万张。继续放宽失业保险支持技能提升补贴申领条件至参保满1年，一季度向48.7万人次发放技能提升补贴8.3亿元。</span></span></p>
<p style="margin: 10px 0px; padding: 0px; font-size: 12px; font-family: 'Microsoft YaHei'; background-color: #ffffff; line-height: 24px;"><span style="margin: 0px; padding: 0px; font-size: 16px; font-family: 微软雅黑; line-height: 32px;"><span style="margin: 0px; padding: 0px;">　　今年高校毕业生规模达到</span><span style="margin: 0px; padding: 0px;">1076万新高。人力资源和社会保障部表示，将采取多种措施促进高校毕业生就业。&ldquo;今年3月至6月，我们组织开展&lsquo;公共就业服务进校园&rsquo;活动，动员各地人社部门、各类就业服务机构力量，主动将服务向前延伸，通过政策宣传、招聘服务、就业指导、创业服务、职业培训、困难帮扶&lsquo;六进校园&rsquo;，满足毕业生多层次、精准化的服务需求。&rdquo;陈勇嘉表示。</span></span></p>');
INSERT INTO content VALUES (427, '<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff; text-align: center;"><strong>社会保险补贴政策</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策内容</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　高校毕业生灵活就业或自主创业，按规定缴纳社会保险费的，可由就业专项资金对个人缴纳的社会保险费给予补贴，补贴标准为个人缴纳养老、医疗保险费的一定数额，补贴期限灵活就业的2年、自主创业的3年。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策依据</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　省财政厅、省人社厅《关于进一步加强就业专项资金管理有关问题的通知》(赣财社[2012]71号);省政府《关于进一步做好新形势下就业创业工作的实施意见》(赣府发[2015] &nbsp;51号);市人社局、市财政局《关于印发〈新余市促进就业创业政策补贴申报审批办法〉的通知》(余人社字[2015]24号)</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　补贴对象</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、灵活就业的高校毕业生;2、自主创业的高校毕业生。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　补贴标准及期限</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、自主创业的高校毕业生，补贴标准按当地上年度在岗职工平均工资的60%计算，养老保险补贴12%，医疗保险补贴3%，失业保险补贴1%。补贴期限最长不超过3年。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、灵活就业的高校毕业生，补贴标准按照灵活就业困难人员标准给予社保补贴，即按个人缴纳的社会保险费计算(补贴缴费基数不高于在岗职工平均工资的100%)，补贴数额原则上不超过实际缴费的2/3。补贴期限最长不超过2年。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　社会保险补贴申领、拨付程序</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、个人申报。社会保险补贴实行&ldquo;先缴后补&rdquo;的方式，由补贴对象个人向参加社会保险所在地劳动就业服务机构申报社保补贴，并提供以下资料：</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(1)《高校毕业生申领社会保险补贴申请表》;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(2)高校毕业生自主创业工商执照复印件(灵活就业人员提供社区《灵活就业证明》);</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(3)高校毕业生高等院校毕业证及复印件;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(4)高校毕业生本人身份证、社保卡及复印件;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(5)高校毕业生本人《就业失业登记证》或《就业创业证》及复印件;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(6)高校毕业生缴纳社会保险费的原始凭证及复印件。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、就业机构受理。社会保险补贴每季度受理一次，由补贴对象参保所在地劳动就业服务机构对申请人的社会保险补贴申请材料5个工作日内进行验审，验审合格后报人力资源和社会保障部门审核。验审不合格的告之申请人完善相关材料后再行申请。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　3、人社部门审核。人力资源和社会保障部门5个工作日内对就业机构提供的材料进行书面或实地审核，同意后向同级财政部门提请社会保险补贴资金拨付。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　4、财政部门拨付。财政部门接到人力资源和社会保障部门社保补贴拨款申请后进行复核，复核无异后5个工作日内将补贴资金划拨至就业专项资金支出户。就业机构收到补贴资金后及时将社会保险补贴资金拨入申请人在银行开设的基本账户或个人社保卡账户。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">&nbsp;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff; text-align: center;"><strong>一次性求职补贴政策</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策内容</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　家庭困难、就业困难的 &ldquo;双困&rdquo;应届高校毕业生和获得国家助学贷款的应届高校毕业生，毕业年度内给予一次性求职补贴，补贴标准为每人1000元。技师学院高级工班、预备技师班和特殊教育院校职业教育类毕业生可参照高校毕业生享受一次性创业补贴。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策依据</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　省人社厅、省教育厅、省财政厅《关于进一步做好高校毕业生就业管理和服务工作的通知》(赣人社字[2014]64号);《江西省人民政府关于大力推进大众创业万众创新若干政策措施的实施意见》(赣府发[2015]36号)。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　一次性求职补贴对象</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　新余市内普通高校毕业年度内的以下毕业生：①家庭困难高校毕业生(享受城乡居民最低生活保障家庭);②就业困难高校毕业生(身体残疾的高校毕业生);③已获得国家助学贷款的高校毕业生。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　一次性求职补贴申领程序</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、政策公告。每年开学，市内各高校将一次性求职补贴发放对象、标准、申请办法、拨付方式、监督举报电话等内容通过网络、短信(微信)、公告等告知本校应届毕业生。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、个人申请。符合条件的高校毕业生向所在高校就业部门提出申请，并提供以下材料：①《一次性求职补贴申请表》;②城乡最低生活保障证或残疾证明;③本人身份证、学生证、户口本;④银行卡账户。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　3、学校申报。高校就业部门对申请材料进行审核并在本校公示后，向市级公共就业服务机构申报。申请材料包括：①申请求职补贴人员花名册;②求职补贴申请表;③补贴对象申请材料复印件。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　4、就业机构受理。劳动就业机构对高校申报的申请材料进行审核后，报同级人社部门进行复核，并在部门网站公示。公示无异议的向同级财政部门提请拨付一次性求职补贴资金。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　5、财政部门拨付。财政部门按照资金拨付程序将补贴资金拨付至就业专项资金支出账户，由就业机构及时拨付至学生银行卡账户。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff; text-align: center;"><strong>　　<strong>创业担保贷款政策</strong></strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策内容</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　高校毕业生自主创业的，可以申请创业担保贷款，贷款额度最高不超过10万元，由财政全额贴息，贷款期限为2年。符合条件的可给予二次扶持，贷款额度最高不超过30万元;对合伙经营和组织起来创业的最高不超过50万元。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策依据</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　省人社厅、省财政厅、人民银行南昌中心支行《关于完善小额担保贷款政策进一步推动创业促进就业的通知》(赣人社发[2012]48号)、《关于转发〈财政部、人社部、中国人民银行关于加强小额贷款财政贴息资金管理的通知〉的通知》(赣财金[2014]3号);《新余市人民政府关于大力推进大众创业万众创新若干政策措施的意见》(余府发[2015]25号)。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　贷款条件</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、创业项目(含开办网店)在本市行政区域，有稳定的经营场所;2、经工商管理部门登记注册;3、从事个体经营或种养殖业;4、能够落实反担保措施。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　对已经通过小额担保贷款扶持实现成功创业，且按时归还小额担保贷款的，可视其经营扩大和带动就业人数(5人以上)增加情况，提供二次扶持。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　对原已扶持的个人，合伙经营和组织起来创业，创业项目持续经营、扩大或改变的，可视其经营规模、带动就业人数、归还贷款、信用记录、贷款使用效益等情况进行再扶持。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　贷款额度</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　符合个人创业条件的最高限额不超过10万元;符合二次扶持条件的，根据个人信用状况和实际创业成果评估确定，最高限额不超过30万元;符合合伙经营和组织起来创业条件的，根据合伙(组织)人数、经营项目、还贷能力、信用状况等具体情况确定，最高限额不超过50万元。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　贷款期限</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　对上述创业贷款期限为2年。如需提出二次扶持或再扶持，必须是在享受完前一轮扶持政策之后，再按照规定提出申请。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　反担保方式</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、党政机关、财政拨款的事业单位工作人员提供信用担保;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、经济效益较好的企业职工提供信用担保;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　3、资产抵押(建设用地使用权、企业房屋建筑物、个人住宅等);</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　4、有价证券质押(股票、存单、债券、其他有价证券等)。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　申请、放贷程序</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、个人申请。由高校毕业生个人向创业地所在再就业小额担保贷款中心提出贷款申请，并提出以下资料：</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(1)《小额担保贷款申请审批表》及《贷前调查表》;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(2)申请人本人及配偶二代身份证、户口簿、《就业失业登记证》;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(3)个体工商营业执照;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(4)两张一寸免冠照片、婚姻证明;</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(5)《反担保保证人工资收入证明及承诺》(抵押、质押贷款的提供相关证明);</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　(6)反担保保证人二代身份证、三个月工资收入明细原件及复印件。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、小贷中心调查。小额贷款担保中心依据申请人提供的资料对其项目以及反担保保证人真实性进行贷前调查。对于符合条件的申请项目提交审贷会审核，对于不符合条件的由小贷中心告知申请人及反担保保证人不予申报的原因。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　3、经办银行放贷。小贷中心将已通过审贷会审核的贷款项目相关资料送至创业担保贷款经办银行，由经办银行审查相关人员的征信情况。对通过审核的贷款申请人由经办银行组织贷款发放工作。对未通过经办银行审查的贷款申请人，小贷中心将相关情况反馈给贷款申请人及反担保保证人。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　抵押、质押贷款的，由经办银行负责与贷款申请人联系办理固定资产抵、质押手续，手续完成后，经办银行汇票将相关资料转至小额贷款担保中心。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff; text-align: center;"><strong>一次性创业补贴政策</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策内容</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　在校大学生及毕业5年内的高校毕业生，创办企业或从事个体经营，稳定经营1年以上，给予一次性创业补贴，补贴标准为每人5000元。已进行就业创业登记并参加社会保险的，可按灵活就业人员待遇给予社会保险补贴。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　技师学院高级工班、预备技师班和特殊教育院校职业教育类毕业生可参照高校毕业生享受一次性创业补贴。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　政策依据</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　省人社厅等九部门《关于印发江西省大学生创业引领计划实施方案的通知》(赣人社字[2014]364号);《江西省人民政府关于大力推进大众创业万众创新若干政策措施的实施意见》(赣府发[2015]36号);《关于做好困难高校毕业生一次性求职创业补贴和大学生一次性创业补贴发放工作的通知》(赣人社字[2015]355号)。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　一次性创业补贴对象</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　在新余市内创办企业或从事个体经营的以下在校大学生或毕业生：①领取了《就业创业证》;②稳定经营1年以上。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;"><strong>　　一次性创业补贴申领程序</strong></p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　1、个人申请。符合条件的大学生或高校毕业生向注册登记营业场所所在地基层人力资源社会保障事务所提出申请，并提供以下材料：①《一次性创业补贴申请表》;②本人身份证、毕业证(学生证)、《就业创业证》;③创办企业或个体经营的营业执照;④银行账户。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　2、初审。人力资源社会保障所对申请材料进行审查，对高校毕业生创业情况进行实地查看且以照片形式记录。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　3、公示。毕业5年内高校毕业生通过审核的，应在人力资源社会保障所张贴公示并在县级人力资源社会保障部门网站上公示;在校生通过审核的，由所在学校公示。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">　　4、审核拨付。人力资源和社会保障部门对初审材料进行审核，统一向同级财政部门提请拨付一次性创业补贴资金。财政部门按照资金拨付程序将补贴资金拨付至同级人力资源社会保障部门就业专项资金支出账户，由人力资源社会保障部门将补贴资金拨付至申请人银行账户。</p>
<p style="font-family: 'Microsoft YaHei'; font-size: 14px; text-indent: 28px; background-color: #ffffff;">本文来源于<a style="text-decoration-line: none;" href="http://yjbys.com/">http://yjbys.com/</a></p>');
INSERT INTO content VALUES (428, '<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; background-color: #ffffff; color: #7b7f83; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; letter-spacing: 1.5px; text-align: justify; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">深化高校创新创业教育改革要着重把握好以下三点：</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: 1em; letter-spacing: 2px; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-id="7053" data-md5="33145">
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; transform: rotate(0deg); width: 135.391px; height: 5px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-md5="33145">
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; height: 5px; background-color: rgba(17, 92, 193, 0.99); letter-spacing: 2px; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
</section>
<section style="margin: -5px 0px 0px; padding: 20px; outline: 0px; max-width: 100%; background-color: #e8f5fd; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-md5="33145">
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #595959; font-size: 15px; letter-spacing: 2px; line-height: 26.25px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-md5="33145">
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: auto; text-align: justify; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; font-size: 16px; background-color: #ffffff; color: #7b7f83; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">一是坚持育人为本，提高培养质量。面向全体、分类施教、结合专业、强化实践，促进学生全面发展，提升人力资本素质，努力造就大众创业、万众创新的生力军。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: auto; text-align: justify; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: auto; text-align: justify; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; font-size: 16px; background-color: #ffffff; color: #7b7f83; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">二是坚持问题导向，补齐培养短板。丰富课程、创新教法、强化师资、改进帮扶，推进教学、科研、实践紧密结合，突破人才培养薄弱环节，增强学生的创新精神、创业意识和创新创业能力。</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: auto; text-align: justify; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: auto; text-align: justify; line-height: 2em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; font-size: 16px; background-color: #ffffff; color: #7b7f83; box-sizing: border-box !important; overflow-wrap: break-word !important;">三是坚持协同推进，汇聚培养合力。统一领导、齐抓共管、开放合作、全员参与，形成全社会关心支持创新创业教育和学生创新创业的良好生态环境。</span></section>
</section>
</section>
</section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: 1em; text-align: justify; letter-spacing: 2px; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; font-size: 16px; background-color: #ffffff; color: #7b7f83; box-sizing: border-box !important; overflow-wrap: break-word !important;">　</span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: 1em; text-align: justify; letter-spacing: 2px; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: 1em; letter-spacing: 2px; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 16px; background-color: #ffffff; color: #7b7f83; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-family: 宋体; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;">完善人才培养质量标准要做到以下三点：</span></strong></span></section>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; min-height: 1em; text-align: justify; letter-spacing: 2px; line-height: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;"></section>
