INSERT INTO content VALUES (441, '<p style="text-align: center;">高校主赛道本科创意组</p>
<p style="text-align: center;">江西软件职业技术大学</p>
<p style="text-align: center;">团队成员：熊诗琦 王逗豆 雷天诚 邹柳翠 兰雪</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;项目概述：随着全球疫情的蔓延，市场消费能力明显萎缩，餐饮企业面临的环境也相对变得严峻起来。餐饮行业急需改革升级，因此，结合当前形式以及外卖行业的迅速发展，我们提出了以中华美食为主，以云平台为依托，算法匹配餐食，精准分量的新型餐饮业的计划书。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;商业模式：从线上点餐/餐品配送收取的主要费用&nbsp;</p>
<p>（1）制作餐品的费用（包括顾客需求的特色菜系）</p>
<p>（2）餐品配送收取的服务费用</p>
<p>（3）APP会员充值费用</p>
<p>从私厨上门收取的主要费用</p>
<p>（1）私厨上门收取的服务费用</p>
<p>（2）私厨上门收取的布置场景费用</p>
<p>（3）餐后处理收取的费用</p>
<p>（4）特定节假日私厨上门额外收取的服务费用</p>
<p>（5）餐品运送费用</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;市场分析：</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-04%2015%3A57%3A271651650967%281%29.jpg?Expires=1967011047&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=NpcV%2FvpLQIGhZ1exS9ySm0prVWY%3D" alt="" width="627" height="378" /></p>
<p style="text-align: left;">&nbsp; &nbsp; &nbsp;营销策略</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-04%2016%3A00%3A161651651181%281%29.jpg?Expires=1967011216&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=AfRHk%2BpOM%2Bs04OnhMA3J4DVd3IA%3D" /></p>
<p style="text-align: center;">&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (442, '<p style="text-align: center;">作者： 郑乐馨</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 什么是数字音乐；数字音乐即以数字格式存储，以互联网为平台进行传输的音乐，根据中国音像与数字出版协会音乐产业促进工作委员会和中国传媒大学对数字音乐产业的界定，数字音乐产业包含数字音乐、在线K歌、短视频以及泛娱乐直播市场。数字音乐产业已经成为音乐产业的核心产业之一。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 用户调研：用户感知在线音乐现存痛点，科技赋能助力平台发展艾媒咨询数据显示，46.6%的受访原创音乐用户认为原创作品版权保护困难。而5G、8K、区块链等前沿技术，为克服行业痛点提供强有力的技术支撑，助力在线音乐平台发展。人们寄期望与区块链来加强版权的保护。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;市场规模：</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-04%2016%3A09%3A051651651706%281%29.jpg?Expires=1967011745&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RYFDTI1bC0bIxzlEyOfjYIy7ec0%3D" alt="" width="818" height="442" /> 社会价值：打破现有的畸形市场，做出一个真正的音乐平台，让别人主宰流行歌曲变成我觉得这个歌好听，打造出一个良性的音乐生态，进而推动音乐行业的发展。</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (443, '<p style="text-align: center;">江西软件职业技术大学&nbsp; &nbsp;VR与艺术学院&nbsp; &nbsp;胡玮涛</p>
<p style="text-align: center;">万杜鹏&nbsp; &nbsp;虚拟现实应用技术专业 引擎交互方面教师&nbsp;</p>
<p style="text-align: center;">徐盼&nbsp; &nbsp; 虚拟现实应用技术专业 三维建模方面教师&nbsp;</p>
<p style="text-align: center;">胡玮涛&nbsp; &nbsp;交互，UI软件设计&nbsp; &nbsp; &nbsp;团队组织协调者</p>
<p style="text-align: center;">张鲁明&nbsp; &nbsp;交互，数据库方面</p>
<p style="text-align: center;">郭殷起&nbsp; &nbsp;三维建模&nbsp;</p>
<p style="text-align: center;">尹志慧&nbsp; &nbsp;英语资料收集整理</p>
<p style="text-align: left;">&nbsp; &nbsp; &nbsp; &nbsp; 市场前景：2016年9月3日，国家领导人习近平出席了G20工商峰会开幕式并发表主旨演讲，并提到了VR虚拟现实：&ldquo;创新是从根本上打开增长之锁的钥匙。以互联网为核心的新一轮科技和产业革命蓄势待发，人工智能、虚拟现实等新技术日新月异，虚拟经济与实体经济的结合，将给人们的生产方式和生活方式带来革命性变化。&rdquo;</p>
<p style="text-align: left;">&nbsp; &nbsp; &nbsp; &nbsp; 产品介绍：该项目综合应用了虚拟现实技术和英语学习教育系统，将目前现阶段相关英语学习系统的不足之处用虚拟现实技术弥补，还融入了 VR面部表情实时识别系统，使得在进行沉浸式学习时能实时监测上课学习情况，并且虚拟现实技术可以使得学生身临其境和虚拟对象进行英语交流。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;产品特色：英语教育+VR</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;将VR技术嫁接入教育内容，模拟出更立体逼真的英语交流场景。学生只需戴上VR设备，就可以身临其境体验到与现实一样的情境，可以与虚拟对象一起进入课程内容的虚拟情境享受真实感学习与立体感皆强的体验，这种学习体验更易激发学生大脑促成主动去学习。VR技术切入英语在线教育的端口，弥补在线教育空间距离难交互与生动不足的短板。&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; 产品优势</p>
<p style="text-align: center;">：<img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-04%2016%3A39%3A461651653513%281%29.jpg?Expires=1967013586&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=45z210O3z%2FhvRkWbW%2BNfuJRzJIw%3D" alt="" width="831" height="474" /></p>
<p style="text-align: left;">&nbsp; &nbsp; &nbsp; 营销模式：</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-04%2016%3A41%3A321651653646%281%29.jpg?Expires=1967013692&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=wN1MPQlgKZj%2FA6w6zxordQwB6Zw%3D" /></p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (444, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近日，体育总局体育经济司发布关于2020年国家体育产业基地评选结果的公示。先锋创客小镇电子竞技基地被国家体育总局评为&ldquo;国家体育产业示范项目&rdquo;，成为全国唯一电子竞技的国家体育产业示范项目。江西软件职业技术大学成为全国唯一获批&ldquo;国家体育产业示范项目&rdquo;的高校。<br style="box-sizing: border-box;" data-filtered="filtered" /></span></p>
<p style="text-indent: 0em; box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff;" align="justify"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-03-27%2021%3A37%3A58719.png?Expires=1932212278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Acqh77KMWThukjP%2BSD4aB9gb7zw%3D" alt="" width="800" height="479" /></p>
<p style="text-indent: 0em; box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff;" align="justify"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-03-27%2021%3A37%3A58735.png?Expires=1932212278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=64jNx9tVutBuAfF6kows4m3ki6U%3D" alt="" width="800" height="657" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">先锋创客小镇电子竞技基地坐落于江西软件职业技术大学内，以学校开设的电子竞技运动与管理专业为支撑,主要培养学生掌握电子竞技基本理论及实践能力，为电竞行业培养电子竞技运动竞赛运动员、教练、裁判、主持、主播、赛事（活动）组织与管理岗位的高素质技术技能人才。基地内还建立了电竞人才数据库，力求用最专业的培养体系，打造出最强的电竞人才孵化基地。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">基地自2016年&ldquo;诞生&rdquo;以来，取了辉煌的成绩。多名全国知名电竞选手被聘为基地客座教授；多次承办省内大型电竞比赛；曾代表江西，参加2020中国体育文化博览会暨中国体育旅游博览会。更值得一提的是，基地的HMG战队凭借自身强大的实力赢得了数十个全国比赛冠军；蝉联了2019年、2020年两届世界大学生电子竞技联赛世界冠军。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近几年来，江西软件职业技术大学在全国乃至世界高校电竞圈的卓越表现，也在一定程度上推动了江西省电竞项目和电竞产业地快速发展，为经济社会发展贡献一份力量。</span></p>');
INSERT INTO content VALUES (445, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近日，体育总局体育经济司发布关于2020年国家体育产业基地评选结果的公示。先锋创客小镇电子竞技基地被国家体育总局评为&ldquo;国家体育产业示范项目&rdquo;，成为全国唯一电子竞技的国家体育产业示范项目。江西软件职业技术大学成为全国唯一获批&ldquo;国家体育产业示范项目&rdquo;的高校。<br style="box-sizing: border-box;" data-filtered="filtered" /></span></p>
<p style="text-indent: 0em; box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff;" align="justify"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-03-27%2021%3A37%3A58719.png?Expires=1932212278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Acqh77KMWThukjP%2BSD4aB9gb7zw%3D" alt="" width="800" height="479" /></p>
<p style="text-indent: 0em; box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff;" align="justify"><img style="box-sizing: border-box; border: 0px; vertical-align: baseline; margin: 5px auto; padding: 0px; list-style-type: none; -webkit-font-smoothing: antialiased; filter: saturate(0.75); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/2021-03-27%2021%3A37%3A58735.png?Expires=1932212278&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=64jNx9tVutBuAfF6kows4m3ki6U%3D" alt="" width="800" height="657" /></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">先锋创客小镇电子竞技基地坐落于江西软件职业技术大学内，以学校开设的电子竞技运动与管理专业为支撑,主要培养学生掌握电子竞技基本理论及实践能力，为电竞行业培养电子竞技运动竞赛运动员、教练、裁判、主持、主播、赛事（活动）组织与管理岗位的高素质技术技能人才。基地内还建立了电竞人才数据库，力求用最专业的培养体系，打造出最强的电竞人才孵化基地。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">基地自2016年&ldquo;诞生&rdquo;以来，取了辉煌的成绩。多名全国知名电竞选手被聘为基地客座教授；多次承办省内大型电竞比赛；曾代表江西，参加2020中国体育文化博览会暨中国体育旅游博览会。更值得一提的是，基地的HMG战队凭借自身强大的实力赢得了数十个全国比赛冠军；蝉联了2019年、2020年两届世界大学生电子竞技联赛世界冠军。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border: 0px; font-size: 16px; font-family: 'Microsoft YaHei'; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; line-height: 2em; color: #333333; background-color: #ffffff; text-align: justify; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; font-size: 15px; list-style-type: none; vertical-align: baseline; -webkit-font-smoothing: antialiased; color: #564059;">近几年来，江西软件职业技术大学在全国乃至世界高校电竞圈的卓越表现，也在一定程度上推动了江西省电竞项目和电竞产业地快速发展，为经济社会发展贡献一份力量。</span></p>');
INSERT INTO content VALUES (446, '<p style="text-align: center;">江西软件职业技术大学 星原队</p>
<p style="text-align: center;">职教赛道 创意组</p>
<p style="text-align: center;">中国农特产品区块链可信溯源第一链</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;市场背景&mdash;政策背景：习总书记在中央政治局第十八次集体学习时强调：把区块链作为核心技术自主创新重要突破口，加快推动区块链技术和产业创新发展。</p>
<p>探索&ldquo;区块链+&rdquo;在民生领域的运用，积极推动区块链技术在教育、就业、养老、精准脱贫、医疗健康、商品防伪、食品安全、公益、社会救助等领域的应用。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 市场背景&mdash;行业背景：近年，我国柚类作物平均种植面积约140万亩，产量呈逐年上升趋势。我国柚子自2003年开始产量快速增长，2018年国内柚子产量突破500万吨。</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-05%2016%3A14%3A121651738401%281%29.jpg?Expires=1967098452&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=x2v5CG5XfB2nj90oM5W60zkqoHg%3D" alt="" width="844" height="476" /></p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-05%2016%3A15%3A141651738401%281%29.jpg?Expires=1967098515&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=BwIBBp81rfBaHau5iiM30XRUd6w%3D" alt="" width="844" height="476" /></p>
<p>&nbsp;</p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (458, '<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-role="title" data-tools="135编辑器" data-id="85822">
<section style="margin: 0px auto; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 10px 0px; outline: 0px; max-width: 100%; box-sizing: border-box; width: 677px; display: inline-block; visibility: visible; overflow-wrap: break-word !important; border: 2px solid #000000;" data-width="100%">
<section style="margin: 20px 0px 0px; padding: 4px 20px; outline: 0px; max-width: 100%; box-sizing: border-box; display: inline-block; border-bottom: 1px solid #000000; visibility: visible; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px 0px 0px 10px; outline: 0px; max-width: 100%; box-sizing: border-box; display: inline-block; vertical-align: top; visibility: visible; overflow-wrap: break-word !important;">
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; text-align: center; vertical-align: inherit; line-height: normal; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #000000; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">01&nbsp;</span></strong><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #000000; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">第八届大赛的背景和目标是什么？</span></strong></span></p>
</section>
</section>
<section style="margin: 10px 0px 0px; padding: 20px; outline: 0px; max-width: 100%; box-sizing: border-box; visibility: visible; overflow-wrap: break-word !important;">
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; text-align: left; vertical-align: inherit; line-height: 1.5em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; letter-spacing: 1px; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #333333; font-size: 14px; caret-color: red; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">为深入贯彻落实习近平总书记关于教育的重要论述和给第三届中国&ldquo;互联网＋&rdquo;大学生创新创业大赛&ldquo;青年红色筑梦之旅&rdquo;的大学生回信精神，落实《国务院办公厅关于深化高等学校创新创业教育改革的实施意见》《国务院办公厅关于进一步支持大学生创新创业的指导意见》等文件精神，全面深化高校创新创业教育改革、提升大学生创新创业能力、加快培养创新创业人才，纵深推进大众创业万众创新。</span></span></p>
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; vertical-align: inherit; line-height: 1.5em; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; visibility: visible; box-sizing: border-box !important; overflow-wrap: break-word !important;">本届大赛总体目标，更中国、更国际、更教育、更全面、更创新，传承和弘扬红色基因，聚焦&ldquo;五育&rdquo;融合创新创业教育实践，激发青年学生创新创造热情，线上线下相融合，打造共建共享、融通中外的国际创新创业盛会，开启创新创业教育改革新征程。</span></p>
</section>
</section>
</section>
</section>
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; vertical-align: inherit; box-sizing: border-box !important; overflow-wrap: break-word !important;">&nbsp;</p>
<section style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #222222; font-family: -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; background-color: #ffffff; box-sizing: border-box !important; overflow-wrap: break-word !important;" data-role="title" data-tools="135编辑器" data-id="85822">
<section style="margin: 0px auto; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 10px 0px; outline: 0px; max-width: 100%; box-sizing: border-box; width: 677px; display: inline-block; overflow-wrap: break-word !important; border: 2px solid #000000;" data-width="100%">
<section style="margin: 20px 0px 0px; padding: 4px 20px; outline: 0px; max-width: 100%; box-sizing: border-box; display: inline-block; border-bottom: 1px solid #000000; overflow-wrap: break-word !important;">
<section style="margin: 0px; padding: 0px 0px 0px 10px; outline: 0px; max-width: 100%; box-sizing: border-box; display: inline-block; vertical-align: top; overflow-wrap: break-word !important;">
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; text-align: center; vertical-align: inherit; line-height: normal; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 18px; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #000000; box-sizing: border-box !important; overflow-wrap: break-word !important;">02&nbsp;</span></strong><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; color: #000000; box-sizing: border-box !important; overflow-wrap: break-word !important;">第八届大赛赛事安排是什么？</span></strong></span></p>
</section>
</section>
<section style="margin: 10px 0px 0px; padding: 20px; outline: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important;">
<p style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; clear: both; min-height: 1em; text-align: left; vertical-align: inherit; line-height: 1.5em; box-sizing: border-box !important; overflow-wrap: break-word !important;"><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; color: #548dd4; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">4月</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">正式启动大赛，</span><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; color: #548dd4; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">4月下旬</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">举行&ldquo;青年红色筑梦之旅&rdquo;活动全国启动仪式，</span><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; color: #548dd4; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">6&mdash;8月</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">举行校赛、省赛，</span><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; color: #548dd4; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">10月</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">举行</span><strong style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;"><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; color: #548dd4; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">总决赛</span></strong><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">。本届大</span><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">赛</span><span style="margin: 0px; padding: 0px; outline: 0px; max-width: 100%; font-size: 14px; color: #333333; text-decoration-style: solid; text-decoration-color: #333333; letter-spacing: 1px; font-family: 微软雅黑, 'Microsoft YaHei', sans-serif; box-sizing: border-box !important; overflow-wrap: break-word !important;">将进一步加大国际参赛的邀请力度，广泛动员国外名校参赛，总决赛期间国内外学生同场竞技。结合新冠肺炎疫情防控要求，制定线下和线上线下相结合两套实施方案，根据疫情防控形势和要求适时转换。</span></p>
</section>
</section>
</section>
</section>');
INSERT INTO content VALUES (468, '<p class="p" style="margin: 0pt; padding: 0pt;"><span class="15" style="font-family: 'Times New Roman'; font-size: 15pt;"><span style="font-family: 宋体;">赛事篇</span></span></p>
<p class="MsoNormal"><span style="font-family: Calibri; font-size: 10.5pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">01&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">第八届大赛的背景和目标是什么？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 宋体;">为深入贯彻落实习近平总书记关于教育的重要论述和给第三届中国</span></span><span style="font-family: Calibri; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;">&ldquo;</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 宋体;">互联网＋</span></span><span style="font-family: Calibri; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;">&rdquo;</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 宋体;">大学生创新创业大赛</span></span><span style="font-family: Calibri; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;">&ldquo;</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 宋体;">青年红色筑梦之旅</span></span><span style="font-family: Calibri; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;">&rdquo;</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 宋体;">的大学生回信精神，落实《国务院办公厅关于深化高等学校创新创业教育改革的实施意见》《国务院办公厅关于进一步支持大学生创新创业的指导意见》等文件精神，全面深化高校创新创业教育改革、提升大学生创新创业能力、加快培养创新创业人才，纵深推进大众创业万众创新。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">本届大赛总体目标，更中国、更国际、更教育、更全面、更创新，传承和弘扬红色基因，聚焦</span></span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;">&ldquo;五育&rdquo;融合创新创业教育实践，激发青年学生创新创造热情，线上线下相融合，打造共建共享、融通中外的国际创新创业盛会，开启创新创业教育改革新征程。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: justify; background: #ffffff;" align="justify"><span style="font-family: 微软雅黑; color: #222222; letter-spacing: 0.4pt; font-size: 12.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">02&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">第八届大赛赛事安排是什么？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">4月</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">正式启动大赛，</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">4月下旬</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">举行</span>&ldquo;青年红色筑梦之旅&rdquo;活动全国启动仪式，</span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">6&mdash;8月</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">举行校赛、省赛，</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">10月</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">举行</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">总决赛</span></span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。本届大赛将进一步加大国际参赛的邀请力度，广泛动员国外名校参赛，总决赛期间国内外学生同场竞技。结合新冠肺炎疫情防控要求，制定线下和线上线下相结合两套实施方案，根据疫情防控形势和要求适时转换。</span></span></p>');
INSERT INTO content VALUES (469, '<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">03&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">第八届大赛参赛项目类型与分组有什么优化？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">根据参赛申报人所处学习阶段，高教主赛道分设为本科生组和研究生组</span></span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，并根据所处创业阶段，本科生组和研究生组内均内设创意组、初创组、成长组。</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">高教主赛道的参赛项目类型调整为新工科类、新医科类、新农科类、新文科类</span></span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，旨在贯彻落实全国高校优化学科专业结构，深化创新创业教育改革。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">04&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">第八届大赛参赛人员年龄限制有什么新变化？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">规定参赛人员年龄</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不超过</span>35岁</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">（</span>1987年3月1日之后出生），进一步突出大学生创新创业大赛的赛事特色。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: justify; background: #ffffff;" align="justify"><span style="font-family: 微软雅黑; color: #222222; letter-spacing: 0.4pt; font-size: 12.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">05&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">第八届大赛入围总决赛项目数有什么变化？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">本届大赛入围总决赛项目数</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">增至</span>3500个</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">（港澳台地区参赛名额单列）。其中高教主赛道</span>2000个（国内项目1500个、国际项目500个）、&ldquo;青年红色筑梦之旅&rdquo;赛道500个、职教赛道500个、萌芽赛道200个、产业命题赛道300个。</span></p>');
INSERT INTO content VALUES (470, '<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">06&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">验证个人信息时显示</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">您的信息未通过学籍验证</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">，该怎么办？如何修改？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">学生填写的个人信息应与学信网上的学籍信息保持一致（尤其是学历层次、所在院校、入学时间、毕业时间），才可验证通过（可填写非最高学籍信息）。若提示未通过验证，学生可登录学信网（</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">https://www.chsi.com.cn/</span></strong><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">）查看个人学籍信息后，登录大赛报名官网，在个人中心的设置板块中修改学籍信息，提交后重新认证。如对学籍学历有疑问，可发送咨询邮件至</span>kefu@chsi.com.cn，进行咨询。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">07&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">什么学籍学历可以报名参加大赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在校或毕业</span>5年内的中职中专、高职高专、职业教育本科、普通本科、博硕士研究生、国家开放大学学历教育学生均可参加大赛。但各赛道及赛道内各组别对参赛对象的学籍学历有不同要求，报名时请按照不同赛道、不同组别的学籍学历要求进行报名参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">08&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">中职中专学历，学信网无学籍学历信息，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">完善个人信息页所填写的学历层次为中职中专时提交申请，无需进行学籍学历校验，即可通过既定流程（参考《学生操作手册》）完成报名参赛或被邀请成为项目团队成员。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">09&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">已经完成注册并完善个人信息，如何判断自己的学籍学历信息是否需要通过校验？如需校验，是否已通过校验？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">登录大赛官网，进入个人中心，个人头像及姓名旁边如出现绿底白字的</span>&ldquo;学籍校验通过&rdquo;，表示学籍学历通过验证可以参赛；如出现红底白字&ldquo;学籍校验不通过&rdquo;，表示学籍学历未通过验证，重新认证方法参见《常见问题》第6条或《学生操作手册》最后一页内容；如未出现任何学籍校验信息，表示无需进行学籍学历校验，可通过既定流程参赛（参考《学生操作手册》）。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;">&nbsp;</p>');
INSERT INTO content VALUES (471, '<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">18&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">报名高教主赛道本科生组创意组、研究生组创意组的项目团队成员有什么限制？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">团队成员中有普通高等学校全日制在校研究生的项目不能报名参加高教主赛道本科生组创意组，只能报名参加高教主赛道研究生组创意组。但均需符合所报赛道及组别的参赛要求。</span></span><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><br /></span><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">如：团队负责人为普通高等学校全日制在校本科生或专科生，但团队成员有普通高等学校全日制研究生，则不能报名参加高教主赛道本科生组创意组，只能报名参加研究生组创意组。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">19&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">大赛通知内</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">大赛通知下发之日</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">具体指哪天？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;">&ldquo;大赛通知下发之日&rdquo;指大赛通知印发日，即2022年4月8日。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">20&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">什么是学校科技成果转化项目？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">学校科技成果转化项目是指</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">创业团队所使用核心科技成果的所有权是学校</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">的项目。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">21&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">我们学校没有关于大赛的通知，也暂未有老师组织比赛，我可以参赛么？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">可以，如需审核协助，请联系学校的创业学院、教务处、就创业工作部门。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">22&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">由于学校名称变更、就读于学校分校区导致的学籍学历校验不通过，怎么办？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">请联系所在省市负责人，省市负责人将统一汇总问题交由大赛组委会处理，各省联系方式详见</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">https://cy.ncss.cn/provincecontact</span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">23&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">创建项目的时候没找到自己所在的学校怎么办？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">此情况须联系所在高校负责大赛的老师，由学校联系省级负责人，并由省级负责人统一联系大赛组委会，由大赛组委会统一处理。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">24&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">肄业</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">/</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">休学</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">/</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">退学导致的学籍学历校验不通过，怎么办？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">须提供</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">之前就读学校的就读证明</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">（证明该生曾在该校就读，提供姓名</span>+身份证号+登录账号）并加盖公章，将扫描件发送到指定的邮箱。通过官方微信公众号（&ldquo;中国互联网十大学生创新创业大赛&rdquo;）进行咨询，并获取指定的邮箱。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">25&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">国际参赛项目到哪里去报名？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">国际参赛项目通过全球青年创新领袖共同体促进会官网（</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">www.pilcchina.org</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">）进行报名。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">26&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">大赛的参赛顺序是什么样的（大赛赛制）？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">大赛主要采用校级初赛、省级复赛、总决赛三级赛制（不含萌芽赛道及国际项目）。校级初赛由各院校负责组织，省级复赛由各省（区、市）负责组织，通过各省推荐，进入总决赛。如对校级比赛、省级比赛有疑问，请咨询所在的高校或所在省市的相关负责人。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">27&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">如何报名参赛？开始及截止日期？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">参赛团队通过登录</span>&ldquo;全国大学生创业服务网&rdquo;（</span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">https://cy.ncss.cn</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">）或微信公众号（名称为</span>&ldquo;全国大学生创业服务网&rdquo;或&ldquo;中国互联网十大学生创新创业大赛&rdquo;）任一方式进行报名。报名系统</span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">开放时间为</span>2022年4月15日</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">截止时间由各地根据复赛安排自行决定</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，但</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不得晚于</span>7月31日</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">28&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目报名参赛过程中需要提供的材料有哪些？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">报名参赛的流程以及需要提供的材料，可以参考全国大学生创业服务网（</span>https://cy.ncss.cn）首页&mdash;&mdash;资料下载&mdash;&mdash;《学生操作手册》。如想了解的更清楚，可登录全国大学生创业服务网（https://cy.ncss.cn）体验网上报名流程。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">29&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">参赛项目只能限于</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">互联网</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">+&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">参赛项目不只限于</span>&ldquo;互联网+&rdquo;项目，组委会鼓励各类创新创业项目参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">30&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目计划书有格式或固定模板要求吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">没有，参赛者可根据自身项目情况、评审要求等准备项目计划书。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">31&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">如何创建项目？团队成员也需要创建项目吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">请查看</span></span><strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">《</span></span></strong><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">学生操作手册</span></span></strong><strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">》</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">了解创建项目的具体操作流程。仅团队负责人进行创建项目即可，团队成员无需创建项目。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">32&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">团队负责人如何添加团队成员？添加的团队成员按照什么规则排序？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">请查看全国大学生创业服务网（</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">https://cy.ncss.cn</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">）资料下载板块的《</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">学生操作手册</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">》。添加的团队成员可通过编辑进行排序。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">33&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">参赛项目团队的人数有何限制？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">大赛以团队为单位报名参赛。每个团队的参赛成员</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不少于</span>3人</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不多于</span>15人</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">（含团队负责人），须为项目的实际核心成员。项目可根据自身情况添加团队成员。到现场参加总决赛现场赛的参赛成员应为</span>3-5人（含团队负责人）。届时会提醒团队，在系统内勾选确认现场赛的成员。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">34&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">学生能否跨校组队参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">允许</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">跨校组建团队，项目归属参赛团队负责人所在院校。其中，校赛和省赛由各学校和各省自行组织安排，如果校赛或省赛不允许跨校组队，请向各省联系人咨询（各省联系方式详见</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;">https://cy.ncss.cn/provincecontact</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">）。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">35&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">院校老师可以作为项目的团队成员吗？项目团队的指导教师有何限制？添加的指导教师按照什么规则排序？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">除产业命题赛道外，院校老师不可作为项目的团队成员参赛，只能作为指导教师参与大赛。</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">大赛不要求团队一定要有指导教师，并且人数上没有限制。建议项目团队在与老师沟通后自行决定是否添加指导教师。添加的指导老师可通过编辑进行排序。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">36&nbsp;&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">青年红色筑梦之旅</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">活动和</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">青年红色筑梦之旅</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">赛道是什么关系？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">活动是活动，赛道是赛道，是两回事情。不论是否参赛、不论何种学历层次，只要在全国大学生创业服务网上创建了项目，均可报名参加</span>&ldquo;青年红色筑梦之旅&rdquo;活动。但是要参加&ldquo;青年红色筑梦之旅&rdquo;赛道的项目则必须要参加&ldquo;青年红色筑梦之旅&rdquo;活动（参加青年红色筑梦之旅赛道的要求详见大赛通知）。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">37&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目可以参加多个赛道吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">项目</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">只能选择参加一个赛道</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">进行报名参赛，具体要求详见大赛通知。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">38&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">已获往届中国国际</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">互联网</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">+&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">大学生创新创业大赛总决赛各赛道金奖和银奖的项目今年可继续参赛吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不可以，但是项目可参加</span>&ldquo;青年红色筑梦之旅&rdquo;活动。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">39&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">一个人可以报多个项目吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">作为项目的团队负责人可以</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">最多创建</span>3个项目</span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，且只能使用</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">一个项目报名参赛</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，但可同时作为其他项目的团队成员报名参赛。同一个人可以作为多个项目的团队成员。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">40&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">一个公司可以报多个项目参赛吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">一个公司只能作为一个整体，作为一个项目参赛，</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">不可</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">将一个公司的业务拆分为几个项目报名参赛。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">41&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">若项目设立了公司或社会组织需提交什么材料？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">除填写公司或社会组织的基本材料外，还需提供公司或社会组织版财务报表，请登录全国大学生创业服务网下载模板，并按照模板要求填写。具体操作及填报流程请参见学生操作手册。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">42&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">因为某些原因不小心填错项目的参赛赛道、参赛组别、参赛类别，是否能重新报名？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">可以</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。在报名系统关闭前（</span>2022年7月31日前），在个人中心，将原有参赛项目&ldquo;取消参赛&rdquo;后重新报名参赛。请注意，已报名参赛项目可能已经通过校级、省级审核，所以请在&ldquo;取消报名&rdquo;前，联系所在院校及省市，以免影响项目参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">43&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">创建项目成功之后想修改项目名称怎么办？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">项目一旦创建完成无法修改项目名称，如果需更改项目名称，要删除项目重新创建</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。（如果项目已通过审核进入校赛或者省赛，删除后项目会回到待审核状态。请谨慎操作，删除项目前须及时和学校或者省里联系，以便在删除项目后，重新申报的项目可以再次进行审核，以免影响项目参赛）。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">44&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">想修改项目计划书和其它与项目有关的信息怎么办？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">如需修改，请直接点击个人中心，项目右上角的</span>&ldquo;编辑&rdquo;按钮，进行重新上传计划书（项目计划书名称为系统默认，重新上传后项目名称不会变化，可通过下载计划书查看并确认是否修改成功），以及其他信息，并点击&ldquo;保存&rdquo;按钮。如对操作有疑问，可以在官网上下载学生操作手册。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">45&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目涉及的知识产权信息需要填报吗？项目曾经获得过国家级或省部级奖项信息需要填报吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">均需要填报</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。知识产权信息包括：专利、论文、软件著作权、作品著作权、商标信息。曾获奖项举例：国家自然科学奖一等奖、重庆市技术进步奖一等奖。</span></span><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><br /></span><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">以上填报的信息须与项目计划书涉及的内容保持一致。具体操作及填报流程请参见学生操作手册。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">46&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">为什么要填写财务以及知识产权等信息？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">提交此类信息，主要便于各省市高校通过集中化、技术化等方法审核参赛项目的真实性。全国组委会对于入围国赛的项目也将据此通过权威技术手段展开严格的真实性审核，并要求所提交的各类信息与网评、现场赛所展示呈现的此类信息保持一致。</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">各级组委会将对项目所提交的信息进行严格保密</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">47&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">如何获取校赛、省赛的比赛进度？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">校赛和省赛都是由各院校和各省市自行安排比赛时间，把握比赛的进度。建议团队在报名成功后及时与院校或省市负责人取得联系，获取校赛及省赛的准确时间，以免影响参赛。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">48&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目的晋级情况是怎么回事？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">项目报名参赛成功后，学校与省市将根据项目的晋级情况给项目设置对应的状态。如对项目晋级情况存在疑问，可联系所在院校或省市。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">49&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">项目一直处于</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&ldquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">学校待审核</span></span></strong><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">&rdquo;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">的状态，是怎么回事？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">你的项目已报名成功，进入学校的审核，如有疑问，请联系学校跟进审核情况，避免影响参赛。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">50&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">为什么在报名不成功的时候，总是提示我某几项信息不对，我已经检查了好几遍了，实在找不出问题在哪里？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">报名系统会非常具有针对性的将你不符合要求的项提示出来。报名前请务必查看各赛道、各组别的具体要求。一般可能出问题的项有：学籍学历验证没通过、年龄限制、公司注册年限、毕业时间、是否注册公司等项。如上述均不存在问题，请通过官方微信公众号进行咨询。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">51&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">国外学生是否可以作为团队成员参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">国外学生</span></span><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">可以</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">作为团队成员参赛。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">52 &nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">学生在国外院校本科或硕士毕业，现为国内院校硕士或博士在校生，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在符合高教主赛道及组别的参赛要求的前提下，学生如作为参赛项目团队负责人，须以国内院校在读的学籍代表国内院校参加高教主赛道的</span>&ldquo;中国大陆参赛项目&rdquo;。学生如作为参赛项目团队成员，则根据团队负责人选定的方式参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">53&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">学生在国内院校本科或硕士毕业，现为国外院校硕士或博士在校生，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在符合高教主赛道及组别的参赛要求的前提下，学生如作为参赛项目团队负责人，须以国内院校在读的学籍代表国内院校参加高教主赛道的</span>&ldquo;中国大陆参赛项目&rdquo;。学生如作为参赛项目团队成员，则根据团队负责人选定的方式参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">54&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">学生参加国内与国外院校联合培养，同时具有国内外两所院校的学籍，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在符合高教主赛道及组别的参赛要求的前提下，学生如作为参赛项目团队负责人，可以国内院校在读的学籍代表国内院校参加高教主赛道的</span>&ldquo;中国大陆参赛项目&rdquo;；也可以国外院校在读的学籍代表国外院校参加高教主赛道的&ldquo;国际参赛项目&rdquo;。学生如作为参赛项目团队成员，则根据团队负责人选定的方式参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">55&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">参赛人已毕业，同时具有国内外两所院校的学历，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在符合高教主赛道及组别的参赛要求的前提下，参赛人如作为参赛项目团队负责人，可以国内院校的学历代表国内院校参加高教主赛道的</span>&ldquo;中国大陆参赛项目&rdquo;；也可以国外院校的学历代表国外院校参加高教主赛道的&ldquo;国际参赛项目&rdquo;。参赛人如作为参赛项目团队成员，则根据团队负责人选定的方式参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">56&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">参赛人已在国外院校毕业，没有国内院校就读经历，如何参赛？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">在符合高教主赛道及组别的参赛要求的前提下，参赛人如作为参赛项目团队负责人，可以国外院校的学历代表国外院校参加高教主赛道的</span>&ldquo;国际参赛项目&rdquo;。参赛人如作为参赛项目团队成员，则根据团队负责人选定的方式参赛。</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt;"><span style="font-family: Calibri; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; text-align: center;" align="center"><strong><span style="font-family: 'Times New Roman'; letter-spacing: 0pt; font-size: 13.5pt;">57&nbsp;</span></strong><strong><span style="font-family: 宋体; letter-spacing: 0pt; font-size: 13.5pt;"><span style="font-family: 宋体;">中国大陆学生到港澳台地区院校就读，希望使用港澳台地区院校在校生或毕业生身份报名参赛，可以吗？</span></span></strong></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><strong><span style="font-family: 微软雅黑; color: #548dd4; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">可以</span></span></strong><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;"><span style="font-family: 微软雅黑;">，但中国大陆学生无港澳台地区身份需使用大陆身份证注册，注册完成并完善个人信息后不能通过港澳台地区院校的学籍校验，无法报名参赛。此时需要学生所在港澳台地区院校出具其在校就读证明并加盖公章，将扫描件连同学生姓名、身份证号及登录账号一同发送到指定邮箱。请通过官方微信公众号（</span>&ldquo;中国互联网十大学生创新创业大赛&rdquo;）进行咨询，获取指定的邮箱。</span></p>
<p class="MsoNormal"><span style="font-family: Calibri; font-size: 10.5pt;">&nbsp;</span></p>');
INSERT INTO content VALUES (472, '<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">壹</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">活动简介</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; 2022</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">4</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">月</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">12</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">日，根据《退役军人事务部办公厅关于组织推荐</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">全国退役军人创业光荣榜</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">上榜名单的通知》</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">(</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">退役军人办电〔</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2020</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">〕</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">77</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">号</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">)</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">和《退役军人事务部办公厅关于组织推荐</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">全国退役军人就业合作光荣榜</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">、</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">全国退役军人创业光荣榜</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">上榜名单的通知》</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">(</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">退役军人办电〔</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2021</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">〕</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">136</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">号</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">)</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">要求，我省于</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2020</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年和</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2021</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年分别组织各地开展了遴选推荐工作，经江西省退役军人事务厅</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2022</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年第</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">次厅长办公会议研究决定，同意南昌市陈苏等</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">29</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">名退役军人上榜江西省退役军人优秀创业者人物榜，并将在第二届江西省退役军人</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">永远跟党走</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">建功新时代</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">主题活动中进行颁奖和宣传。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">贰</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">上榜名单</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp;&nbsp;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">先锋软件集团董事长、学校创始人、退役军人教育学院创业导师陈苏上榜江西省退役军人优秀创业者人物榜。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;">&nbsp;</p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-06%2010%3A17%3A441651803382%281%29.jpg?Expires=1967163464&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=0tg7I2qK6ak8u%2Fze%2BwByBiO3q2Y%3D" alt="" width="760" height="907" /></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt; text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-06%2010%3A12%3A56%E5%9B%BE%E7%89%872.png?Expires=1967163176&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Q4ji10D7VoX8exDBjlR9058HrrQ%3D" /></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">叁</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">董事长简介</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt; text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-06%2010%3A13%3A36%E5%9B%BE%E7%89%873.png?Expires=1967163216&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=ETPXbmpztKjp9TUedgmodVutAtE%3D" /></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">陈苏，先锋软件集团董事长、党委书记，江西软件职业技术大学创始人。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; 1976</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">12</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">月，陈苏满怀报国之志应征入伍。五年芳华，在部队这所大融炉，他百炼成钢，将</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">强军强国必须强科技</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">的夙愿耕植于心。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; </span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">秉承退役不退色的开拓和信仰，退伍后的陈苏，一直赓续信息技术服务国家产业发展、服务社会的初心，倾心倾力于信息产业领域深耕发展，砥砺前行。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">1994</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年创办先锋软件集团；</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2003</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，创办江西先锋软件职业技术学院，后升本改大更名为江西软件职业技术大学。多年来，学校以国产软件为核心，在交通、能源、卫生、教育以及智慧城市等领域为社会累计培养了</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">10</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">万余软件优秀人才。企业累计带动就业</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">1331</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">人，其中三分之一以上为退役军人。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2019</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，南昌市退役军人创业孵化示范基地落户江西软件职业技术大学。陈苏董事长本人曾获评</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">江西改革开放三十年优秀企业家</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">、</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">江西改革开放四十年杰出企业家</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">等荣誉称号，并曾当选第十一、十二、十三次江西省党代会代表，第八、第九、第十届江西省政协委员，第十三届江西省人大代表，第九、第十、第十一届江西省工商联副主席。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">肆</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">筚路蓝缕创伟业，不忘初心铸军魂</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; 1994</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，凭借区区</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">1</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">万元资金，陈苏和</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">个退役军人一起创办了先锋软件集团。创业初期，陈苏将软件与监控、通讯技术进行融合形成</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">先锋</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">AHEAD</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">公路收费监控系统</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">，改变了我国当时国道和高速公路人工收费的原始模式，开创并促进了我国智慧交通的建设与大发展。本世纪初，陈苏在我国信息化建设浪潮中力排众议，联合国内众多知名国产软硬件厂商研发出</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">基于国产软硬件技术的先锋</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">KRM</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">电子政务解决方案</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">，长期服务于我国政府信息化建设，在</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2003</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年胡锦涛总书记近一个小时视察先锋集团时，得到总书记的高度评价和鼓励支持。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp;2003</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，为了更好地实现</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">产学研一体化</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">，为国家大面积培养软件人才，陈苏再次扬帆远航，克服重重困难，创办了江西先锋软件职业技术学院并成功入选全国</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">35</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">所示范性软件职业技术学院；</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2018</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，升格为本科层次职业院校；</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2019</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，更名为江西软件职业技术大学，是全国首批</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">15</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">所本科层次职业教育试点院校，也是全国第一所软件职业技术大学。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">进入</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">十三五</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">期间，在云计算、物联网、人工智能等新一代信息技术风起云涌的大发展时期，陈苏敏锐察觉到区块链技术将会为未来信息技术产业发展带来颠覆性变革，又一次抢占先机，于</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2015</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年即着手区块链技术研究与创新，执着地推动区块链技术的发展与应用，并于</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2019</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">6</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">月组建了全球第一所区块链本科学院，亲任院长。招收了全球第一批区块链本科专业学生，为高层次高水平的区块链人才培养作出了积极贡献。目前，区块链技术正应用于吉安数字农业产业发展，井冈蜜柚成功通过区块链</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">飞入寻常百姓家</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; 2019</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，期盼以久的南昌市退役军人创业孵化示范基地在江西软件职业技术大学落户，借助先锋软件集团和江西软件大学的智力和市场资源，</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">先锋退役军人就业创业园地</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">为入驻的退役军人创业者提供各项服务，为退役军人创业</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">铺路搭桥</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">，发挥其在全市退役军人创业孵化基地建设中的示范引领作用。基地拥有</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">20</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">余项专业技能证书考试及培训资格，可颁发国家教育部统招全日制大专及全日制统招本科学历，是</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2020</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年度江西省退役士兵职业教育和技能培训定点承训机构。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">同时，筹建南昌市退役军人就业创业促进会，以帮助退役军人就业创业为目的，搭建政府与社会、军队与地方、退役军人与爱心企业的合作平台，协助政府部门做好退役军人就业创业服务工作，为国防和军队建设改革聚力，为政府促就业保民生工作解难，为维护社会稳定和谐助力。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp; </span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">在汶川大地震、非典和新冠病毒等多次大灾大难面前，陈苏表现出企业家的社会责任和担当，先后捐资、捐物和对口支持合计近千万元，帮助灾区重建、支持灾区学校发展、派遣师资支援贫困地区、抗击疫情等。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2019</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年，先锋软件集团又投资近</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">5000</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">万元，建设鲜花小镇，连续举办两届南昌郁金香花展。与此同时，他还和罗亭镇义坪村共建田园综合体，带动义坪村整体脱贫。先锋软件集团荣获</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;2020</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">江西民营企业社会责任领先企业</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">称号。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">伍</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 18pt;"><span style="font-family: 微软雅黑;">久有凌云报国志，重上井冈创辉煌</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt 12pt; padding: 0pt; text-align: center; vertical-align: baseline; line-height: 24pt;" align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2022-05-06%2010%3A13%3A53%E5%9B%BE%E7%89%874.png?Expires=1967163233&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=q221vpxy2QSJnogV%2F57CIpexwb0%3D" /></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp;35</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年前，陈苏作为江西省委讲师团的一名讲师，到井冈山中学支教一年，从那时起，他就与井冈山结下了深厚的缘分，井冈山人民的朴实、勤奋给他留下了深刻的印象，井冈山精神也深刻地鼓舞和影响着他。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">5</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年前，他在吉安市全票当选为江西省人大代表，继续得以续写与井冈山的缘分。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">5</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年来，陈苏董事长曾多次组团考察。随着时代的发展，新一代互联网技术不断兴起和迅猛发展，数字经济也迎来了大发展。</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2022</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年初，江西省委、省政府召开全省深化发展和改革双</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">一号工程</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">推进大会，将发展数字经济和优化升级营商环境作为全省改革发展中具有战略性、全局性、引领性和突破性的关键工作、头等大事。在这样的历史机遇下，先锋软件集团、江西软件职业技术大学</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">牵手</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">井冈山市成立先锋软件集团井冈山数字经济产业园、江西软件职业技术大学数字经济产业学院。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 12pt;">&nbsp;</span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt 0.75pt; padding: 0pt; vertical-align: baseline; line-height: 24pt;"><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;2022</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&nbsp;4</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">月</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">7</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">日，先锋软件集团井冈山数字经济产业园和江西软件职业技术大学数字经济产业学院开工仪式在井冈山隆重举行，项目投资</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">30</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">亿元，计划用</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">3</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">至</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">5</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">年的时间，建设占地</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">1000</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">亩，建筑面积</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">60</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">万平方米，园区从业人员和在校学生规模达到</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">2</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">万人的数字经济产业园和数字经济产业学院。学院依托先锋软件集团的技术优势和资源优势，实施一批区块链和数字经济应用示范工程，孵化一批区块链和数字经济创新项目，形成一批可复制推广的数字经济商业模型；依托江西软件职业技术大学的教学资源，采取产学研用一体的发展模式，引进和培养一批创新型实用人才，为井冈山推动</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">双一号</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">工程，加快高质量发展提供人才支撑；坚持产城融合、产城互促，将有效解决井冈山红星城区人气不旺的问题，进一步浓厚商业氛围，为城区发展注入新的活力。通过项目的实施将整合国内外优势资源，把园区打造成为人才引进培养的</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">孵化器</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">、助推经济发展的</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">新引擎</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">、做旺城区活力的</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&ldquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">动力源</span></span><span style="font-family: Arial; color: #564059; letter-spacing: 0pt; font-size: 14pt;">&rdquo;</span><span style="font-family: 微软雅黑; color: #564059; letter-spacing: 0pt; font-size: 14pt;"><span style="font-family: 微软雅黑;">，帮助井冈山发展数字经济，共同探索出一条数字经济发展的新路子。</span></span></p>
<p class="p" style="text-indent: 0pt; margin: 0pt; padding: 0pt; line-height: 15.75pt;"><span style="font-family: 微软雅黑; color: #666666; letter-spacing: 0.75pt; font-size: 10.5pt;">&nbsp;</span></p>
<p class="MsoNormal"><span style="font-family: Calibri; font-size: 10.5pt;">&nbsp;</span></p>');
INSERT INTO content VALUES (473, '<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">为培养创新创业人才，持续激发学生创新创业热情，展示创新创业教育成果，搭建大学生创新创业项目与社会资源对接平台，学校定于</span>2022年4月至6月举办第八届&ldquo;互联网+&rdquo;大学生创新创业大赛。特制定本实施方案。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">一、大赛主题</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;&ldquo;互联网+&rdquo;成就梦想　创新创业开辟未来</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">二、大赛目的和任务</span>&nbsp;</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">互联网</span>+大学生创新创业大赛是国家、省级和学校重要赛事之一。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32.15pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><strong><span style="font-family: 仿宋; color: #666666; font-size: 16pt;"><span style="font-family: 仿宋;">以赛促学，培养创新创业生力军。</span></span></strong><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">大赛旨在激发学生的创造力，培养造就</span>&ldquo;大众创业、万众创新&rdquo;生力军；鼓励大学生扎根中国大地了解国情民情，在创新创业中增长智慧才干，在艰苦奋斗中锤炼意志品质，把激昂的青春梦融入伟大的中国梦，努力成长为德才兼备的有为人才。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32.15pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><strong><span style="font-family: 仿宋; color: #666666; font-size: 16pt;"><span style="font-family: 仿宋;">以赛促教，探索素质教育新途径。</span></span></strong><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">把大赛作为深化创新创业教育改革的重要抓手，引导我校学生主动服务国家战略和区域发展，开展课程体系、教学方法、教师能力、管理制度等方面的综合改革。以大赛为牵引，带动教育教学深化改革，全面推进素质教育，切实提高学生的创新精神、创业意识和创新创业能力。</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32.15pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><strong><span style="font-family: 仿宋; color: #666666; font-size: 16pt;"><span style="font-family: 仿宋;">以赛促创，搭建成果转化新平台。</span></span></strong><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">推动赛事成果转化和产学研用紧密结合，促进</span>&ldquo;互联网+&rdquo;新业态形成，服务经济高质量发展。以创新引领创业、以创业带动就业，努力形成我校毕业生更高质量创业就业的新局面</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">三、组织机构</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">本次大赛由学校主办，创新创业学院承办。学校成立大赛领导小组，组长：范红铭，副组长：徐国荣、高建国、张永革，所有学院总支书记、院长和创新创业学院、教务、科研、学工、团委等部门负责人为成员，领导小组下设办公室，创新创业学院院长倪锋任主任。办公室下设综合协调组、指导评审组、院系参赛团队。院系参赛团队由学院总支书记牵头，负责组建团队并开展集训。</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">四、参赛项目类型（职教赛道和红旅赛道）</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">参赛项目能够将移动互联网、云计算、大数据、人工智能、物联网、区块链等新一代信息技术与经济社会各领域紧密结合，培育新产品、新服务、新业态、新模式；发挥互联网在促进产业升级以及信息化和工业化深度融合中的作用，促进制造业、农业、能源、环保等产业转型升级；发挥互联网在社会服务中的作用，创新网络化服务模式，促进互联网与教育、医疗、交通、金融、消费生活等深度融合。</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1.&ldquo;互联网+&rdquo;现代农业，包括农林牧渔等；</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2.&ldquo;互联网+&rdquo;制造业，包括先进制造、智能硬件、工业自动化、生物医药、节能环保、新材料、军工等领域生产加工、维护、服务；</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3.&ldquo;互联网+&rdquo;信息技术服务，包括人工智能技术、物联网技术、网络空间安全技术、大数据、云计算、工具软件、社交网络、媒体门户、企业服务、下一代通讯技术等；</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">4.&ldquo;互联网+&rdquo;文化创意服务，包括广播影视、设计服务、文化艺术、旅游休闲、艺术品交易、广告会展、动漫娱乐、体育竞技等；</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">5.&ldquo;互联网+&rdquo;社会服务，包括电子商务、消费生活、家政服务、养老服务、食品安全、金融、财经法务、房产家居、高效物流、教育培训、健康服务、交通、社区服务等。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">参赛项目不只限于</span>&ldquo;互联网+&rdquo;项目，鼓励各类创新创业项目参赛，根据专业背景选择相应类型。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">五、参赛项目要求</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1、参赛项目须真实、健康、合法，无任何不良信息，项目立意应弘扬正能量，践行社会主义核心价值观。参赛项目不得侵犯他人知识产权；所涉及的发明创造、专利技术、资源等必须拥有清晰合法的知识产权或物权；抄袭、盗用、提供虚假材料或违反相关法律法规一经发现即刻丧失参赛相关权利并自负一切法律责任。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2、参赛项目涉及他人知识产权的，报名时需提交完整的具有法律效力的所有人书面授权许可书、专利证书等；已完成工商登记注册的创业项目，报名时需提交营业执照及统一社会信用代码等相关复印件、单位概况、法定代表人情况、股权结构等。参赛项目可提供当前财务数据、已获投资情况、带动就业情况等相关证明材料。　　</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3.大赛以团队为单位报名参赛。允许跨校组建团队，每个团队的参赛成员不少于3人，须为项目的实际成员。参赛团队所报参赛创业项目，须为本团队策划或经营的项目，不得借用他人项目参赛。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">4.参赛项目根据各赛道相应的要求，只能选择一个符合要求的赛道参赛。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">5.参赛主要材料及相关要求</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">（</span>1）项目计划书。内容主要包括产品/服务介绍、市场分析及定位、商业模式、营销策略、财务分析、风险控制、团队介绍及其他说明。创意组根据团队创意设计撰写项目计划书；初创组、成长组根据公司实际经营情况撰写创业项目计划书。初创组、成长组中完成工商登记注册的参赛团队还需将组织结构代码证、营业执照复印件、法定代表人情况、股权结构及其他佐证材料（专利、著作、政府批文、鉴定材料等）附在项目计划书中，大小不超过20MB。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">（</span>2）项目展示文档。每个项目要准备PPT或PPTX格式的展示文档。大赛正式报名时，需将项目的PPT或PPTX格式的展示文档上传到&ldquo;全国大学生创业服务网&rdquo;，大小不超过20MB。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">其他需要提交的材料、证明以及材料报送方式等事宜在大赛正式通知中公布。</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">六、参赛项目组别和参赛对象</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">高教主赛道：创意组、初创组、成长组、师生共创组</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">青年红色筑梦之旅赛道：公益组、商业组</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">职教赛道：创意组、创业组</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 30.1pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><strong><span style="font-family: 黑体; line-height: 32px; color: #666666; font-size: 16pt;"><span style="font-family: 黑体;">七、赛程安排</span></span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">大赛分院赛、校赛两个阶段进行，具体赛程安排如下：</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; background: #ffffff;" align="justify"><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">参赛报名（</span>4-5月）。以院系为单位到创新创业学院进行报名。报名截止时间为202</span><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2</span><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋;">年</span>5月</span><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3</span><span style="font-family: 仿宋; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">0日。</span></p>
<p class="MsoNormal" style="margin-bottom: 0pt; text-align: justify; line-height: 1.5px; background: #ffffff;" align="justify"><span style="font-family: 仿宋; line-height: 32px; color: #666666; font-size: 16pt;">&nbsp;</span></p>
