INSERT INTO content VALUES (503, '<h1 style="text-indent: 0.0000pt; border-bottom: 1.0000pt solid #ececec; mso-border-bottom-alt: 0.7500pt solid #ececec; padding: 0pt 0pt 7pt 0pt; mso-pagination: widow-orphan; text-align: center; line-height: 19.5000pt; background: #ffffff; margin: 0.0000pt;" align="center"><strong><span style="font-family: 黑体; color: #113273; letter-spacing: 0pt; font-size: 16.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">喜报！</span></strong><strong><span style="font-family: 黑体; color: #113273; letter-spacing: 0pt; font-size: 16.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西软件职业技术大学</span></strong><strong><span style="font-family: 黑体; color: #113273; letter-spacing: 0pt; font-size: 16.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">众创空间获批</span></strong></h1>
<h1 style="text-indent: 0.0000pt; border-bottom: 1.0000pt solid #ececec; mso-border-bottom-alt: 0.7500pt solid #ececec; padding: 0pt 0pt 7pt 0pt; mso-pagination: widow-orphan; text-align: center; line-height: 19.5000pt; background: #ffffff; margin: 0.0000pt;" align="center"><strong><span style="font-family: 黑体; color: #113273; letter-spacing: 0pt; font-size: 16.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西</span></strong><strong><span style="font-family: 黑体; color: #113273; letter-spacing: 0pt; font-size: 16.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">省级众创空间</span></strong></h1>
<p class="p" style="margin-top: 0.0000pt; margin-right: 0.0000pt; margin-bottom: 7.5000pt; text-indent: 42.0000pt; mso-char-indent-count: 3.0000; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; mso-line-height-alt: 12pt; background: #ffffff;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 宋体;">省科技厅发布《关于</span><span style="font-family: 宋体;">202</span></span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">年拟认定（备案）的省级科技企业孵化器、众创空间的公示》。</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西软件职业技术大学先锋创客小镇</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 宋体;">众创空间在激烈竞争中脱颖而出，成为</span><span style="font-family: 宋体;">202</span></span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">年度</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">省认定的</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">12</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">家省级众创空间之一。</span></p>
<p class="p" style="text-indent: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; mso-line-height-alt: 12pt; background: #ffffff; margin: 0.0000pt 0.0000pt 7.5000pt 0.0000pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp; &nbsp; 此次申报工作，学校领导高度重视，在创新创业学院</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">和</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">相关部门的大力支持，以及在孵企业的积极配合下，经过申报书撰写、</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">湾里经发办</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">实地考察和推荐、</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">省科技厅专家会议评审和实地核查等程序，历时半年，</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">先锋创客小镇</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">众创空间完成申报并成功入选。</span></p>
<p class="p" style="text-indent: 42.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; mso-line-height-alt: 12pt; background: #ffffff; margin: 0.0000pt 0.0000pt 7.5000pt 0.0000pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">先锋创客小镇</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 宋体;">众创空间将继续贯彻落实国家双创以及创新驱动发展战略，紧紧围绕科技成果转移转化和创新创业人才培养，力争在</span><span style="font-family: 宋体;">202</span></span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3</span><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 宋体;">年建设成为特色突出、功能完善、承载力强的国家级众创空间。</span><span style="font-family: 宋体;">&nbsp;</span></span></p>
<p class="p" style="text-indent: 42.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; mso-line-height-alt: 12pt; background: #ffffff; margin: 0.0000pt 0.0000pt 7.5000pt 0.0000pt;"><span style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span style="font-family: 宋体;">2023年2月8日</span></span></p>
<p class="p" style="text-indent: 42.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; mso-line-height-alt: 12pt; background: #ffffff; margin: 0.0000pt 0.0000pt 7.5000pt 0.0000pt;">&nbsp;</p>
<p class="MsoNormal"><span style="font-family: 仿宋_GB2312; font-size: 12pt;">&nbsp;&ldquo;<span style="font-family: Times New Roman;">http://kjt.jiangxi.gov.cn/art/2022/11/25/art_27029_4257676.html&rdquo;<img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2023-03-03%2015%3A18%3A55%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20230303151831.png?Expires=1993187935&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Tsll3juEq1eLtO8o6Gcz3th%2F1Cg%3D" alt="" width="1042" height="563" /></span></span></p>');
INSERT INTO content VALUES (509, '<p class="MsoNormal" style="text-indent: 21.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: center; mso-line-height-alt: 12pt; background: #ffffff; margin: 0.0000pt;" align="center"><strong><span class="15" style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 18pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">江西软件职业技术大学关于征集</span></strong><strong><span class="15" style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 18pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2023</span></strong><strong><span class="15" style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 18pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 宋体;">年中国国际</span><span style="font-family: 宋体;">&ldquo;互联网</span></span></strong><strong><span class="15" style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 18pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">+</span></strong><strong><span class="15" style="font-family: 宋体; color: #333333; letter-spacing: 0pt; font-size: 18pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&rdquo;大学生创新创业大赛项目的通知</span></strong></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">各二级学院、部门：</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">为更好备战</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2023</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">年中国国际</span><span style="font-family: 微软雅黑;">&ldquo;</span><span style="font-family: 仿宋_GB2312;">互联网</span></span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">+</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 微软雅黑;">&rdquo;</span><span style="font-family: 仿宋_GB2312;">大学生创新创业大赛</span></span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">，持续推进学院</span><span style="font-family: 仿宋_GB2312;">&ldquo;互联网+&rdquo;大赛工作，决定面向全校征集&ldquo;互联网+&rdquo;大学生创新创业大赛培育项目，有关事项通知如下：</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 21pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 黑体; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">一、项目负责人基本条件</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">在校生、毕业</span><span style="font-family: 仿宋_GB2312;">5年以内的毕业生（2018年及之后毕业）均可报名。</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 21pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 黑体; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">二、征集范围</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">包括但不限于以下五类</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">:</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">(一</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">)</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">获得往届省赛金奖</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">,</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">但未获国赛金奖和银奖的项目；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">(二</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">)</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">商业模式创新性较强、应用范围较广、市场发展前景较好、关键技术先进成熟的项目；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">(三</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">)</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">已转化落地或已进行创业孵化、有实际产品的科技成果转化项目；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">(四</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">)</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">五年内的校友优秀创业项目；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">(五</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">)</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">挑战杯、</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">三创赛、</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">创青春全国大学生系列赛事、全国大学生生命科学竞赛等其它学科竞赛获奖项目。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 32.15pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">具体要求可参考《教育部关于举办第八届中国国际</span><span style="font-family: 微软雅黑;">&ldquo;</span><span style="font-family: 仿宋_GB2312;">互联网</span></span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">+</span><span style="font-family: Tahoma; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&rdquo;</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">大学生创新创业大赛的通知（教高函〔</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2022</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">〕</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2&nbsp;</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">号）》（附件</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">）。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 21pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 黑体; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">三、征集要求</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 21pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;&nbsp;<span style="font-family: 仿宋_GB2312;">请按照附件</span></span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">，认真填写项目情况和重点培育学生情况。于</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">月</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">31</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">日下班前发送至邮箱：</span><span style="font-family: 微软雅黑; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">328070899@qq.com，</span><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">对于征集的优秀项目学校将提供导师辅导、备赛跟踪、资源对接等后续服务。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 21pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 黑体; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">四、工作安排</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（一）宣传动员重点项目挖掘阶段（</span><span style="font-family: 仿宋_GB2312;">2023年2月-4月）</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1.创新创业学院会同各有关单位开展创新创业专场宣传动员会，鼓励学生积极参与创新创业竞赛活动。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2.各单位结合现有教师科研项目、大学生创新创业训练计划和学生创业项目等，重点挖掘具有培育价值的项目，组织师生填报《2023年&ldquo;互联网&rdquo;大学生创新创业大赛培育项目申报表》（附件1），申报项目经评审后排序填报《2023年&ldquo;互联网+&rdquo;大学生创新创业大赛重点培育项目推荐汇总表》（附件2），并于,3月31日之前将《2023年&ldquo;互联网&rdquo;大学生创新创业大赛培育项目申报表》（电子稿）和《2023年&ldquo;互联网+&rdquo;大学生创新创业大赛重点培育项目推荐汇总表》（纸质稿和电子稿）报创新创业学院。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（二）建立项目培育库（</span><span style="font-family: 仿宋_GB2312;">2023年4月）</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1.学院组织专家对申报项目进行评审，项目分类定级后建立培育项目库。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2.对具有参赛潜力的项目团队成员开展&ldquo;互联网+&rdquo;创新创业训练营活动，优化团队配置，提升项目团队撰写商业计划书和路演能力。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3.对条件成熟的项目逐步配备校外企业家导师，提升项目培育效率。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3.对具有潜力但尚不具备参赛条件的项目进行中长期培育。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（三）项目培育（</span><span style="font-family: 仿宋_GB2312;">2023年4月-5月）</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">在校内外导师共同培育下修改完善项目，丰富实践内容，提升实践实效，积极准备参加校内比赛。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（四）组织学院</span><span style="font-family: 仿宋_GB2312;">&ldquo;互联网+&rdquo;竞赛（2023年5-6月）。</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（五）参加江西省</span><span style="font-family: 仿宋_GB2312;">&ldquo;互联网+&rdquo;竞赛（2023年6-8月）。</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">（六）全国总决赛（</span><span style="font-family: 仿宋_GB2312;">2023年10月）。</span></span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">六、支持与服务</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">1.提供创新创业活动宣传员，会同各单位开展创新创业活动的宣传动员工作;</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2.推荐校外企业家导师，提供专家一对一指导；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">3.优先推荐申请国家级或省级大学生创新创业训练计划项目；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">4.优先推荐入驻学院创新创业园或省、市、县各级各类创新创业孵化器；</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">5.优先推荐参加2023年江西省&ldquo;互联网+&rdquo;大学生创新创业大赛。</span></p>
<p class="MsoNormal" style="margin: 0pt; text-indent: 16pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 仿宋_GB2312;">联系人：黄老师，联系电话：</span><span style="font-family: 仿宋_GB2312;">13767979712，电子邮箱：328070899@qq.com</span></span></p>
<p class="MsoNormal" style="margin-top: 0pt; margin-right: 0pt; margin-bottom: 0pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="MsoNormal" style="margin-top: 0pt; margin-right: 0pt; margin-bottom: 0pt; padding: 0pt; line-height: 15.75pt; background: #ffffff;"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="MsoNormal" style="margin-top: 0.0000pt; margin-right: 0.0000pt; margin-bottom: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: right; line-height: 15.7500pt; background: #ffffff;" align="right"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">创新创业学院</span></p>
<p class="MsoNormal" style="margin-top: 0.0000pt; margin-right: 0.0000pt; margin-bottom: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: right; line-height: 15.7500pt; background: #ffffff;" align="right"><span style="font-family: 仿宋_GB2312; color: #333333; letter-spacing: 0pt; font-size: 16pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">2023年3月7日</span></p>');
INSERT INTO content VALUES (520, '<p class="MsoNormal" style="mso-pagination: widow-orphan; text-align: center; mso-outline-level: 2; vertical-align: baseline; line-height: 22.5000pt; background: #ffffff;" align="center"><strong><span style="font-family: 微软雅黑; color: #333333; font-size: 16.5pt;"><span style="font-family: 微软雅黑;">我敢闯，我会创</span> <span style="font-family: 微软雅黑;">&mdash;&mdash; 我校202</span></span></strong><strong><span style="font-family: 微软雅黑; color: #333333; font-size: 16.5pt;">3</span></strong><strong><span style="font-family: 微软雅黑; color: #333333; font-size: 16.5pt;">年</span></strong><strong><span style="font-family: 微软雅黑; color: #333333; font-size: 16.5pt;">第九届</span></strong><strong><span style="font-family: 微软雅黑; color: #333333; font-size: 16.5pt;">&ldquo;互联网+&rdquo;大学生创新创业决赛圆满落幕</span></strong></p>
<p class="MsoNormal" style="text-indent: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: center; vertical-align: baseline; background: #ffffff; margin: 0.0000pt 7.5000pt 0.0000pt 0.0000pt;" align="center"><span style="font-family: 微软雅黑; color: #aca7ad; letter-spacing: 0pt; font-size: 12pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 微软雅黑;">作者</span> <span style="font-family: 微软雅黑;">: 创业创新学院</span></span><span style="font-family: 微软雅黑; color: #aca7ad; letter-spacing: 0pt; font-size: 10.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: center; vertical-align: baseline; background: #ffffff; margin: 0.0000pt 7.5000pt 0.0000pt 0.0000pt;" align="center"><span style="font-family: 微软雅黑; color: #aca7ad; letter-spacing: 0pt; font-size: 12pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="font-family: 微软雅黑;">摄影</span> <span style="font-family: 微软雅黑;">: 创业创新学院</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">为全面落实习近平总书记给中国</span><span style="font-family: 微软雅黑;">&ldquo;互联网</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">+&rdquo;大学生创新创业大赛&ldquo;青年红色筑梦之旅&rdquo;大学生的重要回信精神，深入推进大众创业万众创新，引领创新创业教育国际交流合作，加快培养创新创业人才，持续激发大学生创新创业热情，促进创新驱动创业、创业引领就业，7月</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">1</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">日，以</span><span style="font-family: 微软雅黑;">&ldquo;互联网+&rdquo;成就梦想、创新创业开辟未来为主题的江西软件职业技术大学2023年</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">第九届</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&ldquo;互联网+&rdquo;大学生创新创业决赛在路演大厅成功举行。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">今年</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">5月至今，学校全面部署大赛组织工作，各学院积极响应，全校学生踊跃参加。历时近2个月，经过组织动员、项目辅导、各学院初赛、校级决赛等阶段，共</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">计</span><span style="font-family: 微软雅黑;">2100</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">多</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">个项目参赛，覆盖了学校所有学院。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">经由院级初赛、复赛评审，共有</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">13个项目晋级校级决赛。决赛分项目展示和评审答辩两个环节，参赛团队创意层出，应答自如,充分展现了我校学子&ldquo;敢闯会创&rdquo;的良好风貌。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">学校聘请由省内知名的企业家、投资人和双创导师</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">邓小朱、王少浪、郭鹏飞</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">组成评委</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">组，关于几位评委老师的简介如下：</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">邓小朱，教授，硕士生导师。主持的《创新创业过程与方法》课程认定为全国高校就业创业金课，</span><span style="font-family: 微软雅黑;">2023 年由教育部认定为国家线上一流课程。指导学生获国创项目 5 项，获各级各类创新创业大赛国奖 200 余项，连续评为优秀指导老师。是中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛专家库成员，国家铁路局铁路科技标准规划及江西省多部门投资项目评审专家。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">王少浪，北京启航致远教育科技有限公司董事长、中国下一代教育基金会锦成致远职业发展专项基金秘书长、高校毕业生就业协会生涯发展工作委员会学术委员会副主任，所获荣誉：教育部第二三届</span><span style="font-family: 微软雅黑;">&ldquo;互联网+&rdquo;创新创业大赛专家委员会委员、人社部&ldquo;中国创翼&rdquo;大赛总决赛评委、教育部全国大学生职业生涯规划大赛评委、教育部全国大学生就业指导课程大赛评委、教育部创业指导教学大赛评委。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">郭鹏飞</span> <span style="font-family: 微软雅黑;">，创新创业导师，现任南昌理工学院科研处副处长，大学生科技创新基地主任，指导学生参加第十届、十一届、十二届、十三届、十六届，十七届</span><span style="font-family: 微软雅黑;">&ldquo;挑战杯&rdquo;大学生课外学术作品竞赛和&ldquo;创青春&rdquo;创业大赛江西省二等奖 8项、三等奖 13项，指导全国大学生&ldquo;互联网+&rdquo;创新创业训练计划项目国家级项目5项，省级项目8项，第五届，第六届，第八届中国大学生&ldquo;互联网+&rdquo;创新创业大赛全国铜奖 2项，江西省银奖 2项，铜奖 6项。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="file:///C:/Users/kr/AppData/Local/Temp/ksohtml14820/wps4.png" width="367" height="275" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">经过三位评委专家对</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">参赛项目逐一点评、打分，为项目后续发展建言献策，帮助项目打磨优化。最终评选出一等奖一个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">VR与艺术学院的《&ldquo;井冈先锋&rdquo;数字化国情教育研学旅行智慧服务平台》，指导老师：梅龙、王芬芬、朱学文、张华琛。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="file:///C:/Users/kr/AppData/Local/Temp/ksohtml14820/wps5.png" width="370" height="277" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">二等奖两个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">新媒体学院的《</span><span style="font-family: 微软雅黑;">&ldquo;小脚印&rdquo;体适能馆》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：杨娇</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">智能科技学院与北斗通航研究院的《基于北斗导航定位与无人机技术的智慧社区网格化管理系统》</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：张璐瑜、梁嘉淋</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="file:///C:/Users/kr/AppData/Local/Temp/ksohtml14820/wps6.png" width="390" height="292" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">三等奖三个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">智能科技学院的《商品三维扫描软件</span><span style="font-family: 微软雅黑;">&mdash;&mdash;衣拟之间》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">指导老师：</span> <span style="font-family: 微软雅黑;">王文鑫、刘婷、黄敏</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">VR</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">与艺术学院的《</span><span style="font-family: 微软雅黑;">&ldquo;治愈馆&rdquo;&mdash;VR改变世界&amp;与负能量说再见》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：张华琛、王国涛</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">网络工程学院的《联黎智能化控温衣物》</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：夏顺顺。</span></p>
<p class="MsoBodyText" style="text-align: center;" align="center"><img src="file:///C:/Users/kr/AppData/Local/Temp/ksohtml14820/wps7.png" width="344" height="282" /><span style="mso-spacerun: 'yes'; font-family: 等线; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">优秀组织奖一个：网络工程学院</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">优秀创新创业指导老师二个：</span><span style="font-family: 微软雅黑;">VR与艺术学院 张华琛；智能科技学院、</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">北斗通航研究院</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">张璐瑜。</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">通过本次比赛，极大地锻炼和提高了同学们的专业素养和创新创业实践能力，心理素质、演讲表达等方面得到整体提升，真正达到了赛训一体同交流，以赛促学共提高。下一步，学院将根据专家评审意见，持续优化创新创业项目，积极备战第九届中国国际</span><span style="font-family: 微软雅黑;">&ldquo;互联网</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">+&rdquo;创新创业大赛省赛。</span></p>');
INSERT INTO content VALUES (521, '<h2 class="MsoNormal" style="text-indent: 0.0000pt; padding: 0pt 0pt 0pt 0pt; mso-pagination: widow-orphan; text-align: center; vertical-align: baseline; background: #ffffff; margin: 0.0000pt 7.5000pt 0.0000pt 0.0000pt;" align="center"><strong>我敢闯，我会创 &mdash;&mdash; 我校2023年第九届&ldquo;互联网+&rdquo;大学生创新创业决赛圆满落幕</strong></h2>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">为全面落实习近平总书记给中国</span><span style="font-family: 微软雅黑;">&ldquo;互联网</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">+&rdquo;大学生创新创业大赛&ldquo;青年红色筑梦之旅&rdquo;大学生的重要回信精神，深入推进大众创业万众创新，引领创新创业教育国际交流合作，加快培养创新创业人才，持续激发大学生创新创业热情，促进创新驱动创业、创业引领就业，7月</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">1</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">日，以</span><span style="font-family: 微软雅黑;">&ldquo;互联网+&rdquo;成就梦想、创新创业开辟未来为主题的江西软件职业技术大学2023年</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">第九届</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&ldquo;互联网+&rdquo;大学生创新创业决赛在路演大厅成功举行。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">今年</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">5月至今，学校全面部署大赛组织工作，各学院积极响应，全校学生踊跃参加。历时近2个月，经过组织动员、项目辅导、各学院初赛、校级决赛等阶段，共</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">计</span><span style="font-family: 微软雅黑;">2100</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">多</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">个项目参赛，覆盖了学校所有学院。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">经由院级初赛、复赛评审，共有</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">13个项目晋级校级决赛。决赛分项目展示和评审答辩两个环节，参赛团队创意层出，应答自如,充分展现了我校学子&ldquo;敢闯会创&rdquo;的良好风貌。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">学校聘请由省内知名的企业家、投资人和双创导师</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">邓小朱、王少浪、郭鹏飞</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">组成评委</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">组，关于几位评委老师的简介如下：</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">邓小朱，教授，硕士生导师。主持的《创新创业过程与方法》课程认定为全国高校就业创业金课，</span><span style="font-family: 微软雅黑;">2023 年由教育部认定为国家线上一流课程。指导学生获国创项目 5 项，获各级各类创新创业大赛国奖 200 余项，连续评为优秀指导老师。是中国国际&ldquo;互联网+&rdquo;大学生创新创业大赛专家库成员，国家铁路局铁路科技标准规划及江西省多部门投资项目评审专家。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">王少浪，北京启航致远教育科技有限公司董事长、中国下一代教育基金会锦成致远职业发展专项基金秘书长、高校毕业生就业协会生涯发展工作委员会学术委员会副主任，所获荣誉：教育部第二三届</span><span style="font-family: 微软雅黑;">&ldquo;互联网+&rdquo;创新创业大赛专家委员会委员、人社部&ldquo;中国创翼&rdquo;大赛总决赛评委、教育部全国大学生职业生涯规划大赛评委、教育部全国大学生就业指导课程大赛评委、教育部创业指导教学大赛评委。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">郭鹏飞</span> <span style="font-family: 微软雅黑;">，创新创业导师，现任南昌理工学院科研处副处长，大学生科技创新基地主任，指导学生参加第十届、十一届、十二届、十三届、十六届，十七届</span><span style="font-family: 微软雅黑;">&ldquo;挑战杯&rdquo;大学生课外学术作品竞赛和&ldquo;创青春&rdquo;创业大赛江西省二等奖 8项、三等奖 13项，指导全国大学生&ldquo;互联网+&rdquo;创新创业训练计划项目国家级项目5项，省级项目8项，第五届，第六届，第八届中国大学生&ldquo;互联网+&rdquo;创新创业大赛全国铜奖 2项，江西省银奖 2项，铜奖 6项。</span></span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2023-07-04%2018%3A19%3A42blob?Expires=2003825983&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=2EOpDRKUCN9WEzZIoGFjcY151dU%3D" alt="" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">经过三位评委专家对</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">参赛项目逐一点评、打分，为项目后续发展建言献策，帮助项目打磨优化。最终评选出一等奖一个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">VR与艺术学院的《&ldquo;井冈先锋&rdquo;数字化国情教育研学旅行智慧服务平台》，指导老师：梅龙、王芬芬、朱学文、张华琛。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2023-07-04%2018%3A22%3A00blob?Expires=2003826120&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=qQA09os8RUpxJMDjXjglTiE2y0k%3D" alt="" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">二等奖两个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">新媒体学院的《</span><span style="font-family: 微软雅黑;">&ldquo;小脚印&rdquo;体适能馆》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：杨娇</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">智能科技学院与北斗通航研究院的《基于北斗导航定位与无人机技术的智慧社区网格化管理系统》</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：张璐瑜、梁嘉淋</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">。</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; text-align: center;" align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2023-07-04%2018%3A19%3A43blob?Expires=2003825983&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=aedcvMBCzZszvIcD3m9jhe4cnR0%3D" alt="" /><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 21.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">三等奖三个</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">：</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">智能科技学院的《商品三维扫描软件</span><span style="font-family: 微软雅黑;">&mdash;&mdash;衣拟之间》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">指导老师：</span> <span style="font-family: 微软雅黑;">王文鑫、刘婷、黄敏</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">VR</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">与艺术学院的《</span><span style="font-family: 微软雅黑;">&ldquo;治愈馆&rdquo;&mdash;VR改变世界&amp;与负能量说再见》</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：张华琛、王国涛</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">；</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">网络工程学院的《联黎智能化控温衣物》</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">，</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">指导老师：夏顺顺。</span></p>
<p class="MsoBodyText" style="text-align: center;" align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/2023-07-04%2018%3A19%3A43blob?Expires=2003825983&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=aedcvMBCzZszvIcD3m9jhe4cnR0%3D" alt="" /><span style="mso-spacerun: 'yes'; font-family: 等线; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">优秀组织奖一个：网络工程学院</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">优秀创新创业指导老师二个：</span><span style="font-family: 微软雅黑;">VR与艺术学院 张华琛；智能科技学院、</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">北斗通航研究院</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 10.5000pt; mso-font-kerning: 1.0000pt;">&nbsp;</span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">张璐瑜。</span></p>
<p class="MsoNormal" style="text-indent: 22.0000pt; mso-char-indent-count: 2.0000; line-height: 22.0000pt; mso-line-height-rule: exactly;"><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;"><span style="font-family: 微软雅黑;">通过本次比赛，极大地锻炼和提高了同学们的专业素养和创新创业实践能力，心理素质、演讲表达等方面得到整体提升，真正达到了赛训一体同交流，以赛促学共提高。下一步，学院将根据专家评审意见，持续优化创新创业项目，积极备战第九届中国国际</span><span style="font-family: 微软雅黑;">&ldquo;互联网</span></span><span style="mso-spacerun: 'yes'; font-family: 微软雅黑; mso-bidi-font-family: 'Times New Roman'; font-size: 11.0000pt; mso-font-kerning: 1.0000pt;">+&rdquo;创新创业大赛省赛。</span></p>');
INSERT INTO content VALUES (522, '<div id="js_article" class="rich_media" style="margin: 0px; padding: 0px; outline-width: 0px;">
<div id="js_base_container" class="rich_media_inner" style="margin: 0px; padding: 0px; outline-width: 0px;">
<div id="page-content" class="rich_media_area_primary" style="margin: 0px; outline-width: 0px;">
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px; text-align: center;"><span style="font-family: 微软雅黑; font-size: 18px;"><span style="background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;">中国国际大学生创新大赛（2024）</span></span></span></span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px; text-align: center;"><span style="font-family: 微软雅黑; font-size: 18px;"><span style="background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;">江西软件职业技术大学</span></span></span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;">获奖名单公布</span></span></span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; </span></span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;">&nbsp;</h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 为深入贯彻落实习近平总书记给&ldquo;青年红色筑梦之旅&rdquo;学生重要回信和&ldquo;把创新教育贯穿教育活动全过程&rdquo;重要指示精神，贯彻党的二十大关于加快建设教育强国的战略部署，江西软件职业技术大学举办了中国国际大学生创新大赛2024，现将获奖名单公布如下。</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">一、【金奖项目】：</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 职教赛道创意组，基于体积视频技术的红色文旅公共服务合拍平台</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">二、【银奖项目】：</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; </span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 青年红色筑梦之旅赛道创意组，井冈先锋数字化国情教育研学旅行智慧服务平台；</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; </span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 职教赛道创意组，基于区块链的先锋积分管理系统</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">三、【铜奖项目】：</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; </span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 青年红色筑梦之旅赛道创意组，灵眸&mdash;基于图灵AI大模型的社区综合管理系统；</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; </span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 高教主赛道创意组，VR陶韵视界&mdash;数字陶瓷艺术展馆；</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 职教赛道创意组，小力速达&mdash;您的智能配送管家</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">四、【优秀组织奖】：</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 区块链学院</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">五、【优秀创新创业导师奖】：</span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp; 井冈山数字经济产业学院 蔡咸健</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp;</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word;">&nbsp; &nbsp; </span></span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word;">&nbsp; &nbsp; 中国国际大学生创新大赛2024江西软件职业技术大学校赛自5月15日以来，共有970个项目报名，27支队伍进入决赛。决赛于6月11日至6月17日并经过线上与线下两轮共一个星期的评选，评选出以上</span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word;">金银铜奖共六支优胜项目。项目队伍将稍晚代表江西软件职业技术大学参加江西</span></span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word;">省赛选拔。</span></span></span></h2>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #000000; box-sizing: border-box; overflow-wrap: break-word;">&nbsp; &nbsp; 以下是校赛获奖名单：</span></span></span></h2>
<p><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><img style="color: #301491; background-color: #ffffff; display: block; margin-left: auto; margin-right: auto; text-decoration: underline;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-25%2010%3A35%3A24%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240625103508.png?Expires=2034642925&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=BffnThJWg%2B%2BKbCGycJWS%2Fb4%2F94k%3D" width="675" height="998" /></span></p>
<h2 class="rich_media_area_primary_inner" style="margin: 0px auto; padding: 0px; outline-width: 0px; max-width: 677px;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;"><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #301491; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;">&nbsp; &nbsp;<span style="color: #000000;"> 祝贺以上获奖的优胜队伍，希望在省赛中获得更好的成绩。也希望更多的江软学子们参与其</span></span><span style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; color: #301491; box-sizing: border-box; overflow-wrap: break-word; background-color: #ffffff;"><span style="color: #000000;">中，践行大赛&ldquo;我敢闯 我会创&rdquo;精神与本校&ldquo;创新创业，知识管理&rdquo;校训，努力争先，为校争光。</span></span></span></h2>
<section style="margin: 0px; padding: 5px 33px 0px 0px; outline-width: 0px; max-width: 100%; display: flex; flex-direction: column; box-sizing: border-box; overflow-wrap: break-word;" data-mid="">
<section style="margin: 0px; padding: 0px; outline-width: 0px; max-width: 100%; display: flex; flex-direction: column; align-self: flex-end; box-sizing: border-box; overflow-wrap: break-word;" data-mid="">
<section style="margin: 0px 0px -28px -12px; padding: 0px; outline-width: 0px; max-width: 100%; width: 25px; height: 34px; display: flex; justify-content: center; align-items: center; box-sizing: border-box; overflow-wrap: break-word;" data-mid=""></section>
</section>
</section>
</div>
</div>
</div>
<div class="underline-container" style="margin: 0px; padding: 0px; outline-width: 0px; pointer-events: none;" data-v-9d99f138="">
<div class="menu_options menu_options_default menu_options_show" style="margin: 0px; padding: 0px 0px 5px; outline-width: 0px; color: #ffffff; filter: none; pointer-events: auto; transition: opacity 0.2s ease 0s; position: absolute; z-index: 50; font-size: 0px; opacity: 1; max-width: calc(100vw - 16px); transform: scale(0);" data-v-bdc8501c="" data-v-9d99f138="">
<h2 class="menu_options_bar" style="margin: 0px; padding: 0px; outline-width: 0px; background-color: currentcolor; backdrop-filter: none; filter: none; box-shadow: rgba(0, 0, 0, 0.2) 0px 4px 30px; border-radius: 4px; font-size: 14px; position: relative; z-index: 1; color: #ffffff; font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei UI', 'Microsoft YaHei', Arial, sans-serif; white-space: normal;"><span style="background-color: #ffffff; font-family: 微软雅黑; font-size: 14px;">人划线</span></h2>
</div>
</div>');
INSERT INTO content VALUES (523, '<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A33%3A46640.jpg?Expires=2034747226&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=G3XADMTofwXuZCgTFnec%2Bl7MQ8w%3D" alt="" width="874" height="492" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">春去夏来<br />一群大学生迎来了一个不一样的五一假期</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A35%3A17%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626153326.jpg?Expires=2034747318&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=d7Jcjcf2L5HLS7RoMkNSY7bgykQ%3D" width="859" height="1148" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">为了更好的实践创新创业的理念<br />江软创新创业学院组织协会同学<br />在先锋小镇开展了五一劳动社会实践活动</p>
<p style="text-align: center;">&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A37%3A36%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626153757.jpg?Expires=2034747456&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Z7NASMDdNCn9jFOaERjrDzIlhsQ%3D" alt="" width="867" height="488" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">由学院的同学们开门迎客<br />开始了先锋小镇与天使咖啡的运营<br />从小镇的入园引导，到园区的卫生维护<br />从咖啡甜点的制作到园区营地的搭建<br />同学们为到园游客提供了无微不至的服务</p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A38%3A56%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626153914.jpg?Expires=2034747537&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=tY6hvXTcXvsiqzgXjnBBRRhaeAA%3D" alt="" width="887" height="1183" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">先锋小镇，水流青透<br />花儿红艳，绿树成荫<br />同学们不但在这学到了知识<br />实践了技能，体会了劳动<br />在这五月的时刻<br />遇见更好的自己</p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A41%3A45%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626154212.jpg?Expires=2034747706&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=YPVhafXT6qX4m6SapTbKmzqCW9s%3D" alt="" width="901" height="1353" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">先锋小镇，也在同学们的运营下<br />成为江西软件职业技术大学的特色实践实习基地<br />与南昌周边的新晋郊野公园</p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2015%3A49%3A04%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626154819.jpg?Expires=2034748145&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Lwh2QYaK6ATv389eSOblCN1yZ5s%3D" width="914" height="1219" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">邀约先锋小镇</p>
<p style="text-align: center;">相聚天使咖啡</p>
<p style="text-align: center;">这里不是欧洲</p>
<p style="text-align: center;">而是南昌的先锋小镇</p>
<p style="text-align: center;">&nbsp;</p>
<p data-mid="">参加五一劳动实践的同学：</p>
<p data-mid="">周凡、黄龙跃、尹杰豪、邓丽婷、李峰、王乐、周文帝、陈永杰</p>
<p style="text-align: center;">&nbsp;</p>');
INSERT INTO content VALUES (524, '<p><a title="第十届大创课准备进行时" href="https://mp.weixin.qq.com/s/Kf8xTnOzX8mqJ3TsC7M9lg" target="_blank" rel="noopener">&ldquo;筑梦青春，志在赣鄱 创新引领赣才留赣&rdquo; 江西省第十届大学生创业公开课正式启动。</a></p>');
INSERT INTO content VALUES (533, '<p style="text-align: center;">创新创业，知识管理</p>
<p style="text-align: center;" align="center">&ldquo;筑梦青春，志在赣鄱</p>
<p style="text-align: center;" align="center">创新引领赣才留赣&rdquo;</p>
<p style="text-align: center;" align="center">江西省第十届大学生创业公开课正式启动。</p>
<p style="text-align: center;" align="center">2024年5月15日</p>
<p style="text-align: center;" align="center">江西软件职业技术大学作为比赛专场</p>
<p style="text-align: center;" align="center">奔跑在创新的赛道上</p>
<p style="text-align: center;" align="center">助力选手们跑好这一棒子！！！</p>
<p style="text-align: center;" align="center">&nbsp;</p>
<p style="text-align: center;" align="center">&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A24%3A33blob?Expires=2034750274&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=BQeOQc1rVqGQX0FPjbNKn3VQ4pI%3D" alt="IMG_259" width="600" height="791" /></p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A24%3A35blob?Expires=2034750276&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=SB8gCNSiBDg7xyIDOqsxUl%2BxnSY%3D" alt="IMG_260" width="596" height="792" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;">为加强我省高校创新创业教育和就业指导</p>
<p style="text-align: center;">增强大学生创新意识</p>
<p style="text-align: center;">大力推进产学研合作和科技成果转移转化</p>
<p style="text-align: center;">不断增强高校服务国家重大战略</p>
<p style="text-align: center;">和经济社会发展能力</p>
<p style="text-align: center;">吸引更多社会企业</p>
<p style="text-align: center;">产业资源共同关注高校创新创业教育</p>
<p style="text-align: center;">人才培养，助推高校毕业生</p>
<p style="text-align: center;">高质量创业就业</p>
<p style="text-align: center;">江西省教育厅、江西省发展和改革委员会</p>
<p style="text-align: center;">江西省工业和信息化厅</p>
<p style="text-align: center;">江西省人力资源和社会保障</p>
<p style="text-align: center;">江西省农业农村厅、江西省退役军人事务厅</p>
<p style="text-align: center;">江西省妇女联合会和江西广播电视台</p>
<p style="text-align: center;">在连续举办第九届大学生创业公开课活动</p>
<p style="text-align: center;">决定继续开展江西省第十届&ldquo;大创课&rdquo;活动</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A16%3A21image.png?Expires=2034749782&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=BS%2Bsi%2Bds6yTIZDxnV39HVCV0des%3D" width="651" height="872" /></p>
<p style="text-align: center;">&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A16%3A44image.png?Expires=2034749804&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=cDr1NAwR0oo79r0MGKhvTV5wKxc%3D" width="661" height="889" /></p>
<p style="text-align: center;">&nbsp;</p>
<p align="center"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A13%3A04blob?Expires=2034749584&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=z8nzLQAa61rPiw6KqIUupaLxhlo%3D" alt="IMG_264" width="596" height="1131" /></p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (534, '<p style="text-align: center;">曾经，有这样一个声音告诉我们</p>
<p style="text-align: center;">大学里，你有无数的选择</p>
<p style="text-align: center;">是每天早九晚五的学习升本？深造考研！</p>
<p style="text-align: center;">是专精技术，渴望就业的专业</p>
<p style="text-align: center;">是整日忙改着PPT与项目书的比赛？</p>
<p style="text-align: center;">亦或是成立一家企业或跟着一群怀着梦想的小伙伴，一起创新创业！</p>
<p style="text-align: center;">&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A30%3A26blob?Expires=2034750627&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Rs0t2fzbWYTLJgGyKNbQgjcVyM0%3D" alt="IMG_261" width="454" height="604" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;为响应国家进一步对大学生创新创业指导意见，响应江西软件职业技术大学&ldquo;创新创业、知识管理&rdquo;的理念，江西软件职业技术大学创新创业学院与创新创业协会，正式开展先锋小镇运营团队招募。</p>
<p>宣传部：</p>
<p>1.策划组：负责总体的宣传策划</p>
<p>2.文案组：负责宣传文案或脚本的写作</p>
<p>3.运营组：负责团队账号与其他相关事宜的运营</p>
<p>4.剪辑摄影组：负责团队项目的剪辑与摄影</p>
<p>&nbsp;</p>
<p>活动部：</p>
<p>1.商务组：负责商业项目的谈判与分析</p>
<p>2.策划组：负责活动与项目的总体策划</p>
<p>3.执行组：负责活动与项目的执行与落地并与部门其他成员分工协作</p>
<p align="center"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A30%3A34undefined?Expires=2034750635&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=mtVrx27NpqruV9cfdw%2F7ZwcPsR0%3D" alt="IMG_268" width="534" height="756" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 项目介绍先锋小镇，一个美轮美奂的休闲度假小镇，打造如梅林一般的自然美景公园。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 具专业的团队技术指导，由创新创业学院院长李孟领衔，以南昌先锋天使咖啡有限公司作背书，支持大学生创新创业与岗位就业。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A30%3A27blob?Expires=2034750628&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=DvnAKOZ2QXy3mHfWtzeW%2BI1yMdo%3D" alt="IMG_273" width="510" height="680" /></p>
<p align="center">&nbsp;</p>
<p align="center">对标浙江安吉&ldquo;深蓝计划&rdquo;</p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2016%3A30%3A33undefined?Expires=2034750634&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Me4pfbIgRR0kYPWn9YB%2BphcvO9E%3D" alt="IMG_284" width="605" height="485" /></p>
<p align="center"><span style="font-size: 12px;">相关视频链接</span></p>
<p align="center"><span style="font-size: 12px;">没错，我也喜欢这里｜深蓝计划_哔哩哔哩_bilibili</span></p>
<p>&nbsp;</p>
<p style="text-align: center;">如果你也曾有着一番热血，想要大干一场，快来加入我们吧！！！</p>
<p><span style="display: none;">&nbsp;</span></p>');
INSERT INTO content VALUES (535, '<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp; &ldquo;<strong>筑梦青春志在赣鄱，创新引领赣才留赣</strong>&rdquo;，为响应国家对大学生创新创业的号召，践行江西软件职业技术大学&ldquo;<strong>创新创业，知识管理</strong>&rdquo;的理念，在江西省各级领导的支持下，2024年5月15日，江西软件职业技术大学作为江西省第十届&ldquo;大创课&rdquo;专场，一共六支创业队伍前往<strong>江西广播电视台</strong>参与节目录制与项目的比拼。</p>
<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp; 2024年5月15日清晨6：30软件大学的参赛同学们早早地来到了行政大楼集合，乘坐专车来到了江西广播电视台。经过一系列的彩排与演练，选手们对大创课的流程有了详细的了解。同时，也对自己的项目进行了一系列的精进与修改。</p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A06%3A35image.png?Expires=2034752796&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=oSJeU4MbBX5IQ956But%2FbzNrVuA%3D" width="706" height="529" /></p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A05%3A33blob?Expires=2034752734&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=ZdP6xD%2B7cds%2BzImajF4skG5d3EI%3D" alt="IMG_262" width="713" height="536" /></p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 下午13：00，选手们来到了录播室开始了紧张又激烈的正式比赛。</p>
<p>&nbsp;</p>
<p style="text-align: justify;" align="left">&nbsp; &nbsp; &nbsp; &nbsp;首先举行的是名师指导公开课。公开课邀请了国内知名导师针对评省规则、商业计划书撰写与注意事项、路演表达等方面进行创赛辅导与实训。其中，傅许坚导师以他精湛的专业知识与过人的审美视角，为选手们带来了一堂主题为《创业中的审美感》课程。课程中他提到：对于创业者而言应该去培养创业的美感以及对项目的美感。关于创赛又应以什么样的视角去对待去学习去精进。</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A05%3A34blob?Expires=2034752734&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=EBUDUK4ashRFt69gTXMffWfg%2Frk%3D" alt="IMG_265" width="718" height="718" /></p>
<p>&nbsp;</p>
<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp;紧接着是政策公开课：制作一次性求职补贴、一次性创业补贴、创业担保贷款、职业技能培训等等政策内容视频，将最新最全的就业创业服务政策集中发布，帮扶毕业生高质量就业，助力大学生创业成长。</p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A05%3A35blob?Expires=2034752735&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=GVGZMfuKYp6hut%2FPYKKJzLvg988%3D" alt="IMG_267" width="720" height="541" /></p>
<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp;最后的重头戏是路演公开课。江软挑选的六支队伍走进演播室进行项目路演PK，最终本场排名第一名的项目进入大创课决赛。本次进行比拼的六支队伍分别是福辰AI、生态数据之桥、暖佑安、小力速达、新的家与爱链。</p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A05%3A36blob?Expires=2034752736&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=mFTq69Wu%2BwYx%2B1DqETqBjAc1SUE%3D" alt="IMG_269" width="705" height="529" /></p>
<p style="text-align: justify;">&nbsp; &nbsp; &nbsp;本次江软校赛&ldquo;大创课&rdquo;结束了，但创新创业的道路永远不会结束。大创课不仅仅只是一场大创课，也是自大创课改革以来，江软创新创业学院与软件大学的一次新尝试，更为中国国际大学生创业大赛打下坚实基础。同时也预祝所有的创业大学生与创业者们更上一层楼，深刻的明白&ldquo;创新创业，知识管理&rdquo;的优秀理念，体会到&ldquo;筑梦青春志在赣鄱，创新引领赣才留赣&rdquo;的深远意义。</p>
<p>&nbsp;</p>
<p><span style="display: none;">&nbsp;</span></p>');
INSERT INTO content VALUES (539, '<p style="text-align: justify;">2024年5月20日江西软件职业技术大学创新创业学院在南昌高新区开展就业之家创业沙龙活动。</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A30%3A47blob?Expires=2034754248&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=iS8FpRxUTjraVmmqhNL1s1yQ98Y%3D" alt="IMG_256" width="567" height="425" /></p>
<p>&nbsp;</p>
<p>来到高新区就业之家，同学们在那一一完成了签到，参观展区，而会场也为同学们准备了丰盛的餐点。</p>
<p>&nbsp;</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A30%3A48blob?Expires=2034754248&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=vcaQ4WQ3EFdgIbF0nzE3NQhGEro%3D" alt="IMG_257" width="567" height="425" /></p>
<p>&nbsp;</p>
<p>紧接着，同学们与主持人一起欢迎来宾，开始了当日的活动。</p>
<p>&nbsp;</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A51%3A12blob?Expires=2034755472&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Q5pXoVc%2BRX27uz%2FKCDY7tj2a4UM%3D" alt="IMG_258" width="567" height="756" /></p>
<p>&nbsp;</p>
<p>最后，导师们、青年创业代表们等为同学带来了精彩的路演，而同学们也在此次活动中明白了创业之美与知识管理的重要性。</p>
<p>&nbsp;</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A51%3A51blob?Expires=2034755511&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=LaZt0UznNsw5PUTe65kYOXR7ChQ%3D" alt="IMG_259" width="567" height="426" /></p>
<p>&nbsp;</p>
<p align="left"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A51%3A13blob?Expires=2034755473&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=mOj478LqEA0I0zkmDFzU6R4vO30%3D" alt="IMG_260" width="567" height="426" /></p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;</p>');
INSERT INTO content VALUES (540, '<p>&nbsp; &nbsp; &nbsp; &nbsp;为贯彻落实党的二十大精神，深入贯彻落实习近平总书记关于教育的重要论述和给&ldquo;青年红色筑梦之旅&rdquo;大学生重要回信精神，&ldquo;三位一体&rdquo;统筹推进教育、科技、人才工作，把创新教育贯彻教育活动全过程，加强拔尖创新人才自主培养，培育新质生产力发展新动能，为教育强国建设支撑引领中国式现代化做出更大贡献，教育部定于2024年4月至10月举办中国国际大学生创新大赛。</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;5月31日，为了让更好的发动和组织师生参加赛事，我校于创客大厦路演大厅举办了&ldquo;2024年中国国际大学生创新大赛赛前培训&rdquo;创新创业学院院长李孟与省级&ldquo;双师型&rdquo;教师，校级精品课程&ldquo;新媒体营销&rdquo;主讲教师万炜烨老师参与指导并教授相关的课程。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2017%3A59%3A59blob?Expires=2034755999&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=dC2kx7KjzAi1b3a3qr%2BySydqGag%3D" alt="图片" width="680" height="510" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;首先是万炜烨老师为选手们带来一堂主题为《项目赛场演讲表现》的课程。课程中她分别从路演前、路演时、路演结束三个维度为选手们进行比赛技巧的项目指导。其中，万炜烨老师提到了一个关键的理论&ldquo;赛马机制&rdquo;，即在同一赛道的项目里做到最优，并强调了比赛里价值主张的重要性。同时还提醒选手们在赛场上一定不能怯场要有抗压的能力。最后，万炜烨老师也基于今日所讲的内容以蓝牙门锁为例，为选手们出了一道设计命题&ldquo;如果你们设计出一款智能蓝牙门锁，你们会如何演讲&rdquo;。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2018%3A00%3A41image.png?Expires=2034756041&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HWlWDslzFLu9d%2FrUi1gGPXo%2BD5o%3D" width="691" height="517" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 紧接着是李孟院长为选手们进行&ldquo;中国大学生创新大赛&rdquo;赛制解读，李院长以他精湛的专业技巧与实战经验，分别从高教赛道、职教赛道、红色筑梦之旅三个层面为选手们进行大赛赛制的解读。同时又在三个层面里，通过政策、学校、项目本身进行一一剖析，李院长提到：&ldquo;大赛往往考验的不是比赛的能力而是选手们的综合素养&rdquo;。他还提到：&ldquo;职教赛道主要考验的是大国工匠而高教组大多比拼的是硬科技&rdquo;。同时李院长还带着选手们重温往届大赛的赛制，并从实事上解剖了红色筑梦之旅赛道的由来，并为选手们提供了宝贵的经验。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2021%3A18%3A34blob?Expires=2034767914&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=n4Mm2nXJopbqF7H1znJAohAqFPY%3D" width="692" height="519" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 不积跬步，无以至千里，预祝江软所有的参赛选手们能够继承我校&ldquo;创新创业，知识管理&rdquo;的理念，在接下来的校赛和省赛上勇夺佳绩，为我校增添新的荣誉也为自己的大学旅程上画上精彩的一笔，俗话说：&ldquo;台上三分钟，台下十年功&rdquo;，看似普通的竞赛，里面却包含了森罗万象的道理，也期待更多的师生能够积极参与到创新教育的时间中来，共同推动我校创新教育的深入发展。</p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (541, '<p>&nbsp; &nbsp; &nbsp; &nbsp;中国国际大学生创新大赛2024江软校赛自5月15号报名开始以来，同学们踊跃报名，截止发稿时止共报名项目1000余个。经过半个多月紧张的评选，目前确定27个项目入围中国国际大学生创新大赛2024江软校赛校赛决赛。决赛预计于6月11日下午2:00在江软南昌校区创客大厦路演大厅举行。</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2021%3A46%3A544a5e694f46905160f211e990fa6e69ce.png?Expires=2034769614&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=SY7rPBICPvjKES%2BzD8qB%2BTIpBGw%3D" width="586" height="707" /></p>');
INSERT INTO content VALUES (542, '<p>&nbsp; &nbsp; &nbsp; &nbsp; 各位小伙伴们！江西软件职业技术大学2024 年中国国际大学生创新创业大赛路演决赛的激情时刻终于来临！</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2021%3A58%3A10640%20%283%29.jpg?Expires=2034770290&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=SRGhC66DaY7mpPwBfyBPM%2BC1Vds%3D" width="617" height="400" /></p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 今日，我校迎来了一场极具意义的盛事&mdash;&mdash;2024 年中国国际大学生创新创业大赛路演决赛！</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;在这个充满挑战与机遇的舞台上，一共二十七支队伍从970支队伍中脱颖而出。他们带着独具匠心的创新项目，满怀激情与信心，站在了这里。</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A01%3A55add9b73d0f4860df3b64c6b96d97aeb3.jpg?Expires=2034770516&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Hjj9LEDCi0qH72%2B60U3O%2BrB%2B%2B%2F4%3D" width="624" height="468" /></p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 在决赛伊始，由江西软件职业技术大学郭宏副校长发表讲话并对参赛团队寄予崇高的希望，随后宣布江西软件职业技术大学中国国际大学生创新创业大赛（2024）校决赛正式开始。&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A04%3A59%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240626220509.jpg?Expires=2034770700&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=UsmeWEsAsw5IRF%2F72FqagISazfg%3D" width="617" height="462" /></p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 决赛现场，紧张而又热烈的氛围弥漫在每一个角落。选手们精彩绝伦的路演展示，让我们看到了年轻一代的无限创造力和对未来的大胆构想。从前沿科技到生活创意，从商业模式创新到社会问题解决，每一个项目都闪耀着智慧的光芒。</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A09%3A05640%20%284%29.jpg?Expires=2034770945&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=3t5u9oPdjDTlWPVS7VhnmVNtyDc%3D" width="619" height="464" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 我校的参赛团队更是以卓越的表现，展现了他们扎实的专业知识和勇于突破的精神。他们的项目不仅具有创新性，更具有广阔的发展前景和社会价值。</p>
<p align="center">&nbsp;</p>
<p align="center"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A10%3A53640%20%285%29.jpg?Expires=2034771053&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=u%2BvfpYdV1jmko6Nlns7xvTfBpMY%3D" width="621" height="465" /></p>
<p align="center">&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; 这不仅是一场比赛，更是一次思想的碰撞、灵感的激发。它见证了大学生们的成长与进步，也激励着更多的同学投身到创新创业的热潮中。</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A14%3A11640%20%286%29.jpg?Expires=2034771252&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=FK32xsqKEKvRJB9cnLZ%2Fi0pplvQ%3D" width="629" height="470" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 让我们共同为所有参赛选手加油鼓劲，期待他们在这场巅峰对决中取得优异的成绩，为校争光！同时，也希望通过这样的大赛，能进一步推动我校创新创业教育的发展，培养出更多具有创新意识和创业能力的优秀人才！</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-26%2022%3A15%3A49640%20%287%29.jpg?Expires=2034771349&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=gynGlqp9E%2BrZQMm5agaE%2B0QKTus%3D" width="638" height="478" /></p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; 上半场的角逐精彩非凡，各个团队都展现出了非凡的实力和魅力。现在，上半场已经落下帷幕，但精彩仍在继续！让我们把最热烈的掌声送给已经完成展示的团队们！</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;而即将登场的下半场参赛团队们，你们是接棒前行的勇士，承载着更多的期待。希望你们能以更加饱满的热情、更加坚定的信心，在接下来的路演中发挥出最佳状态，展现出最独特的创意和最强大的实力。加油，下半场的你们必将创造新的辉煌，让我们共同期待你们的惊艳表现！</p>');
INSERT INTO content VALUES (543, '<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp; 2024年6月14日江西省第十届大学生创业公开课决赛正式开始，本次活动在江西省广播电视台融媒体演播室举行，决赛和颁奖活动进行全程直播，此次参赛的项目分别是各个高校校赛中决出的冠军队伍。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2009%3A34%3A43640.png?Expires=2034812083&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=A31a6Ow49fULrl7C3N7niBtHTY8%3D" width="778" height="583" /></p>
<p>&nbsp;</p>
<p style="text-align: justify;">&nbsp; &nbsp; &nbsp; &nbsp;此次大创课的形式充分结合了中国国际大学生创新大赛的赛制，赛道划分为高教组与职教组，我校职教组项目&ldquo;小力速达&rdquo;成功进入省赛与其他高校的种子选手进行同台竞技，在比赛过程中，他们以他卓越的专业知识与激情的青春风貌，为大家带来了一场生动精彩的路演与答辩。</p>
<p>&nbsp;</p>
<p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2009%3A35%3A31640%20%281%29.png?Expires=2034812131&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=oTeJRYQ2v3exGr29C1T%2FvjjT2VQ%3D" width="787" height="590" /></p>
<p>&nbsp;</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp;在此次的竞赛里，我校选手更是彰显了我校&ldquo;创新创业，知识管理&rdquo;的优秀理念，并在此次大创课中取得不错的成绩，希望他们再接再厉，也希望更多的江软学子能够参与其中，赢得佳绩，砥砺前行。</p>');
INSERT INTO content VALUES (544, '<p align="center"><strong>江软件职业技术大学公布关于中国国际大学生创新大赛（</strong><strong>2024</strong><strong>）</strong></p>
<p align="center"><strong>获奖名单的通知</strong></p>
<p>为深入贯彻落实习近平总书记给&ldquo;青年红色筑梦之旅&rdquo;学生重要回信和&ldquo;把创新教育贯穿教育活动全过程&rdquo;重要指示精神，贯彻党的二十大关于加快建设教育强国的战略部署，江西软件职业技术大学举办了中国国际大学生创新大赛2024，现将获奖名单公布如下。</p>
<p>一、【金奖项目】：</p>
<p>&nbsp; 职教赛道创意组，基于体积视频技术的红色文旅公共服务合拍平台</p>
<p>二、【银奖项目】：</p>
<p>&nbsp; 青年红色筑梦之旅赛道创意组，井冈先锋数字化国情教育研学旅行智慧服务平台；</p>
<p>&nbsp; 职教赛道创意组，基于区块链的先锋积分管理系统</p>
<p>三、【铜奖项目】：</p>
<p>&nbsp; 青年红色筑梦之旅赛道创意组，灵眸&mdash;基于图灵AI大模型的社区综合管理系统；</p>
<p>&nbsp; 高教主赛道创意组，VR陶韵视界&mdash;数字陶瓷艺术展馆；</p>
<p>职教赛道创意组，小力速达&mdash;您的智能配送管家</p>
<p>四、【优秀组织奖】：区块链学院</p>
<p>五、【优秀创新创业导师奖】：井冈山数字经济产业学院 蔡咸健</p>
<p>中国国际大学生创新大赛2024江西软件职业技术大学校赛自5月15日以来，共有970个项目报名，27支队伍进入决赛。决赛于6月11日至6月17日并经过线上与线下两轮共一个星期的评选，评选出以上<strong>金银铜奖共六支优胜项目。项目队伍将稍晚代表江西软件职业技术大学参加江西</strong>省赛选拔。</p>
<p>&nbsp;</p>
<p><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A28%3A04%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20240627112825.png?Expires=2034818885&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RLDe9pz96NO6SD1CAkUf0h4Aj8Q%3D" width="837" height="1238" /></p>
<p>&nbsp;</p>
<p>祝贺以上获奖的优胜队伍，希望在省赛中获得更好的成绩。也希望更多的江软学子们参与其中，践行大赛&ldquo;我敢闯 我会创&rdquo;精神与本校&ldquo;创新创业，知识管理&rdquo;校训，努力争先，为校争光。</p>
<p>&nbsp;</p>');
INSERT INTO content VALUES (545, '<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="background-color: #ffffff; color: #000000;"><span style="font-size: 24pt; line-height: 130%; font-family: minorEastAsia; background: #ffffff;">先锋天使无人打印</span><span style="font-size: 24pt; line-height: 130%; background: #ffffff;">&nbsp;</span></span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 24pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">全天候守护不打烊</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="background-color: #ffffff; color: #000000;"><span style="font-size: 12pt; line-height: 130%; font-family: minorEastAsia; background: #ffffff;">随时随地</span><span style="font-size: 12pt; line-height: 130%; background: #ffffff;">&middot;</span><span style="font-size: 12pt; line-height: 130%; font-family: minorEastAsia; background: #ffffff;">及时打印</span></span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="background-color: #ffffff; color: #000000;"><strong><span style="font-size: 18pt; line-height: 130%; font-family: minorEastAsia; background: #ffffff;">你是否有过这样的场景</span></strong></span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">考试前夕，焦急地四处寻找打印店</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">深夜赶材料，急需寻找一台可靠的打印机</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 15pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">现在告别这些烦恼迎接</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 15pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">江软新宠</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 15pt; line-height: 130%; font-family: minorEastAsia; color: #000000; background: #ffffff;">先锋天使无人自助打印</span></p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center">&nbsp;</p>
<p style="text-align: center; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;" align="center"><span style="font-size: 15.0pt; line-height: 130%; font-family: minorEastAsia; color: #024760; background: white;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A32%3A54640.webp?Expires=2034819175&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=W4LgzKt0oYJlCyJC0PgiqPb1Er8%3D" width="790" height="1054" /></span></p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333; text-align: justify;" align="center"><span style="font-size: 15.0pt; line-height: 130%; font-family: minorEastAsia; color: #024760; background: white;"><span style="font-size: 15pt; line-height: 130%; color: #024760; background: white;">&nbsp;<span style="font-size: 18px;">1、</span></span><span style="color: #000000; font-size: 18px;"><span style="line-height: 130%; font-family: minorEastAsia; background: white;">随时随地，一键打印</span> </span></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">&nbsp; &nbsp; &nbsp; &nbsp;先锋天使无人打印机</span><span style="font-size: 10.5pt; line-height: 130%; background: white;">&mdash;&mdash;</span><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">你的</span><span style="font-size: 10.5pt; line-height: 130%; background: white;">24</span><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">小时学习与生活小助手。无需等待，只需轻松一扫，学习资料、报告、甚至是珍贵的回忆照片即刻打印到手。不论你是在图书馆挑灯夜读，还是在宿舍为明天的演讲做最后准备，先锋天使都如影随形，为你提供即时、高效的打印服务，默默陪伴并支持你的每一份付出与努力。让学习与生活更便捷，更轻松。</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A41%3A37640%20%281%29.webp?Expires=2034819698&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=VKkwMx6A%2FPPkFJQKr%2Ba9srNDYiA%3D" width="783" height="1007" /></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 18px; color: #000000; background-color: #ffffff;"><span style="line-height: 130%; font-family: minorEastAsia; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">&nbsp;<span style="font-size: 18px; background-color: #ffffff;">2、大批量打印，毫无压力</span></span></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">&nbsp; &nbsp; &nbsp; &nbsp;传统打印机在散热性能上存在局限性，当面临大批量打印任务时，往往因散热不足而导致性能下降甚至中断打印，这无疑给使用者带来了诸多不便和焦虑。然而，我们独特的无人打印机则以其卓越的散热性能，轻松应对大批量打印需求，确保打印过程连续稳定，让您在繁忙的工作中感受到前所未有的安心与便捷。</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A42%3A26640%20%283%29.webp?Expires=2034819746&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KU8s5sJ0Hym9b21mgWtcM672GPw%3D" width="786" height="583" /></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333; text-align: left;" align="center"><span style="font-size: 13.5pt; line-height: 130%; color: #024760; background: white;">3、</span><span style="font-size: 18px; line-height: 130%; font-family: minorEastAsia; color: #000000; background: white;">安全便捷，隐私保护</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">&nbsp; &nbsp; &nbsp; &nbsp;担心文件泄露？先锋天使无人打印机已全面升级，采用业界领先的加密技术，确保您的文件在传输和打印过程中都得到严格保护。现在，通过我们的全新优化的专属微信小程序，您可以更方便快捷地上传文件、选择打印机并自定义打印选项。此外，我们还提供了更灵活的支付方式，让您轻松完成支付流程，即刻享受高效、安全的打印服务。让先锋天使无人打印机成为您办公和生活的得力助手，为您的文件安全保驾护航。</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A42%3A58640%20%284%29.webp?Expires=2034819778&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KA717ZPVo%2BRMjuMw%2FOi1iS19K6w%3D" width="787" height="549" /></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 18px; line-height: 130%; font-family: minorEastAsia; color: #000000; background: white;">4、位置优越，触手可及</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">&nbsp; &nbsp; &nbsp; &nbsp;我们的无人打印机已经率先在创客大厦负一楼的先锋天使咖啡设立服务点，开启了便捷的自助打印新时代。展望未来，我们致力于将这一创新服务覆盖到校园的每个角落</span><span style="font-size: 10.5pt; line-height: 130%; background: white;">&mdash;&mdash;</span><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">图书馆、教学楼、学生中心，甚至是宿舍楼旁。</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A43%3A33640%20%285%29.webp?Expires=2034819813&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KHSaks9e24h9bEpXRIzEgvFn0l8%3D" width="805" height="848" /></span></p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;"><img style="display: block; margin-left: auto; margin-right: auto;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/innovate/img/2024-06-27%2011%3A45%3A12640%20%286%29.webp?Expires=2034819913&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Ldjpik2g9%2Bzj0751mvtpq%2F6YFMM%3D" width="809" height="606" /></span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;">&nbsp;</p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; background: white;">&nbsp; &nbsp; &nbsp; &nbsp; </span><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">无需再为打印奔波，只需在校园里留意我们精心布设的打印小站，你的打印需求，我们随时为你满足！一网打尽你的打印烦恼，让学习与生活更加便捷无忧。</span></p>
<p style="margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 11.5pt; line-height: 130%; font-family: minorEastAsia; color: #024760; background: white;">价格实惠，福利享不停</span></p>
<p style="text-align: justify; margin: 3pt 0cm; line-height: 130%; font-size: 11pt; font-family: minorHAnsi; color: #333333;"><span style="font-size: 10.5pt; line-height: 130%; font-family: minorEastAsia; background: white;">&nbsp; &nbsp; &nbsp; &nbsp;我们提供质价比高的优质的打印服务，满足大家各种急需的打印需求。并且我们还会提供线上咨询服务，给您随时提供贴心的服务。</span></p>');
